parameters.jsCode:
const SOURCE_NODE_CANDIDATES = ['KI-Ergebnis übernehmen', 'Validieren & Materialtext vorbereiten'];
const SUPPLIER_NODE = 'Lieferantenliste auslesen';

const readNode = (name) => {
  try {
    return $(name).all().map((i) => i.json ?? {});
  } catch {
    return null;
  }
};

const hasMaterialColumns = (rows) =>
  Array.isArray(rows) &&
  rows.some((r) =>
    (r.Artikelbezeichnung || r.artikelbezeichnung || r.Werkstoff || r.werkstoff || r.materialtyp || r.kategorie),
  );

const inputRows = $input.all().map((i) => i.json ?? {});
let materialRows = null;
let materialSource = null;

if (hasMaterialColumns(inputRows)) {
  materialRows = inputRows;
  materialSource = 'Direkteingang';
} else {
  for (const nodeName of SOURCE_NODE_CANDIDATES) {
    const data = readNode(nodeName);
    if (data && data.length) {
      materialRows = data;
      materialSource = nodeName;
      break;
    }
  }
}

if (!materialRows) {
  throw new Error(`Keine Materialdaten gefunden. Erwartet: Direkteingang oder ${SOURCE_NODE_CANDIDATES.join(' oder ')}`);
}

const supplierRows = readNode(SUPPLIER_NODE);
if (!supplierRows || !supplierRows.length) {
  throw new Error(`Keine Lieferantendaten aus Node "${SUPPLIER_NODE}" gefunden.`);
}

const hasSupplierColumns = supplierRows.some(
  (r) =>
    (r.Lieferant || r.lieferant) &&
    (r.Sortimentsbreite || r.sortimentsbreite || r.Sortiment || r.sortiment),
);
if (!hasSupplierColumns) {
  throw new Error(
    `Node "${SUPPLIER_NODE}" liefert keine CSV-Zeilen mit Lieferant/Sortimentsbreite. ` +
      'Nutze vorher "Extract from File" mit Operation "Extract from CSV".',
  );
}

const dedupSupplierRows = [];
const supplierSeen = new Set();
for (const row of supplierRows) {
  const key = [
    String(row.Lieferant ?? row.lieferant ?? '').trim().toLowerCase(),
    String(row.Sortimentsbreite ?? row.sortimentsbreite ?? row.Sortiment ?? row.sortiment ?? '')
      .trim()
      .toLowerCase(),
    String(row.Lieferpauschale ?? row.lieferpauschale ?? '').trim(),
    String(row.Entladungskosten ?? row.entladungskosten ?? '').trim(),
  ].join('|');
  if (!supplierSeen.has(key)) {
    supplierSeen.add(key);
    dedupSupplierRows.push(row);
  }
}

const pick = (obj, keys, fallback = '') => {
  for (const key of keys) {
    const value = obj?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return fallback;
};

const norm = (v = '') =>
  String(v)
    .toLowerCase()
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9.]+/g, ' ')
    .trim();

const tokenize = (v = '') => norm(v).split(/\s+/).filter(Boolean);

const expandToken = (token = '') => {
  const t = norm(token);
  if (!t) return [];
  const out = new Set([t]);

  if (t.includes('edelstahl') || /^1\.\d{4}$/.test(t) || t.includes('inox') || t.includes('rostfrei')) {
    out.add('edelstahl');
    out.add('stahl');
  }
  if (t.includes('aluminium') || t === 'alu' || t.startsWith('alu')) {
    out.add('aluminium');
  }
  if (/^s\d{3,4}$/.test(t)) {
    out.add('baustahl');
  }
  if (t.includes('stahl') || t.includes('flachstahl') || t.includes('winkel') || t.includes('profil') || t.includes('blech')) {
    out.add('stahl');
    out.add('baustahl');
  }
  return [...out];
};

const unique = (arr) => [...new Set(arr.filter(Boolean))];

const classifyText = (text) => {
  const all = norm(text);
  if (/edelstahl|1\.\d{4}|inox|rostfrei/.test(all)) return 'edelstahl';
  if (/aluminium|\balu\b/.test(all)) return 'aluminium';
  if (/s\d{3,4}|stahl|flachstahl|winkel|blech|profil/.test(all)) return 'baustahl';
  return '';
};

const classifyMaterial = (row) => {
  const werkstoff = String(pick(row, ['Werkstoff', 'werkstoff'], ''));
  const artikel = String(pick(row, ['Artikelbezeichnung', 'artikelbezeichnung', 'artikel'], ''));
  const materialtyp = String(pick(row, ['materialtyp', 'kategorie'], ''));
  const suchbegriffe = Array.isArray(row.suchbegriffe) ? row.suchbegriffe.join(' ') : '';
  return classifyText([werkstoff, artikel, materialtyp, suchbegriffe].join(' '));
};

return materialRows.map((row, idx) => {
  const artikel = String(pick(row, ['Artikelbezeichnung', 'artikelbezeichnung', 'artikel'], ''));
  const werkstoff = String(pick(row, ['Werkstoff', 'werkstoff'], ''));
  const normWert = String(pick(row, ['Norm', 'norm'], ''));
  const menge = pick(row, ['Menge', 'menge'], '');
  const statusAlt = String(pick(row, ['status'], ''));
  const materialtyp = String(pick(row, ['materialtyp', 'kategorie'], ''));
  const suchbegriffe = Array.isArray(row.suchbegriffe) ? row.suchbegriffe : [];

  const materialKlasse = classifyMaterial(row);
  const materialTokens = unique([
    ...[artikel, werkstoff, normWert, materialtyp].flatMap(tokenize).flatMap(expandToken),
    ...suchbegriffe.flatMap(tokenize).flatMap(expandToken),
    materialKlasse,
  ]);

  const scored = dedupSupplierRows.map((supplier) => {
    const supplierName = String(pick(supplier, ['Lieferant', 'lieferant'], 'Unbekannt'));
    const sortimentRaw = String(pick(supplier, ['Sortimentsbreite', 'sortimentsbreite', 'Sortiment', 'sortiment'], ''));
    const supplierKlasse = classifyText(sortimentRaw);
    const sortimentTokens = unique(
      sortimentRaw
        .split(/[;,|]/)
        .map((s) => s.trim())
        .flatMap(tokenize)
        .flatMap(expandToken),
    );

    let score = 0;
    for (const mt of materialTokens) {
      if (sortimentTokens.includes(mt)) score += 3;
      else if (mt.length >= 4 && sortimentTokens.some((st) => st.includes(mt) || mt.includes(st))) score += 1;
    }
    if (materialKlasse && supplierKlasse) {
      if (supplierKlasse === materialKlasse) score += 12;
      else score -= 12;
    }
    if (materialKlasse && sortimentTokens.includes(materialKlasse)) score += 3;

    return { supplier, supplierName, supplierKlasse, score };
  });

  let kandidaten = scored.filter((s) => s.score > 0);
  if (materialKlasse) {
    const gleicheKlasse = kandidaten.filter((s) => s.supplierKlasse === materialKlasse);
    if (gleicheKlasse.length) kandidaten = gleicheKlasse;
  }

  const maxScore = Math.max(...kandidaten.map((s) => s.score), 0);
  const passende = kandidaten
    .filter((s) => s.score >= maxScore - 1)
    .sort((a, b) => b.score - a.score)
    .map((s) => s.supplier);

  const moeglicheLieferanten = passende
    .map((s) => String(pick(s, ['Lieferant', 'lieferant'], '')).trim())
    .filter(Boolean);

  const lieferantenInfos = passende.map((s) => ({
    Lieferant: String(pick(s, ['Lieferant', 'lieferant'], '')).trim(),
    Sortimentsbreite: String(pick(s, ['Sortimentsbreite', 'sortimentsbreite', 'Sortiment', 'sortiment'], '')).trim(),
    Lieferpauschale: Number(pick(s, ['Lieferpauschale', 'lieferpauschale'], 0)) || 0,
    Entladungskosten: Number(pick(s, ['Entladungskosten', 'entladungskosten'], 0)) || 0,
    to_email: String(pick(s, ['Email', 'email', 'E-Mail', 'e_mail', 'kontakt_email'], '')).trim(),
  }));

  const posRaw = Number.parseInt(String(pick(row, ['pos', 'Pos', 'Positionsnummer'], idx + 1)), 10);
  const pos = Number.isInteger(posRaw) && posRaw > 0 ? posRaw : idx + 1;

  return {
    json: {
      ...row,
      pos,
      Artikelbezeichnung: artikel,
      Werkstoff: werkstoff,
      Norm: normWert,
      Menge: menge,
      materialtyp,
      suchbegriffe,
      moeglicheLieferanten,
      lieferantenInfos,
      matchingScores: scored.map((s) => ({ lieferant: s.supplierName, score: s.score })),
      zuordnungStatus: moeglicheLieferanten.length ? 'zugeordnet' : 'kein passender Lieferant',
      status: moeglicheLieferanten.length ? statusAlt || 'ok' : 'offen/prüfpflichtig',
      materialQuelle: materialSource,
    },
  };
});

