parameters.jsCode:
const BASIS_NODE = 'Validieren & Materialtext vorbereiten';
const kiItems = $input.all();

let basis;
try {
  basis = $(BASIS_NODE).all();
} catch {
  throw new Error(`Node "${BASIS_NODE}" nicht gefunden. Bitte Node-Name im Code exakt anpassen.`);
}

if (!basis.length) {
  throw new Error(`Node "${BASIS_NODE}" hat keine Daten. Führe den Node vorher aus.`);
}

if (basis.length !== kiItems.length) {
  throw new Error(
    `Item-Anzahl passt nicht: Basis=${basis.length}, KI=${kiItems.length}. ` +
    'Prüfe Verzweigung bzw. füge einen Merge (Position) ein.'
  );
}

const stripCodeFence = (value) => String(value ?? '')
  .replace(/^\`\`\`json\s*/i, '')
  .replace(/^\`\`\`/i, '')
  .replace(/\`\`\`$/i, '')
  .trim();

function parseKi(rawJson) {
  let raw = rawJson.output ?? rawJson.text ?? rawJson.response ?? rawJson.data ?? rawJson;
  if (typeof raw === 'string') {
    const cleaned = stripCodeFence(raw);
    try { raw = JSON.parse(cleaned); } catch { return null; }
  }
  if (raw && typeof raw === 'object' && raw.output && typeof raw.output === 'object') raw = raw.output;
  if (!raw || typeof raw !== 'object') return null;
  return {
    materialtyp: String(raw.materialtyp ?? raw.kategorie ?? '').trim(),
    suchbegriffe: Array.isArray(raw.suchbegriffe) ? raw.suchbegriffe.map((value) => String(value ?? '').trim()).filter(Boolean) : [],
    confidence: Number(raw.confidence ?? raw.konfidenz ?? 0) || 0,
    begruendung: String(raw.begruendung ?? '').trim(),
  };
}

const pick = (obj, keys, fallback = '') => {
  for (const key of keys) {
    const value = obj?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }
  return fallback;
};

const normalize = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9.]+/g, ' ')
  .trim();

const title = (value) => String(value ?? '')
  .trim()
  .replace(/\s+/g, ' ')
  .replace(/\bEDELSTAHL\b/g, 'Edelstahl')
  .replace(/\bALUMINIUM\b/g, 'Aluminium');

const unique = (arr) => {
  const out = [];
  const seen = new Set();
  for (const raw of arr) {
    const value = title(raw);
    const key = normalize(value);
    if (!key || seen.has(key)) continue;
    seen.add(key);
    out.push(value);
  }
  return out;
};

const classifyWerkstoff = (werkstoff, artikel) => {
  const text = normalize([werkstoff, artikel].join(' '));
  if (/1\.4301|1\.4404|edelstahl|inox|rostfrei/.test(text)) return 'Edelstahl';
  if (/aluminium|\balu\b/.test(text)) return 'Aluminium';
  if (/s235|s355|stahl|flachstahl|winkel|blech|profil/.test(text)) return 'Baustahl';
  if (String(werkstoff ?? '').trim()) return title(werkstoff);
  return '';
};

const classifyForm = (artikel) => {
  const text = normalize(artikel);
  if (/flachstahl|flach/.test(text)) return 'Flachstahl';
  if (/winkel/.test(text)) return 'Winkelstahl';
  if (/rohr/.test(text)) return 'Rohr';
  if (/blech/.test(text)) return 'Blech';
  if (/rundstahl|rund/.test(text)) return 'Rundstahl';
  if (/vierkant/.test(text)) return 'Vierkantprofil';
  if (/profil/.test(text)) return 'Profil';
  return title(artikel);
};

const buildDeterministicClassification = (row) => {
  const artikel = String(pick(row, ['Artikelbezeichnung', 'artikelbezeichnung', 'artikel'], '')).trim();
  const werkstoff = String(pick(row, ['Werkstoff', 'werkstoff'], '')).trim();
  const norm = String(pick(row, ['Norm', 'norm'], '')).trim();
  const oberflaeche = String(pick(row, ['Oberflaecheneigenschaften', 'Oberflaeche', 'oberflaeche', 'Oberfläche'], '')).trim();
  const form = classifyForm(artikel);
  const klasse = classifyWerkstoff(werkstoff, artikel);
  const materialtyp = form && klasse
    ? (normalize(form).includes(normalize(klasse)) ? form : `${form} aus ${klasse}`)
    : (form || klasse || 'Unklassifiziert');
  const suchbegriffe = unique([
    artikel,
    werkstoff,
    norm,
    oberflaeche,
    form,
    klasse,
  ]).filter((value) => !/^(ja|nein|true|false)$/i.test(value));
  return {
    materialtyp,
    suchbegriffe,
    begruendung: 'Deterministisch aus Artikelbezeichnung, Werkstoff, Norm und Oberfläche der Stückliste abgeleitet. KI-Begriffe werden nicht übernommen.',
  };
};

return basis.map((item, idx) => {
  const json = { ...item.json };
  const ki = parseKi(kiItems[idx]?.json ?? {});
  const deterministic = buildDeterministicClassification(json);

  json.materialtyp = deterministic.materialtyp;
  json.suchbegriffe = deterministic.suchbegriffe;
  json.kategorie = deterministic.materialtyp;
  json.kategorieQuelle = 'Codeextraktion';
  json.kategorieConfidence = 1;
  json.kategorieBegruendung = deterministic.begruendung;
  json.ki_materialtyp_vorschlag = ki?.materialtyp ?? '';
  json.ki_suchbegriffe_vorschlag = ki?.suchbegriffe ?? [];
  json.ki_materialklassifikation_ignoriert = true;
  json.ki_materialklassifikation_ignoriert_grund = 'Freie KI-Materialgruppen und Suchbegriffe werden wegen Halluzinationsrisiko nicht mehr übernommen.';

  return { json };
});

parameters.text:
=Du prüfst eine Materialposition im technischen Einkauf.

Wichtig:
- Keine erfundenen Begriffe.
- Keine zusätzlichen Materialien, Branchen oder Anwendungen ergänzen.
- Nutze nur Wörter und Werte aus Artikelbezeichnung, Werkstoff, Norm, Oberfläche und Gesamtkontext.
- Wenn du unsicher bist, schreibe die Unsicherheit in "begruendung".

Eingang:
- Artikelbezeichnung: {{ $json.Artikelbezeichnung }}
- Werkstoff: {{ $json.Werkstoff }}
- Norm: {{ $json.Norm }}
- Oberfläche: {{ $json.Oberflaeche }}
- Gesamtkontext: {{ $json.materialText }}

Gib ausschließlich JSON zurück mit:
{
  "materialtyp": "<nur aus Eingangsdaten abgeleitete kurze Warengruppe>",
  "suchbegriffe": ["<nur Begriffe aus den Eingangsdaten>"],
  "confidence": <Zahl 0 bis 1>,
  "begruendung": "<kurz, ohne erfundene Begriffe>"
}

