const stripBom = (s) => String(s ?? '').replace(/^\uFEFF/, '');

const pick = (obj, keys, fallback = '') => {
  for (const key of keys) {
    const value = obj?.[key];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }

  const lower = Object.entries(obj ?? {}).reduce((acc, [k, v]) => {
    acc[stripBom(String(k)).toLowerCase()] = v;
    return acc;
  }, {});

  for (const key of keys) {
    const value = lower[String(key).toLowerCase()];
    if (value !== undefined && value !== null && String(value).trim() !== '') return value;
  }

  return fallback;
};

const toNum = (v) => {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

const splitCsvLine = (line, delimiter) => {
  const out = [];
  let cur = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const ch = line[i];

    if (ch === '"') {
      if (inQuotes && line[i + 1] === '"') {
        cur += '"';
        i += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (ch === delimiter && !inQuotes) {
      out.push(cur);
      cur = '';
      continue;
    }

    cur += ch;
  }

  out.push(cur);
  return out;
};

const parseCollapsedCsvRow = (row) => {
  const entries = Object.entries(row ?? {});
  if (entries.length !== 1) return row;

  const [headerRaw, valueRaw] = entries[0];
  const headerLine = stripBom(String(headerRaw ?? '')).trim();
  const dataLine = String(valueRaw ?? '');

  const semiCount = (headerLine.match(/;/g) || []).length;
  const commaCount = (headerLine.match(/,/g) || []).length;
  const delimiter = semiCount >= commaCount ? ';' : ',';

  if (!headerLine.includes(delimiter)) {
    return row;
  }

  const headers = splitCsvLine(headerLine, delimiter).map((h) => stripBom(h).trim());
  const values = splitCsvLine(dataLine, delimiter);

  if (headers.length <= 1 || values.length <= 1) {
    return row;
  }

  const expanded = {};
  for (let i = 0; i < headers.length; i++) {
    expanded[headers[i] || `col_${i + 1}`] = values[i] ?? '';
  }

  return expanded;
};

const normalizeRow = (rawRow) => {
  const maybeExpanded = parseCollapsedCsvRow(rawRow ?? {});
  const out = {};

  for (const [k, v] of Object.entries(maybeExpanded)) {
    out[stripBom(k)] = v;
  }

  return out;
};

const hasAnyValue = (obj) =>
