const maxPos = basisPositionen.length;
const byPos = new Map();

const baseForPos = (pos) => {
  const basis = basisPositionen[pos - 1] ?? {};
  const infos = Array.isArray(basis.lieferantenInfos) ? basis.lieferantenInfos : [];

  const infoMap = new Map();
  for (const info of infos) {
