for (let rowIndex = 0; rowIndex < rows.length; rowIndex++) {
  const row = rows[rowIndex];

  const posRaw = pick(row, ['Pos', 'pos', 'Positionsnummer', 'positionsnummer', 'Position', 'position'], '');
  const posRawText = String(posRaw).trim();

  const fieldsForBusinessData = [
    'Artikelbezeichnung',
    'artikelbezeichnung',
    'Menge',
    'menge',
    'Werkstoff',
    'werkstoff',
    'Norm',
    'norm',
    'Lieferant',
    'lieferant',
    'Status',
    'status',
  ];

  const hasBusinessData = fieldsForBusinessData.some((k) => String(row[k] ?? '').trim() !== '');

  if (!posRawText) {
    if (hasBusinessData) {
      throw new Error(`Ungueltige Positionsnummer in CSV (Zeile ${rowIndex + 2}): leer`);
    }
    continue;
  }

  const pos = Number.parseInt(posRawText, 10);
  if (!Number.isInteger(pos) || pos < 1 || pos > maxPos) {
    throw new Error(`Ungueltige Positionsnummer in CSV (Zeile ${rowIndex + 2}): ${posRawText}`);
  }

  if (!byPos.has(pos)) {
    byPos.set(pos, baseForPos(pos));
  }

  const target = byPos.get(pos);
  const artikel = String(pick(row, ['Artikelbezeichnung', 'artikelbezeichnung', 'Artikel', 'artikel'], '')).trim();
  const menge = pick(row, ['Menge', 'menge'], '');
  const werkstoff = String(pick(row, ['Werkstoff', 'werkstoff'], '')).trim();
  const norm = String(pick(row, ['Norm', 'norm'], '')).trim();
  const pruefzeugnis = String(pick(row, ['Pruefzeugnis', 'pruefzeugnis'], '')).trim();
  const oberflaeche = String(
    pick(row, ['Oberflaecheneigenschaften', 'oberflaecheneigenschaften', 'Oberflaeche', 'oberflaeche'], ''),
  ).trim();
  const kategorie = String(pick(row, ['Kategorie', 'kategorie', 'Materialtyp', 'materialtyp'], '')).trim();
  const status = String(pick(row, ['Status', 'status'], '')).trim();

  if (artikel) target.Artikelbezeichnung = artikel;
  if (String(menge).trim() !== '') target.Menge = menge;
  if (werkstoff) target.Werkstoff = werkstoff;
  if (norm) target.Norm = norm;
  if (pruefzeugnis) target.Pruefzeugnis = pruefzeugnis;
  if (oberflaeche) target.Oberflaecheneigenschaften = oberflaeche;
  if (kategorie) target.kategorie = kategorie;
  if (status) target.status = status;

  const lieferant = String(pick(row, ['Lieferant', 'lieferant'], '')).trim();
  if (!lieferant) continue;

  const key = lieferant.toLowerCase();
  target.infoMap.set(key, {
    Lieferant: lieferant,
    Sortimentsbreite: String(pick(row, ['Sortimentsbreite', 'sortimentsbreite', 'Sortiment', 'sortiment'], '')).trim(),
    Lieferpauschale: toNum(pick(row, ['Lieferpauschale', 'lieferpauschale'], 0)),
    Entladungskosten: toNum(pick(row, ['Entladungskosten', 'entladungskosten'], 0)),
  });
}


const kp1FormData = (() => {
  try {
    return $('Bearbeitete CSV hochladen (Warten)').first().json.data ?? {};
  } catch {
    return {};
  }
})();

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const sanitizeFormValue = (value) => {
  if (value === undefined || value === null) return '';
  const raw = String(value).trim();
  if (/^\{\{[\s\S]*\}\}$/.test(raw)) return '';
  return raw;
};

const getFormField = (...aliases) => {
  for (const alias of aliases) {
    if (Object.prototype.hasOwnProperty.call(kp1FormData, alias)) {
      const direct = sanitizeFormValue(kp1FormData[alias]);
      if (direct !== '') return direct;
    }
  }

  const wanted = aliases.map((alias) => normalizeKey(alias));
  for (const [key, raw] of Object.entries(kp1FormData)) {
    const keyNorm = normalizeKey(key);
    if (wanted.includes(keyNorm) || wanted.some((alias) => keyNorm.includes(alias) || alias.includes(keyNorm))) {
      const value = sanitizeFormValue(raw);
      if (value !== '') return value;
    }
  }

  return '';
};

const hasKp1FormData = Object.keys(kp1FormData).length > 0;
const kp1DecisionRaw = getFormField('entscheidung', 'Entscheidung').toLowerCase();

let kp1Entscheidung = 'freigeben';
if (kp1DecisionRaw === 'ablehnen') kp1Entscheidung = 'ablehnen';
else if (kp1DecisionRaw === 'freigeben') kp1Entscheidung = 'freigeben';
else if (hasKp1FormData) {
  throw new Error('KP1-Entscheidung konnte aus dem Upload-Formular nicht gelesen werden.');
}

const kp1Ablehnungsgrund = getFormField('ablehnungsgrund', 'Ablehnungsgrund');
const kp1AblehnungsaktionRaw = getFormField('bei_ablehnung', 'Bei Ablehnung').toLowerCase();
const kp1Ablehnungsaktion = kp1Entscheidung === 'ablehnen'
  ? (kp1AblehnungsaktionRaw === 'abbrechen' ? 'abbrechen' : 'erneut_bearbeiten')
  : '';
const kp1Aenderungshinweis = getFormField(
  'aenderungshinweis',
  'Aenderungshinweis',
  'Aenderungshinweis (optional)',
  'Änderungshinweis',
  'Änderungshinweis (optional)',
);

if (kp1Entscheidung === 'ablehnen' && !kp1Ablehnungsgrund) {
  throw new Error('Bei KP1-Ablehnung bitte einen Ablehnungsgrund eintragen.');
}

const result = [];
for (let idx = 0; idx < basisPositionen.length; idx++) {
  const pos = idx + 1;
  const basis = basisPositionen[idx];
  const rec = byPos.get(pos) ?? baseForPos(pos);
  const infos = Array.from(rec.infoMap.values());

  result.push({
    json: {
      ...basis,
      pos,
      Artikelbezeichnung: rec.Artikelbezeichnung,
      Menge: rec.Menge,
      Werkstoff: rec.Werkstoff,
      Norm: rec.Norm,
      Pruefzeugnis: rec.Pruefzeugnis,
      Oberflaecheneigenschaften: rec.Oberflaecheneigenschaften,
      kategorie: rec.kategorie,
      status: infos.length ? rec.status || 'ok' : 'offen/prüfpflichtig',
      lieferantenInfos: infos,
      moeglicheLieferanten: infos.map((i) => i.Lieferant),
      zuordnungStatus: infos.length ? 'zugeordnet' : 'kein passender Lieferant',
      kp1_entscheidung: kp1Entscheidung,
      kp1_ablehnungsgrund: kp1Ablehnungsgrund,
      kp1_ablehnungsaktion: kp1Ablehnungsaktion,
      kp1_aenderungshinweis: kp1Aenderungshinweis,
    },
  });
}

return result;

const input = $input.first()?.json ?? {};
  const rows = Array.isArray(input.kp1_csv_rows) ? input.kp1_csv_rows : [];
  if (!rows.length) {
    throw new Error('Keine CSV-Zeilen für KP1 gefunden.');
  }

  const headers = [
    'AnfrageID',
    'Pos',
    'Artikelbezeichnung',
    'Menge',
    'Werkstoff',
    'Norm',
    'Pruefzeugnis',
    'Oberflaecheneigenschaften',
    'Kategorie',
    'Status',
    'Lieferant',
    'Sortimentsbreite',
    'Lieferpauschale',
    'Entladungskosten',
  ];

  const csvEscape = (value) => {
    const text = String(value ?? '');
    if (/[";\n\r]/.test(text)) {
      return '"' + text.replace(/"/g, '""') + '"';
    }
    return text;
  };

  const csv = [
    headers.join(';'),
    ...rows.map((row) => headers.map((header) => csvEscape(row?.[header] ?? '')).join(';')),
  ].join('\n');

  return [{
    json: {
      kp1_request_id: input.kp1_request_id,
      kp1_csv_dateiname: input.kp1_csv_dateiname,
    },
    binary: {
      data: {
        data: Buffer.from(csv, 'utf8').toString('base64'),
        mimeType: 'text/csv',
        fileName: String(input.kp1_csv_dateiname || 'kp1_lieferantenzuordnung.csv'),
        fileExtension: 'csv',
      },
    },
  }];

