const first = $input.first();
const binary = first.binary ?? {};
const keys = Object.keys(binary);

if (!keys.length) {
  throw new Error('Keine Datei im Formular-Upload gefunden.');
}

const preferred = keys.find((k) => /csv|datei|file|upload/i.test(k)) ?? keys[0];

return [{
  json: {
    ...(first.json ?? {}),
    uploadBinaryKey: preferred,
  },
  binary: {
    data: binary[preferred],
  },
}];

const query = $json.query ?? {};

const rid = String(query.rid ?? '').trim();
const token = String(query.token ?? '').trim();
const file = String(query.file ?? '').trim();

if (!rid || !token || !file) {
  throw new Error('Fehlende Parameter. Erwartet: rid, token, file');
}

if (!/^kp1_[0-9]{14}_[a-z0-9]{6}$/i.test(rid)) {
  throw new Error('Ungueltige rid.');
}

if (!/^[a-z0-9._-]+\.csv$/i.test(file)) {
  throw new Error('Ungueltiger Dateiname.');
}

if (!file.startsWith(`${rid}_`)) {
  throw new Error('Datei gehoert nicht zur Anfrage-ID.');
}

const tokenFromFile = file.slice((rid + '_').length, -4);
if (tokenFromFile !== token) {
  throw new Error('Token passt nicht zur Datei.');
}

return [{
  json: {
    ...$json,
    download_file: file,
  },
}];

const toNum = (v) => {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

const normalizeEmail = (v) => String(v ?? '').trim();
const looksLikeEmail = (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);

const pickEmail = (obj) => {
  const candidates = [
    obj?.to_email,
    obj?.Email,
    obj?.email,
    obj?.['E-Mail'],
    obj?.e_mail,
    obj?.kontakt_email,
    obj?.KontaktEmail,
    obj?.AnsprechpartnerEmail,
  ];

  for (const c of candidates) {
    const value = normalizeEmail(c);
    if (value && looksLikeEmail(value)) return value;
  }

  return '';
};

const slug = (value = '') => String(value)
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-+|-+$/g, '')
  .slice(0, 20);

let requestId = '';
try {
  requestId = String($('KP1 – Übersicht vorbereiten').first().json.kp1_request_id ?? '').trim();
} catch {
  requestId = '';
}

const gruppen = new Map();

for (const { json } of items) {
  const pos = Number.parseInt(String(json.pos ?? ''), 10);
  if (!Number.isInteger(pos) || pos < 1) continue;

  const infos = Array.isArray(json.lieferantenInfos) && json.lieferantenInfos.length
    ? json.lieferantenInfos
    : (Array.isArray(json.moeglicheLieferanten)
        ? json.moeglicheLieferanten.map((name) => ({ Lieferant: name }))
        : []);

  for (const info of infos) {
    const lieferant = String(info?.Lieferant ?? info?.lieferant ?? '').trim();
    if (!lieferant) continue;

    const key = lieferant.toLowerCase();
    if (!gruppen.has(key)) {
      gruppen.set(key, {
        lieferant,
        to_email: pickEmail(info),
        kp1_request_id: requestId,
        anfrage_positionen: [],
        lieferpauschale_standard: toNum(info?.Lieferpauschale ?? info?.lieferpauschale ?? 0),
        entladungskosten_standard: toNum(info?.Entladungskosten ?? info?.entladungskosten ?? 0),
      });
    }

    const g = gruppen.get(key);
    if (!g.to_email) {
      const em = pickEmail(info);
      if (em) g.to_email = em;
    }

    const exists = g.anfrage_positionen.some((p) => Number(p.pos) === pos);
    if (!exists) {
      g.anfrage_positionen.push({
        pos,
        Artikelbezeichnung: String(json.Artikelbezeichnung ?? ''),
        Menge: json.Menge ?? '',
        Werkstoff: String(json.Werkstoff ?? ''),
        Norm: String(json.Norm ?? ''),
        Pruefzeugnis: String(json.Pruefzeugnis ?? ''),
        Oberflaecheneigenschaften: String(json.Oberflaecheneigenschaften ?? ''),
      });
    }
  }
}

if (!gruppen.size) {
  throw new Error('Keine Lieferanten nach KP1-Auswahl gefunden. Bitte Zuordnung in der CSV prüfen.');
}

const out = Array.from(gruppen.values())
  .map((g) => {
    g.anfrage_positionen.sort((a, b) => Number(a.pos) - Number(b.pos));
    return { json: g };
  })
  .sort((a, b) => String(a.json.lieferant).localeCompare(String(b.json.lieferant), 'de'));

out.forEach((entry, idx) => {
  const supplierSlug = slug(entry.json.lieferant || `lieferant-${idx + 1}`) || `lieferant-${idx + 1}`;
  const seq = String(idx + 1).padStart(3, '0');
  const internId = `RFQ-${requestId || 'lokal'}-${seq}-${supplierSlug}`;

  entry.json.rfq_intern_id = internId;
  entry.json.rfq_id = internId;
  entry.json.anfrage_materialanzahl = Array.isArray(entry.json.anfrage_positionen)
    ? entry.json.anfrage_positionen.length
    : 0;
});

return out;

const toNum = (v) => {
    const n = Number(String(v ?? '').replace(',', '.'));
    return Number.isFinite(n) ? n : 0;
  };

  const round = (n) => Number((Math.round(n * 100) / 100).toFixed(2));

  const positionen = items
    .map(({ json }) => {
      const pos = { ...json };
      const menge = toNum(pos.Menge);
      const angebote = Array.isArray(pos.angebote) ? pos.angebote : [];

      pos.angebote = angebote
        .map((a) => {
          const stueckpreis = toNum(a.stueckpreis);
          const lieferkosten = toNum(a.lieferkosten);
          const entladung = toNum(a.entladungspauschale);
          const zusatzkosten = toNum(a.zusatzkosten);

          const kostenVariable = round(stueckpreis * menge);
          const fixkosten = round(lieferkosten + entladung + zusatzkosten);
          const gesamtEinzel = round(kostenVariable + fixkosten);

          return {
            ...a,
            lieferant: String(a.lieferant ?? '').trim(),
            stueckpreis,
            lieferkosten,
            entladungspauschale: entladung,
            zusatzkosten,
            kosten_variable: kostenVariable,
            fixkosten,
            gesamt_einzel: gesamtEinzel,
            gesamt: gesamtEinzel,
          };
        })
        .filter((a) => a.lieferant);

      return pos;
    })
    .sort((a, b) => Number(a.pos ?? 0) - Number(b.pos ?? 0));

  if (!positionen.length) return items;

  const unversorgt = positionen.filter((p) => !p.angebote.length).map((p) => Number(p.pos ?? 0));
  if (unversorgt.length) {
    return positionen.map((p) => ({
      json: {
        ...p,
        bester: p.angebote[0] ?? null,
        optimierung: {
          status: 'unvollstaendig',
          fehlende_positionen: unversorgt,
        },
      },
    }));
  }

  const LIMIT = 50000;
  let states = 0;
  let best = {
    total: Number.POSITIVE_INFINITY,
    assignment: null,
    fixedBySupplier: null,
  };

  const dfs = (idx, assignment, variableSum, fixedBySupplier) => {
    if (variableSum > best.total) return;
    if (states > LIMIT) return;

    if (idx >= positionen.length) {
      let fixed = 0;
      for (const v of fixedBySupplier.values()) {
        fixed += toNum(v.lieferkosten) + toNum(v.entladungspauschale) + toNum(v.zusatzkosten);
      }

      const total = round(variableSum + fixed);
      if (total < best.total) {
        best = {
          total,
          assignment: assignment.map((a) => ({ ...a })),
          fixedBySupplier: new Map(Array.from(fixedBySupplier.entries()).map(([k, v]) => [k, { ...v }])),
        };
      }
      return;
    }

    const pos = positionen[idx];
    for (const offer of pos.angebote) {
      states += 1;

      const supplierKey = String(offer.lieferant).toLowerCase();
      const nextFixed = new Map(fixedBySupplier);
      const prev = nextFixed.get(supplierKey);

      const nextInfo = {
        lieferant: offer.lieferant,
        to_email: String(offer.to_email ?? ''),
        lieferkosten: prev ? Math.max(toNum(prev.lieferkosten), toNum(offer.lieferkosten)) : toNum(offer.lieferkosten),
        entladungspauschale: prev ? Math.max(toNum(prev.entladungspauschale), toNum(offer.entladungspauschale)) : toNum(offer.entladungspauschale),
        zusatzkosten: prev ? Math.max(toNum(prev.zusatzkosten), toNum(offer.zusatzkosten)) : toNum(offer.zusatzkosten),
      };

      nextFixed.set(supplierKey, nextInfo);

      assignment[idx] = {
        pos: Number(pos.pos ?? idx + 1),
        offer,
      };

      dfs(
        idx + 1,
        assignment,
        round(variableSum + toNum(offer.kosten_variable)),
        nextFixed,
      );
    }
  };

  dfs(0, new Array(positionen.length), 0, new Map());

  if (!best.assignment) {
    return positionen.map((p) => ({
      json: {
        ...p,
        bester: p.angebote[0] ?? null,
        optimierung: {
          status: 'fallback',
          grund: 'Keine Kombination berechenbar.',
        },
      },
    }));
  }

  const supplierAssignedVars = new Map();
  const supplierAssignedCounts = new Map();
  for (const rec of best.assignment) {
    const supplierKey = String(rec.offer.lieferant).toLowerCase();
    supplierAssignedVars.set(supplierKey, toNum(supplierAssignedVars.get(supplierKey)) + toNum(rec.offer.kosten_variable));
    supplierAssignedCounts.set(supplierKey, toNum(supplierAssignedCounts.get(supplierKey)) + 1);
  }

  const selectedByPos = new Map();
  for (const rec of best.assignment) {
    selectedByPos.set(Number(rec.pos), rec.offer);
  }

  return positionen.map((p) => {
    const pos = Number(p.pos ?? 0);
    const selected = selectedByPos.get(pos) ?? null;

    const angebote = (Array.isArray(p.angebote) ? p.angebote : [])
      .map((a) => ({
        ...a,
        gesamt: toNum(a.gesamt_einzel),
      }))
      .sort((a, b) => toNum(a.gesamt) - toNum(b.gesamt));

    let bester = null;
    if (selected) {
      const key = String(selected.lieferant).toLowerCase();
      const fixedInfo = best.fixedBySupplier.get(key) ?? { lieferkosten: 0, entladungspauschale: 0, zusatzkosten: 0 };
      const fixedTotal = toNum(fixedInfo.lieferkosten) + toNum(fixedInfo.entladungspauschale) + toNum(fixedInfo.zusatzkosten);
      const supplierVar = toNum(supplierAssignedVars.get(key));
      const supplierCount = Math.max(1, toNum(supplierAssignedCounts.get(key)));
      const varShare = supplierVar > 0
        ? toNum(selected.kosten_variable) / supplierVar
        : 1 / supplierCount;
      const fixAnteil = round(fixedTotal * varShare);
      const allokGesamt = round(toNum(selected.kosten_variable) + fixAnteil);

      bester = {
        ...selected,
        fixkostenanteil: fixAnteil,
        gesamt: allokGesamt,
        gesamt_einzel: toNum(selected.gesamt_einzel),
      };
    }

    return {
      json: {
        ...p,
        angebote,
        bester,
        optimierung: {
          status: states > LIMIT ? 'approximiert' : 'optimal',
          kombinierte_gesamtkosten: best.total,
          berechnete_kombinationen: states,
        },
      },
    };
  });

const esc = (v = '') => String(v)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;');

const toNum = (v) => {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const euro = (value) => toNum(value).toFixed(2) + ' €';
const deVisible = (value) => String(value ?? '')
  .replace(/\bverfuegbar\b/gi, 'verfügbar')
  .replace(/\bVerfuegbarkeit\b/g, 'Verfügbarkeit')
  .replace(/\bPruefzeugnis\b/g, 'Prüfzeugnis')
  .replace(/\bfuer\b/g, 'für')
  .replace(/\bueber\b/g, 'über');
const days = (value) => {
  const n = Number.parseInt(String(value ?? '').trim(), 10);
  return Number.isInteger(n) && n > 0 ? String(n) + ' Tage' : '—';
};

const positionen = items
  .map(({ json }) => ({ ...json }))
  .sort((a, b) => Number(a.pos ?? 0) - Number(b.pos ?? 0));

const reviewScoreRaw = Number(positionen[0]?.automatik_score_prozent ?? 0);
const reviewScore = Number.isFinite(reviewScoreRaw) ? Math.max(0, Math.min(100, reviewScoreRaw)) : 0;
const reviewReason = String(positionen[0]?.automatik_score_begruendung ?? '').trim();
const reviewWarnings = Array.isArray(positionen[0]?.automatik_warnhinweise)
  ? positionen[0].automatik_warnhinweise.map((hint) => deVisible(String(hint ?? '').trim())).filter(Boolean)
  : [];
const reviewFactors = Array.isArray(positionen[0]?.automatik_score_faktoren)
  ? positionen[0].automatik_score_faktoren.map((factor) => ({
      faktor: String(factor.faktor ?? '').trim(),
      gewicht_prozent: toNum(factor.gewicht_prozent),
      bewertung_prozent: toNum(factor.bewertung_prozent),
      beitrag_prozentpunkte: toNum(factor.beitrag_prozentpunkte),
      begruendung: deVisible(String(factor.begruendung ?? '').trim()),
    })).filter((factor) => factor.faktor)
  : [];
const reviewReadiness = String(positionen[0]?.automatik_entscheidungsreife ?? '').trim();
const stuecklistenAbgleich = positionen[0]?.af7_stuecklisten_abgleich && typeof positionen[0].af7_stuecklisten_abgleich === 'object'
  ? positionen[0].af7_stuecklisten_abgleich
  : {};
const materialabweichungenGlobal = Array.isArray(stuecklistenAbgleich.materialabweichungen) ? stuecklistenAbgleich.materialabweichungen : [];
const reviewMode = String(positionen[0]?.ki_job_modus ?? (positionen[0]?.ki_noetig ? 'extraktion' : 'review')).trim();
const scoreColor = reviewScore >= 90 ? '#027a48' : (reviewScore >= 75 ? '#f79009' : '#b42318');
const scoreBg = reviewScore >= 90 ? '#ecfdf3' : (reviewScore >= 75 ? '#fffaeb' : '#fef3f2');
const reviewModeLabel = reviewMode === 'ki_kp2_bestellpruefung' ? 'KI-Vollständigkeitsprüfung KP2' : (reviewMode === 'extraktion' ? 'Direkte KI-Extraktion' : 'Fallback + KI-Review');
const readinessNorm = reviewReadiness.toLowerCase();
const readinessBlocked = /nicht|fehl|unvoll|unklar|manuell/.test(readinessNorm) || reviewScore < 75;
const statusColor = readinessBlocked ? (reviewScore >= 75 ? '#f79009' : '#b42318') : '#027a48';
const statusBg = readinessBlocked ? (reviewScore >= 75 ? '#fffaeb' : '#fef3f2') : '#ecfdf3';
const statusLabel = readinessBlocked ? (reviewScore >= 75 ? 'prüfen' : 'nicht freigabereif') : 'freigabereif';
const offerTone = (status, selected) => {
  const text = String(status ?? '').toLowerCase();
  if (selected) return { bg: '#ecfdf3', color: '#027a48', label: 'Ausgewählt' };
  if (/angebot|verfügbar|verfuegbar/.test(text)) return { bg: '#eff8ff', color: '#175cd3', label: 'Angebot' };
  if (/alternative|teil/.test(text)) return { bg: '#fffaeb', color: '#b54708', label: 'Alternative' };
  if (/absage|keine|unklar|fehlt/.test(text)) return { bg: '#fef3f2', color: '#b42318', label: status || 'unklar' };
  return { bg: '#f8fafc', color: '#344054', label: status || '—' };
};

const selectedTotal = positionen.reduce((sum, p) => sum + toNum(p?.bester?.gesamt), 0);
const alternativeCount = positionen.reduce((sum, p) => {
  const angebote = Array.isArray(p.angebote) ? p.angebote : [];
  const besterName = normalizeKey(p?.bester?.lieferant ?? '');
  return sum + angebote.filter((a) => normalizeKey(a?.lieferant ?? '') !== besterName).length;
}, 0);
const reworkedCount = positionen.filter((p) => p.kp2_ki_geaendert === true).length;
const reworkHints = [
  ...new Set(
    positionen
      .map((p) => String(p.kp2_ki_globaler_hinweis ?? '').trim())
      .filter(Boolean),
  ),
];


const parseTrace = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch {}
  }
  return [];
};

const appendTrace = (trace, entry) => [
  ...parseTrace(trace),
  {
    timestamp: new Date().toISOString(),
    warnings: [],
    errors: [],
    ...entry,
  },
];

const debugSource = positionen[0] ?? {};
const debugTrace = appendTrace(debugSource.debug_trace, {
  step: 'KP2 – Bestellzuordnung vorbereiten',
  status: reviewWarnings.length || readinessBlocked ? 'warnung' : 'ok',
  summary: 'KP2-Übersicht mit ausgewählten Angeboten, Alternativen, Vollständigkeitsprüfung und Warnhinweisen vorbereitet.',
  input: {
    positionen: positionen.length,
    alternative_angebote: alternativeCount,
    modus: reviewModeLabel,
  },
  output: {
    automatik_score_prozent: reviewScore,
    entscheidungsreife: reviewReadiness || statusLabel,
    warnhinweise: reviewWarnings.length,
    ki_geaenderte_positionen: reworkedCount,
  },
  warnings: reviewWarnings,
});

const debugCarry = {
  debug_run_id: debugSource.debug_run_id,
  debug_started_at: debugSource.debug_started_at,
  debug_cache_file: debugSource.debug_cache_file,
  debug_trace: debugTrace,
  debug_file_write_ok: debugSource.debug_file_write_ok,
  debug_file_write_error: debugSource.debug_file_write_error,
};

let html = '';
html += '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.45">';
html += '<h2 style="margin:0 0 10px 0">KP2 – Bestellzuordnung bestätigen</h2>';
html += '<p style="margin:0 0 12px 0">Die Tabelle zeigt alle aktuell zugeordneten Lieferanten, die Kostenbestandteile und die Alternativen je Position. Liefer- und Nebenkosten werden je Lieferant nur einmal ausgewiesen. Bitte nur noch freigeben oder nicht freigeben. Bei Nicht-Freigabe reicht eine Begründung bzw. ein Änderungswunsch.</p>';

html += '<div style="display:flex;flex-wrap:wrap;gap:12px;margin:0 0 16px 0">';
for (const card of [
  ['Positionen', String(positionen.length)],
  ['Ausgewählte Gesamtkosten', euro(selectedTotal)],
  ['Alternative Angebote', String(alternativeCount)],
  ['KI-geänderte Positionen', String(reworkedCount)],
]) {
  html += '<div style="min-width:180px;padding:12px;border:1px solid #d0d5dd;border-radius:10px;background:#f8fafc">';
  html += '<div style="font-size:12px;color:#475467;margin-bottom:4px">' + esc(card[0]) + '</div>';
  html += '<div style="font-size:20px;font-weight:700;color:#101828">' + esc(card[1]) + '</div>';
  html += '</div>';
}
html += '</div>';

html += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:12px;margin:12px 0 16px">';
html += '<div style="padding:12px;border:1px solid ' + scoreColor + ';border-radius:8px;background:' + scoreBg + ';font-size:13px">';
html += '<p style="margin:0 0 8px 0"><b>Datenvollständigkeit</b> <span style="display:inline-block;margin-left:6px;padding:3px 8px;border-radius:999px;background:' + scoreColor + ';color:#fff">' + esc(reviewScore.toFixed(0) + ' %') + '</span></p>';
html += '<p style="margin:0;color:#344054">Bewertet wird, ob Preise, Lieferzeit, Lieferkosten, Materialangaben und Alternativen ausreichend erkannt wurden. Das ist keine automatische Freigabe.</p>';
html += '</div>';
html += '<div style="padding:12px;border:1px solid ' + statusColor + ';border-radius:8px;background:' + statusBg + ';font-size:13px">';
html += '<p style="margin:0 0 8px 0"><b>Entscheidungsstatus:</b> ' + esc(reviewReadiness || statusLabel) + '</p>';
html += '<p style="margin:0"><b>Modus:</b> ' + esc(reviewModeLabel) + '</p>';
html += '</div>';
html += '</div>';

html += '<div style="margin:12px 0 16px;padding:12px;border:1px solid #d0d5dd;border-radius:8px;background:#ffffff;font-size:13px">';
html += '<p style="margin:0 0 8px 0"><b>KI-Begründung kurz:</b> ' + esc(reviewReason || 'Keine explizite KI-Begründung vorhanden.') + '</p>';
if (reviewFactors.length) {
  html += '<details style="margin:8px 0"><summary><b>Faktoren der KI-Einschätzung anzeigen</b></summary>';
  html += '<table style="border-collapse:collapse;width:100%;font-size:12px;background:#fff;margin:8px 0 0 0">';
  html += '<thead><tr><th style="border:1px solid #d0d5dd;padding:4px;text-align:left">Faktor</th><th style="border:1px solid #d0d5dd;padding:4px;text-align:right">Gewicht</th><th style="border:1px solid #d0d5dd;padding:4px;text-align:right">Bewertung</th><th style="border:1px solid #d0d5dd;padding:4px;text-align:right">Beitrag</th><th style="border:1px solid #d0d5dd;padding:4px;text-align:left">Begründung</th></tr></thead><tbody>';
  for (const factor of reviewFactors) {
    html += '<tr>'
      + '<td style="border:1px solid #d0d5dd;padding:4px">' + esc(factor.faktor) + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:4px;text-align:right">' + esc(factor.gewicht_prozent.toFixed(1) + ' %') + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:4px;text-align:right">' + esc(factor.bewertung_prozent.toFixed(0) + ' %') + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:4px;text-align:right">' + esc(factor.beitrag_prozentpunkte.toFixed(1)) + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:4px">' + esc(factor.begruendung || '—') + '</td>'
      + '</tr>';
  }
  html += '</tbody></table></details>';
}
if (reviewWarnings.length) {
  html += '<div style="margin-top:10px;padding:10px;border:1px solid #f79009;border-radius:8px;background:#fffaeb">';
  html += '<p style="margin:0 0 6px 0"><b>Zu prüfen:</b></p><ul style="margin:0 0 0 18px;padding:0">' + reviewWarnings.map((hint) => '<li>' + esc(hint) + '</li>').join('') + '</ul>';
  html += '</div>';
} else {
  html += '<p style="margin:0;color:#027a48"><b>Keine zusätzlichen Warnhinweise.</b></p>';
}
html += '</div>';

if (materialabweichungenGlobal.length || (Array.isArray(stuecklistenAbgleich.unbekannte_positionen) && stuecklistenAbgleich.unbekannte_positionen.length)) {
  html += '<div style="margin:12px 0 16px;padding:12px;border:1px solid #f79009;border-radius:8px;background:#fffaeb;font-size:13px">';
  html += '<p style="margin:0 0 8px 0"><b>Stücklisten-Abgleich nach Lieferantenantworten:</b> Die ursprünglichen Positionen bleiben geschützt. Abweichungen werden nur als Angebots-/Alternativinformation angezeigt.</p>';
  if (materialabweichungenGlobal.length) {
    html += '<ul style="margin:0 0 0 18px;padding:0">' + materialabweichungenGlobal.map((entry) => '<li>Pos. ' + esc(entry.pos ?? '') + ' / ' + esc(entry.lieferant ?? 'unbekannt') + ': ' + esc(entry.status ?? '') + (entry.begruendung ? ' – ' + esc(entry.begruendung) : '') + '</li>').join('') + '</ul>';
  }
  if (Array.isArray(stuecklistenAbgleich.unbekannte_positionen) && stuecklistenAbgleich.unbekannte_positionen.length) {
    html += '<p style="margin:8px 0 0 0;color:#b42318"><b>Unbekannte Positionen:</b> ' + esc(stuecklistenAbgleich.unbekannte_positionen.join(', ')) + '</p>';
  }
  html += '</div>';
}

if (reworkHints.length || reworkedCount) {
  html += '<div style="margin:12px 0 16px;padding:12px;border:1px solid #7a5af8;border-radius:8px;background:#f4f3ff;font-size:13px">';
  html += '<p style="margin:0 0 8px 0"><b>Letzte KI-Überarbeitung nach Nicht-Freigabe:</b> ' + esc(String(reworkedCount)) + ' Position(en) angepasst.</p>';
  if (reworkHints.length) {
    html += '<p style="margin:0 0 6px 0"><b>Globaler KI-Hinweis:</b></p><ul style="margin:0 0 0 18px;padding:0">' + reworkHints.map((hint) => '<li>' + esc(hint) + '</li>').join('') + '</ul>';
  }
  html += '</div>';
}

html += '<div style="overflow-x:auto">';
html += '<table style="border-collapse:collapse;width:100%;min-width:1600px;font-size:13px">';
html += '<thead><tr style="background:#f4f4f4">';
for (const head of ['Pos.', 'Artikel', 'Menge', 'Werkstoff / Norm', 'Auswahl', 'Lieferant', 'Status', 'Stückpreis', 'Lieferkosten', 'Entladung', 'Zusatzkosten', 'Gesamt', 'Lieferzeit', 'Verfügbarkeit', 'Quelle', 'KI-Hinweis']) {
  html += '<th style="border:1px solid #ddd;padding:6px;text-align:left;vertical-align:top">' + esc(head) + '</th>';
}
html += '</tr></thead><tbody>';

const supplierCostDisplaySeen = new Set();

for (const p of positionen) {
  const angeboteBase = Array.isArray(p.angebote) ? p.angebote.map((offer) => ({ ...offer })) : [];
  const bester = p.bester ?? null;
  const offers = [...angeboteBase];
  const selectedMatches = (offer) => Boolean(bester)
    && normalizeKey(offer?.lieferant ?? '') === normalizeKey(bester?.lieferant ?? '')
    && Math.abs(toNum(offer?.stueckpreis) - toNum(bester?.stueckpreis)) < 0.0001
    && normalizeKey(offer?.rfq_intern_id ?? offer?.rfq_id ?? '') === normalizeKey(bester?.rfq_intern_id ?? bester?.rfq_id ?? '');
  const hasSelectedOffer = bester && offers.some((offer) => selectedMatches(offer));
  if (bester && !hasSelectedOffer) offers.unshift({ ...bester });
  if (!offers.length) offers.push({});

  offers.sort((left, right) => {
    const leftSelected = selectedMatches(left);
    const rightSelected = selectedMatches(right);
    if (leftSelected !== rightSelected) return leftSelected ? -1 : 1;
    return toNum(left?.gesamt) - toNum(right?.gesamt);
  });

  const rowSpan = offers.length;
  const kiHintParts = [];
  if (p.kp2_ki_begruendung) kiHintParts.push(String(p.kp2_ki_begruendung));
  if (p.kp2_ki_unsicher) kiHintParts.push('KI markiert diese Auswahl als unsicher.');
  const abgleichHints = Array.isArray(p.af7_position_abgleich) ? p.af7_position_abgleich : [];
  for (const entry of abgleichHints) {
    kiHintParts.push('Stücklisten-Abgleich: ' + String(entry.status ?? '') + (entry.begruendung ? ' – ' + String(entry.begruendung) : ''));
  }
  const kiHint = deVisible(kiHintParts.join(' '));

  offers.forEach((offer, index) => {
    const isSelected = selectedMatches(offer);
    const rowBg = isSelected ? '#ecfdf3' : (index % 2 === 0 ? '#ffffff' : '#fafafa');
    const supplierCostKey = [
      normalizeKey(offer?.lieferant ?? ''),
      toNum(offer?.lieferkosten).toFixed(2),
      toNum(offer?.entladungspauschale).toFixed(2),
      toNum(offer?.zusatzkosten).toFixed(2),
    ].join('|');
    const showSupplierCosts = normalizeKey(offer?.lieferant ?? '') && !supplierCostDisplaySeen.has(supplierCostKey);
    if (showSupplierCosts) supplierCostDisplaySeen.add(supplierCostKey);
    const lieferkostenText = showSupplierCosts && offer?.lieferkosten !== undefined ? euro(offer?.lieferkosten) : '—';
    const entladungText = showSupplierCosts && offer?.entladungspauschale !== undefined ? euro(offer?.entladungspauschale) : '—';
    const zusatzkostenText = showSupplierCosts && offer?.zusatzkosten !== undefined ? euro(offer?.zusatzkosten) : '—';
    html += '<tr style="background:' + rowBg + '">';

    if (index === 0) {
      html += '<td rowspan="' + rowSpan + '" style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:center;font-weight:700">' + esc(p.pos ?? '') + '</td>';
      html += '<td rowspan="' + rowSpan + '" style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(p.Artikelbezeichnung ?? '') + '</td>';
      html += '<td rowspan="' + rowSpan + '" style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:center">' + esc(p.Menge ?? '') + '</td>';
      html += '<td rowspan="' + rowSpan + '" style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc([p.Werkstoff ?? '', p.Norm ?? ''].filter(Boolean).join(' | ') || '—') + '</td>';
    }

    const tone = offerTone(offer?.antwort_status, isSelected);
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top;font-weight:' + (isSelected ? '700' : '400') + '"><span style="display:inline-block;padding:3px 8px;border-radius:999px;background:' + tone.bg + ';color:' + tone.color + ';font-weight:700">' + esc(isSelected ? 'Ausgewählt' : 'Alternative') + '</span></td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(offer?.lieferant ?? '—') + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top"><span style="display:inline-block;padding:3px 8px;border-radius:999px;background:' + tone.bg + ';color:' + tone.color + ';font-weight:700">' + esc(tone.label) + '</span></td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:right">' + esc(offer?.stueckpreis !== undefined ? euro(offer?.stueckpreis) : '—') + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:right">' + esc(lieferkostenText) + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:right">' + esc(entladungText) + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:right">' + esc(zusatzkostenText) + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top;text-align:right;font-weight:' + (isSelected ? '700' : '400') + '">' + esc(offer?.gesamt !== undefined ? euro(offer?.gesamt) : '—') + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(days(offer?.lieferzeit_tage)) + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(deVisible(offer?.verfuegbarkeit ?? '—')) + '</td>';
    html += '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(offer?.preisquelle ?? '—') + '</td>';

    if (index === 0) {
      html += '<td rowspan="' + rowSpan + '" style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(kiHint || '—') + '</td>';
    }

    html += '</tr>';
  });
}

html += '</tbody></table>';
html += '</div>';
html += '<p style="margin:12px 0 0 0;font-size:12px;color:#5e6875">Bei Nicht-Freigabe bitte im Begründungsfeld kurz angeben, was geändert werden soll. Wenn du dort "Abbruch" schreibst, wird der Vorgang beendet.</p>';
html += '</div>';

return [{
  json: {
    ...debugCarry,
    kp2_mail_html: html,
    positionen,
    automatik_score_prozent: reviewScore,
    automatik_score_begruendung: reviewReason,
    automatik_warnhinweise: reviewWarnings,
    automatik_score_faktoren: reviewFactors,
    automatik_entscheidungsreife: reviewReadiness,
    ki_job_modus: reviewMode,
  },
}];

