parameters.jsCode:
const form = $json.data ?? $json;

const sanitize = (value) => {
  const raw = String(value ?? '').trim();
  if (/^\{\{[\s\S]*\}\}$/.test(raw)) return '';
  return raw;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const getField = (...aliases) => {
  for (const alias of aliases) {
    if (Object.prototype.hasOwnProperty.call(form, alias)) {
      return sanitize(form[alias]);
    }
  }

  const wanted = aliases.map((alias) => normalizeKey(alias));
  for (const [key, raw] of Object.entries(form)) {
    const keyNorm = normalizeKey(key);
    if (wanted.includes(keyNorm) || wanted.some((alias) => keyNorm.includes(alias))) {
      return sanitize(raw);
    }
  }

  return '';
};

const isAbortReason = (value) => /\b(abbruch|abbrechen|stopp?|stop|cancel|verwerfen|beenden)\b/i.test(String(value ?? '').trim());

const entscheidungRaw = getField('entscheidung', 'Entscheidung').toLowerCase();
const entscheidung = ['nicht_freigeben', 'nicht freigeben', 'ablehnen'].includes(entscheidungRaw)
  ? 'ablehnen'
  : entscheidungRaw;
const ablehnungsgrund = getField('ablehnungsgrund', 'Ablehnungsgrund / Änderungswunsch', 'Änderungswunsch', 'Aenderungswunsch');
const ablehnungsaktion = entscheidung === 'ablehnen'
  ? (isAbortReason(ablehnungsgrund) ? 'abbrechen' : 'erneut_bearbeiten')
  : '';

if (!['freigeben', 'ablehnen'].includes(entscheidung)) {
  throw new Error("Ungültige Entscheidung. Erlaubt: 'freigeben' oder 'nicht_freigeben'.");
}

if (entscheidung === 'ablehnen' && !ablehnungsgrund) {
  throw new Error('Bei Nicht-Freigabe ist eine Begründung bzw. ein Änderungswunsch erforderlich.');
}

const basis = $('KP2 – Übersicht vorbereiten').first().json.positionen;
if (!Array.isArray(basis) || !basis.length) {
  throw new Error('KP2-Basisdaten fehlen.');
}

return basis
  .map((p) => ({
    ...p,
    angebote: Array.isArray(p.angebote) ? p.angebote.map((angebot) => ({ ...angebot })) : [],
    bester: p.bester ? { ...p.bester } : null,
  }))
  .sort((a, b) => Number(a.pos ?? 0) - Number(b.pos ?? 0))
  .map((p) => ({
    json: {
      ...p,
      kp2_entscheidung: entscheidung,
      kp2_ablehnungsgrund: ablehnungsgrund,
      kp2_ablehnungsaktion: ablehnungsaktion,
      kp2_kommentar: ablehnungsgrund,
    },
  }));

const esc = (v = '') => String(v)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;');

const toNum = (v) => {
  const raw = String(v ?? '').trim();
  if (!raw) return 0;
  let normalized = raw.replace(/[^0-9,.-]/g, '');
  if (!normalized || normalized === '-' || normalized === ',' || normalized === '.') return 0;
  if (normalized.includes(',') && normalized.includes('.')) {
    normalized = normalized.lastIndexOf(',') > normalized.lastIndexOf('.')
      ? normalized.replace(/\./g, '').replace(',', '.')
      : normalized.replace(/,/g, '');
  } else if (normalized.includes(',')) {
    normalized = normalized.replace(',', '.');
  }
  const n = Number(normalized);
  return Number.isFinite(n) ? n : 0;
};

const euro = (value) => new Intl.NumberFormat('de-DE', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(toNum(value)) + ' €';
const hours = (value) => new Intl.NumberFormat('de-DE', { minimumFractionDigits: Number.isInteger(value) ? 0 : 1, maximumFractionDigits: 1 }).format(value);
const roundHalf = (value) => Math.max(0.5, Math.round(toNum(value) * 2) / 2);

const normalizeList = (value) => Array.isArray(value)
  ? value.map((entry) => String(entry ?? '').trim()).filter(Boolean)
  : [];

const splitEmails = (value) => String(value ?? '')
  .split(/[;,\n]+/)
  .map((entry) => entry.trim())
  .filter(Boolean);

const inputRows = $input.all().map((item) => item.json ?? {});
const first = inputRows[0] ?? {};

let data;
if (inputRows.length === 1 && Array.isArray(first.positionen)) {
  data = { ...first, positionen: first.positionen.map((entry) => ({ ...entry })) };
} else {
  data = { ...first, positionen: inputRows.map((entry) => ({ ...entry })) };
}

const positionen = Array.isArray(data.positionen) ? data.positionen : [];
const beschaffungskosten = Number((toNum(data.beschaffungskosten) || positionen.reduce((sum, p) => sum + toNum(p?.bester?.gesamt), 0)).toFixed(2));
const margenfaktor = Number((toNum(data.margenfaktor ?? 1.3) || 1.3).toFixed(3));
const kostenvoranschlag = Number((toNum(data.kostenvoranschlag) || (beschaffungskosten * margenfaktor)).toFixed(2));
const savedEmails = normalizeList(data.kunden_emails);
const kundenEmails = savedEmails.length ? savedEmails : splitEmails(data.kunden_to_email ?? '');
const kundenEmailsText = kundenEmails.join(', ');
const kiOpenPoints = normalizeList(data.kp3_ki_offene_punkte);
const kiHint = String(data.kp3_ki_hinweis ?? '').trim();
const validierungsfehler = String(data.kp3_validierungsfehler ?? '').trim();
const projektName = String(data.projektname ?? data.projekt ?? data.verwendungszweck ?? data.kundenprojekt ?? '').trim();
const projektLabel = projektName || '[Projekt/Verwendungszweck ergänzen]';
const subjectVorschlag = String(data.kundenmail_betreff ?? '').trim() || 'Kostenvoranschlag für ' + projektLabel;

const qtyTotal = positionen.reduce((sum, p) => sum + toNum(p.Menge), 0);
const prepMin = roundHalf(Math.max(1.5, positionen.length * 0.75 + qtyTotal * 0.08));
const prepMax = roundHalf(prepMin + Math.max(1, positionen.length * 0.45));
const onsiteMin = roundHalf(Math.max(2, positionen.length * 0.8 + qtyTotal * 0.05));
const onsiteMax = roundHalf(onsiteMin + Math.max(1.5, positionen.length * 0.6));

const materialLines = positionen.map((p) => {
  const artikel = String(p.Artikelbezeichnung ?? '').trim() || 'Materialposition';
  const menge = String(p.Menge ?? '').trim();
  const werkstoffNorm = [String(p.Werkstoff ?? '').trim(), String(p.Norm ?? '').trim()].filter(Boolean).join(' / ');
  const preis = toNum(p?.bester?.gesamt);
  return '- ' + artikel
    + (menge ? ', ' + menge + ' Stück' : '')
    + (werkstoffNorm ? ', ' + werkstoffNorm : '')
    + (preis > 0 ? ': kalkulierter Materialanteil ca. ' + euro(preis) : '');
}).filter(Boolean);

const materialPreviewHtml = materialLines.length
  ? '<pre style="background:#f8fafc;border:1px solid #d0d5dd;padding:10px;white-space:pre-wrap">' + esc(materialLines.join('\n')) + '</pre>'
  : '<p>Keine Positionen vorhanden.</p>';

const workEstimateText = [
  '- Vorarbeit im Unternehmen/Werkstatt: ca. ' + hours(prepMin) + ' bis ' + hours(prepMax) + ' Stunden für Materialprüfung, Zuschnitt, Vorbereitung, Schweiß-/Anpassarbeiten und Nacharbeit.',
  '- Arbeit vor Ort/Montage: ca. ' + hours(onsiteMin) + ' bis ' + hours(onsiteMax) + ' Stunden für Einbau, Ausrichtung, Befestigung und Abschlusskontrolle.',
].join('\n');

const defaultText =
  'Sehr geehrte Damen und Herren,\n\n' +
  'vielen Dank für Ihre Anfrage zu Ihrem Projekt "' + projektLabel + '". Auf Basis der aktuellen Materialangebote und unserer internen Kalkulation können wir Ihnen folgenden Kostenvoranschlag nennen.\n\n' +
  'Für die Umsetzung sind aktuell folgende Material- und Beschaffungskosten eingeplant:\n' +
  (materialLines.length ? materialLines.join('\n') + '\n\n' : 'Die Materialpositionen werden intern entsprechend der Projektanforderungen beschafft.\n\n') +
  'Geschätzter Arbeitsaufwand:\n' +
  workEstimateText + '\n\n' +
  'Die Schätzung umfasst die Vorbereitung der Materialien im Unternehmen sowie die Arbeiten vor Ort. Je nach Aufmaß, Zugänglichkeit und finaler Ausführung kann sich der tatsächliche Aufwand noch ändern.\n\n' +
  'Kostenvoranschlag gesamt: ' + euro(kostenvoranschlag) + '.\n\n' +
  'Wenn Sie mit dem Kostenvoranschlag einverstanden sind, geben Sie uns bitte kurz per E-Mail Bescheid. Bei Rückfragen oder Anpassungswünschen melden Sie sich gerne.\n\n' +
  'Mit freundlichen Grüßen';

const textVorschlag = String(data.kundenmail_text ?? '').trim() || defaultText;
const letzteEntscheidung = String(data.kundenentscheidung ?? '').trim();
const letzteBegruendung = String(data.kundenentscheidung_begruendung ?? '').trim();
const letzterAenderungswunsch = String(data.kundenentscheidung_aenderungswunsch ?? '').trim();
const letzteKundenmail = String(data.kundenantwort_mail ?? '').trim();

let html = '';
html += '<h2>KP3 – Kostenvoranschlag freigeben</h2>';
html += '<p><b>Projekt:</b> ' + esc(projektLabel) + '</p>';
html += '<p><b>Material/Beschaffung intern:</b> ' + esc(euro(beschaffungskosten)) + '</p>';
html += '<p><b>Margenfaktor:</b> ' + esc(margenfaktor.toFixed(3)) + '</p>';
html += '<p><b>Kostenvoranschlag an Kunden:</b> ' + esc(euro(kostenvoranschlag)) + '</p>';
html += '<p><b>Geschätzte Vorarbeit:</b> ' + esc(hours(prepMin) + ' bis ' + hours(prepMax) + ' Std.') + ' &nbsp; <b>Geschätzte Arbeit vor Ort:</b> ' + esc(hours(onsiteMin) + ' bis ' + hours(onsiteMax) + ' Std.') + '</p>';
html += '<p><b>Aktuelle Kunden-E-Mails:</b> ' + esc(kundenEmailsText || 'noch nicht gesetzt') + '</p>';
html += '<p><b>Vorgeschlagener Betreff:</b> ' + esc(subjectVorschlag) + '</p>';
html += '<p>Bitte prüfe den Projektbezug, die Arbeitszeit-Schätzung und den Gesamtpreis. Bei <b>freigeben</b> wird die Mail direkt an die unten eingetragenen Kunden-E-Mails gesendet.</p>';

if (validierungsfehler) {
  html += '<div style="margin:12px 0;padding:12px;border:1px solid #dc2626;border-radius:8px;background:#fef2f2;color:#991b1b">';
  html += '<p style="margin:0"><b>Betreff prüfen:</b> ' + esc(validierungsfehler) + '</p>';
  html += '</div>';
}

if (kiHint || kiOpenPoints.length) {
  html += '<div style="margin:12px 0;padding:12px;border:1px solid #b3b8c4;border-radius:8px;background:#f8fafc">';
  html += '<p style="margin:0 0 8px 0"><b>Hinweis aus letzter KI-Überarbeitung:</b> ' + esc(kiHint || 'Kein zusätzlicher Hinweis.') + '</p>';
  if (kiOpenPoints.length) html += '<p style="margin:0 0 6px 0"><b>Offene Punkte:</b></p><ul style="margin:0 0 0 18px;padding:0">' + kiOpenPoints.map((point) => '<li>' + esc(point) + '</li>').join('') + '</ul>';
  html += '</div>';
}

if (letzteEntscheidung || letzteBegruendung || letzterAenderungswunsch || letzteKundenmail) {
  html += '<div style="margin:12px 0;padding:12px;border:1px solid #f2cc8f;border-radius:8px;background:#fff7e6">';
  html += '<p style="margin:0 0 8px 0"><b>Letzte Kundenrückmeldung:</b></p>';
  if (letzteEntscheidung) html += '<p style="margin:0 0 6px 0"><b>Erkannte Entscheidung:</b> ' + esc(letzteEntscheidung) + '</p>';
  if (letzteBegruendung) html += '<p style="margin:0 0 6px 0"><b>Begründung:</b> ' + esc(letzteBegruendung) + '</p>';
  if (letzterAenderungswunsch) html += '<p style="margin:0 0 6px 0"><b>Änderungswunsch:</b> ' + esc(letzterAenderungswunsch) + '</p>';
  if (letzteKundenmail) html += '<p style="margin:0"><b>Originalmail:</b><br><pre style="background:#fff;border:1px solid #e5e7eb;padding:10px;white-space:pre-wrap">' + esc(letzteKundenmail) + '</pre></p>';
  html += '</div>';
}

html += '<table style="border-collapse:collapse;width:100%;font-family:Arial,sans-serif;font-size:13px">';
html += '<thead><tr style="background:#f4f4f4">';
html += '<th style="border:1px solid #ddd;padding:6px">Pos.</th>';
html += '<th style="border:1px solid #ddd;padding:6px">Material für Projektumsetzung</th>';
html += '<th style="border:1px solid #ddd;padding:6px">Lieferant</th>';
html += '<th style="border:1px solid #ddd;padding:6px">Kalkulierter Anteil</th>';
html += '</tr></thead><tbody>';
for (const p of positionen) {
  html += '<tr>'
    + '<td style="border:1px solid #ddd;padding:6px;text-align:center">' + esc(p.pos ?? '') + '</td>'
    + '<td style="border:1px solid #ddd;padding:6px">' + esc([p.Artikelbezeichnung, p.Menge ? p.Menge + ' Stück' : '', [p.Werkstoff, p.Norm].filter(Boolean).join(' / ')].filter(Boolean).join(', ')) + '</td>'
    + '<td style="border:1px solid #ddd;padding:6px">' + esc(p?.bester?.lieferant ?? '—') + '</td>'
    + '<td style="border:1px solid #ddd;padding:6px;text-align:right">' + esc(euro(p?.bester?.gesamt)) + '</td>'
    + '</tr>';
}
html += '</tbody></table>';
html += '<p style="margin-top:12px"><b>Materialübersicht für den Kundenmailtext:</b></p>' + materialPreviewHtml;
html += '<p style="margin-top:12px"><b>Arbeitszeit-Schätzung für den Kundenmailtext:</b></p>';
html += '<pre style="background:#f8fafc;border:1px solid #d0d5dd;padding:10px;white-space:pre-wrap">' + esc(workEstimateText) + '</pre>';
html += '<p style="margin-top:12px"><b>Vorschlagtext (im Formular bearbeitbar):</b></p>';
html += '<pre style="background:#f8fafc;border:1px solid #d0d5dd;padding:10px;white-space:pre-wrap">' + esc(textVorschlag) + '</pre>';

const parseTrace = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch {}
  }
  return [];
};

const appendTrace = (trace, entry) => [
  ...parseTrace(trace),
  {
    timestamp: new Date().toISOString(),
    warnings: [],
    errors: [],
    ...entry,
  },
];

const debugTrace = appendTrace(data.debug_trace, {
  step: 'KP3 – Kostenvoranschlag vorbereiten',
  status: validierungsfehler ? 'warnung' : 'ok',
  summary: 'Kostenvoranschlag, Kundenmail-Vorschlag, Materialübersicht und Arbeitszeit-Schätzung wurden für die Freigabe vorbereitet.',
  input: {
    positionen: positionen.length,
    kunden_emails: kundenEmails.length,
    projekt: projektLabel,
  },
  output: {
    beschaffungskosten,
    kostenvoranschlag,
    vorarbeit_stunden: hours(prepMin) + ' bis ' + hours(prepMax),
    vorort_stunden: hours(onsiteMin) + ' bis ' + hours(onsiteMax),
  },
  warnings: validierungsfehler ? [validierungsfehler] : [],
});

const debugCarry = {
  debug_run_id: data.debug_run_id,
  debug_started_at: data.debug_started_at,
  debug_cache_file: data.debug_cache_file,
  debug_trace: debugTrace,
  debug_file_write_ok: data.debug_file_write_ok,
  debug_file_write_error: data.debug_file_write_error,
};

return [{
  json: {
    ...data,
    ...debugCarry,
    positionen,
    beschaffungskosten,
    margenfaktor,
    kostenvoranschlag,
    projektname: projektName,
    arbeitszeit_vorarbeit_min: prepMin,
    arbeitszeit_vorarbeit_max: prepMax,
    arbeitszeit_vorort_min: onsiteMin,
    arbeitszeit_vorort_max: onsiteMax,
    kp3_mail_html: html,
    kp3_textvorschlag: textVorschlag,
    kp3_betreff_vorschlag: subjectVorschlag,
    kp3_empfaenger_vorschlag: kundenEmailsText,
  },
}];

