parameters.jsCode:
const form = $json.data ?? $json;

const sanitize = (value) => {
  const raw = String(value ?? '').trim();
  if (/^\{\{[\s\S]*\}\}$/.test(raw)) return '';
  return raw;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const getField = (...aliases) => {
  for (const alias of aliases) {
    if (Object.prototype.hasOwnProperty.call(form, alias)) {
      return sanitize(form[alias]);
    }
  }

  const wanted = aliases.map((alias) => normalizeKey(alias));
  for (const [key, raw] of Object.entries(form)) {
    const keyNorm = normalizeKey(key);
    if (wanted.includes(keyNorm) || wanted.some((alias) => keyNorm.includes(alias))) {
      return sanitize(raw);
    }
  }

  return '';
};

const toNum = (v) => {
  const n = Number(String(v ?? '').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

const extractEmails = (value) => {
  const normalized = String(value ?? '')
    .replace(/[\u00A0\u2009\u200A\u202F\u205F\u3000]/g, ' ')
    .replace(/\s*@\s*/g, '@');

  const matches = normalized.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/ig) || [];
  const out = [];
  const seen = new Set();
  for (const entry of matches) {
    const mail = String(entry ?? '').trim();
    const key = mail.toLowerCase();
    if (!mail || seen.has(key)) continue;
    seen.add(key);
    out.push(mail);
  }
  return out;
};

const subjectNeedsPurpose = (value) => /\[.*verwendungszweck.*\]|verwendungszweck ergänzen/i.test(String(value ?? ''));

const entscheidung = getField('entscheidung', 'Entscheidung').toLowerCase();
const ablehnungsgrund = getField('ablehnungsgrund', 'Ablehnungsgrund');

if (!['freigeben', 'ablehnen'].includes(entscheidung)) {
  throw new Error("Ungültige Entscheidung. Erlaubt: 'freigeben' oder 'ablehnen'.");
}

if (entscheidung === 'ablehnen' && !ablehnungsgrund) {
  throw new Error('Ablehnung ohne Grund ist nicht zulässig.');
}

const basisRaw = $('KP3 – Übersicht vorbereiten').first().json;
const {
  kundenantwort_mail_html,
  kundenantwort_mail,
  kundenentscheidung,
  kundenentscheidung_begruendung,
  kundenentscheidung_aenderungswunsch,
  kundenentscheidung_unsicher,
  kundenentscheidung_quelle,
  kp3_validierungsfehler,
  kp3_betreff_status,
  ...basis
} = basisRaw;

const margenfaktorRaw = getField('margenfaktor', 'Margenfaktor') || String(basis.margenfaktor ?? '1.3');
const margenfaktor = toNum(margenfaktorRaw);
if (!(margenfaktor > 0)) {
  throw new Error('margenfaktor muss größer als 0 sein.');
}

const beschaffungskosten = toNum(basis.beschaffungskosten);
const kostenvoranschlag = Number((beschaffungskosten * margenfaktor).toFixed(2));
const kundenmailText = getField('kundenmail_text', 'Kundenmailtext') || String(basis.kp3_textvorschlag ?? basis.kundenmail_text ?? '');
const kundenmailBetreffInput = getField('kundenmail_betreff', 'Betreff der Kundenmail');
const kundenmailBetreff = kundenmailBetreffInput || String(basis.kp3_betreff_vorschlag ?? basis.kundenmail_betreff ?? 'Kostenvoranschlag für [Verwendungszweck ergänzen]');
const emailRaw = getField('kunden_emails', 'Kunden-E-Mails') || String(basis.kp3_empfaenger_vorschlag ?? basis.kunden_to_email ?? '');
const kundenEmails = extractEmails(emailRaw);
const kommentarFreitext = getField('kommentar_freitext', 'Zusätzlicher Kommentar (optional)', 'Kommentar');
const kommentar = kommentarFreitext || (entscheidung === 'ablehnen' ? ablehnungsgrund : '');

if (entscheidung === 'freigeben' && !kundenEmails.length) {
  throw new Error('Bei freigeben muss mindestens eine gültige Kunden-E-Mail angegeben werden.');
}
if (entscheidung === 'freigeben' && !kundenmailText) {
  throw new Error('Bei freigeben darf der Kundenmailtext nicht leer sein.');
}

const betreffUngueltig = entscheidung === 'freigeben' && (!kundenmailBetreffInput || subjectNeedsPurpose(kundenmailBetreffInput));
const betreffStatus = betreffUngueltig ? 'fehlt' : 'ok';
const validierungsfehler = betreffUngueltig
  ? 'Bitte wähle einen konkreten Betreff mit Verwendungszweck, z. B. „Kostenvoranschlag für Gartenzaun“.'
  : '';

return [{
  json: {
    ...basis,
    margenfaktor: Number(margenfaktor.toFixed(3)),
    beschaffungskosten,
    kostenvoranschlag,
    kunden_emails: kundenEmails,
    kunden_to_email: kundenEmails.join(', '),
    kundenmail_betreff: kundenmailBetreff,
    kundenmail_text: kundenmailText,
    kp3_entscheidung: entscheidung,
    kp3_ablehnungsgrund: ablehnungsgrund,
    kp3_kommentar: kommentar,
    kp3_betreff_status: betreffStatus,
    kp3_validierungsfehler: validierungsfehler,
  },
}];

const esc = (v = '') => String(v)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;');

  const toNum = (value) => {
    const raw = String(value ?? '').trim();
    if (!raw) return 0;
    let normalized = raw.replace(/[^0-9,.-]/g, '');
    if (!normalized || normalized === '-' || normalized === ',' || normalized === '.') return 0;
    if (normalized.includes(',') && normalized.includes('.')) {
      if (normalized.lastIndexOf(',') > normalized.lastIndexOf('.')) {
        normalized = normalized.replace(/\./g, '').replace(',', '.');
      } else {
        normalized = normalized.replace(/,/g, '');
      }
    } else if (normalized.includes(',')) {
      normalized = normalized.replace(',', '.');
    }
    const number = Number(normalized);
    return Number.isFinite(number) ? number : 0;
  };

  const round = (value) => Number((Math.round(toNum(value) * 100) / 100).toFixed(2));

  const euro = (value) => new Intl.NumberFormat('de-DE', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(toNum(value)) + ' €';

  const quantity = (value) => {
    const raw = String(value ?? '').trim();
    if (!raw) return '—';
    const numeric = toNum(raw);
    if (!numeric) return raw;
    return new Intl.NumberFormat('de-DE', {
      minimumFractionDigits: Number.isInteger(numeric) ? 0 : 2,
      maximumFractionDigits: 2,
    }).format(numeric);
  };

  const formatQuantity = (value) => {
    const raw = String(value ?? '').trim();
    if (!raw) return '';
    const numeric = toNum(raw);
    if (!numeric) return raw;
    return new Intl.NumberFormat('de-DE', {
      minimumFractionDigits: Number.isInteger(numeric) ? 0 : 2,
      maximumFractionDigits: 2,
    }).format(numeric);
  };

  const prettifyArticle = (value) => String(value ?? '')
    .trim()
    .replace(/(\d)\.(\d)/g, '$1,$2')
    .replace(/(\d)\s*[xX]\s*(\d)/g, '$1 x $2');

  const prettifyMaterial = (value) => String(value ?? '')
    .trim()
    .replace(/\bEDELSTAHL\b/g, 'Edelstahl')
    .replace(/\bALUMINIUM\b/g, 'Aluminium');

  const buildSubject = (positions) => {
    const labels = (Array.isArray(positions) ? positions : [])
      .map((entry) => prettifyArticle(entry.artikel))
      .filter(Boolean);

    if (!labels.length) return 'Bestellung Material';
    const first = labels[0];
    if (labels.length === 1) return 'Bestellung – ' + first;
    return 'Bestellung – ' + first + ' und ' + String(labels.length - 1) + ' weitere' + (labels.length - 1 === 1 ? 's Material' : ' Materialien');
  };

  const materialOrderSentence = (entry, index) => {
    const details = [
      entry.menge ? entry.menge + ' Stück' : '',
      entry.artikel || '',
      entry.werkstoff ? 'aus ' + entry.werkstoff : '',
      entry.norm ? 'nach ' + entry.norm : '',
    ].filter(Boolean).join(' ');

    const priceParts = [];
    if (entry.stueckpreis > 0) priceParts.push('Der Stückpreis laut Angebot beträgt ' + euro(entry.stueckpreis) + ' netto');
    if (entry.preis > 0) priceParts.push('der Gesamtpreis für diese Menge beträgt ' + euro(entry.preis) + ' netto');

    const intro = index === 0 ? 'Wir bestellen ' : 'Zusätzlich bestellen wir ';
    return intro + (details || 'das angebotene Material') + '.' + (priceParts.length ? ' ' + priceParts.join(', ') + '.' : '');
  };

  const buildMailText = (lieferant, positions, supplierCosts, summe) => {
    const list = Array.isArray(positions) ? positions : [];
    const lines = [];
    lines.push('Guten Tag ' + lieferant + '-Team,', '');
    lines.push('vielen Dank für Ihr Angebot. Wir bestellen auf dieser Grundlage die folgenden Materialien:', '');

    for (let i = 0; i < list.length; i += 1) {
      lines.push(materialOrderSentence(list[i], i), '');
    }

    if (supplierCosts > 0) {
      lines.push('Die Liefer- und Nebenkosten laut Angebot betragen ' + euro(supplierCosts) + ' netto.', '');
    }

    if (summe > 0) {
      lines.push('Der voraussichtliche Gesamtbestellwert beträgt ' + euro(summe) + ' netto.', '');
    }

    lines.push('Bitte bestätigen Sie uns die Bestellung sowie den Liefertermin schriftlich per E-Mail.', '');
    lines.push('Mit freundlichen Grüßen');
    return lines.join('\n');
  };

  const hasInternalOrderLabels = (body) => /(?:^|\n)\s*(?:pos\.?|position)\s*\d+\s*(?::|\)|\.|-|–|—)|folgenden\s+Positionen|Positionspreis|Materialposition/i.test(String(body ?? ''));

  const naturalizeOrderMailText = (body, lieferant, positions, supplierCosts, summe) => {
    const raw = String(body ?? '').trim();
    const list = Array.isArray(positions) ? positions : [];
    if (!raw || (hasInternalOrderLabels(raw) && list.length)) {
      return buildMailText(String(lieferant || 'Lieferant').trim(), list, supplierCosts, summe);
    }
    return raw
      .replace(/folgenden\s+Positionen/gi, 'folgenden Materialien')
      .replace(/Positionspreis laut Angebot/gi, 'Gesamtpreis für diese Menge laut Angebot')
      .replace(/\bMaterialpositionen\b/g, 'Materialien')
      .replace(/\bMaterialposition\b/g, 'Material')
      .trim();
  };

  const renderPositions = (rows) => {
    const list = Array.isArray(rows) ? rows : [];
    if (!list.length) {
      return '<p style="margin:8px 0 0 0">Keine Materialdaten vorhanden.</p>';
    }

    return list.map((entry, index) => {
      const pos = Number.parseInt(String(entry?.pos ?? ''), 10) || index + 1;
      const artikel = String(entry?.artikel ?? entry?.Artikelbezeichnung ?? '').trim();
      const menge = quantity(entry?.menge ?? entry?.Menge ?? '');
      const werkstoff = String(entry?.werkstoff ?? entry?.Werkstoff ?? '').trim();
      const norm = String(entry?.norm ?? entry?.Norm ?? '').trim();
      const stueckpreis = toNum(entry?.stueckpreis);
      const positionspreis = toNum(entry?.preis ?? entry?.gesamt ?? 0);

      let html = '';
      html += '<div style="margin:10px 0;padding:10px;border:1px solid #e4e7ec;border-radius:8px;background:#ffffff">';
      html += '<p style="margin:0 0 6px 0;font-weight:700">Material ' + esc(index + 1) + '</p>';
      html += '<p style="margin:0 0 4px 0">' + esc(artikel || '—') + '</p>';
      html += '<p style="margin:0 0 4px 0"><b>Menge:</b> ' + esc(menge) + ' Stück</p>';
      html += '<p style="margin:0 0 4px 0"><b>Werkstoff:</b> ' + esc(werkstoff || '—') + '</p>';
      html += '<p style="margin:0 0 4px 0"><b>Norm:</b> ' + esc(norm || '—') + '</p>';
      if (stueckpreis > 0) {
        html += '<p style="margin:0 0 4px 0"><b>Stückpreis laut Angebot:</b> ' + esc(euro(stueckpreis)) + ' netto</p>';
      }
      if (positionspreis > 0) {
        html += '<p style="margin:0"><b>Gesamtpreis für diese Menge:</b> ' + esc(euro(positionspreis)) + ' netto</p>';
      }
      html += '</div>';
      return html;
    }).join('');
  };

  const normalizeExistingDraft = (entry) => {
    const out = {
      ...entry,
      lieferant: String(entry?.lieferant ?? '').trim(),
      to_email: String(entry?.to_email ?? '').trim(),
      mail_subject: String(entry?.mail_subject ?? '').trim(),
      entwurf_text: String(entry?.entwurf_text ?? '').trim(),
      positionen: Array.isArray(entry?.positionen) ? entry.positionen.map((pos) => ({ ...pos })) : [],
      lieferkosten: round(entry?.lieferkosten),
      entladungspauschale: round(entry?.entladungspauschale),
      zusatzkosten: round(entry?.zusatzkosten),
      nebenkosten: round(entry?.nebenkosten ?? (toNum(entry?.lieferkosten) + toNum(entry?.entladungspauschale) + toNum(entry?.zusatzkosten))),
      positionssumme: round(entry?.positionssumme),
      summe: round(entry?.summe ?? entry?.gesamt ?? entry?.preis),
    };
    if (!out.mail_subject) out.mail_subject = buildSubject(out.positionen);
    out.entwurf_text = naturalizeOrderMailText(out.entwurf_text, out.lieferant, out.positionen, out.nebenkosten, out.summe);
    return out;
  };

  const buildDraftsFromPositionen = (data, positionen) => {
    const gruppen = new Map();

    for (const p of positionen) {
      const supplierName = String(p?.bester?.lieferant ?? 'Unbekannt').trim() || 'Unbekannt';
      const toEmail = String(p?.bester?.to_email ?? '').trim();

      if (!gruppen.has(supplierName)) {
        gruppen.set(supplierName, {
          to_email: toEmail,
          lieferkosten: 0,
          entladungspauschale: 0,
          zusatzkosten: 0,
          positionspreis_summe: 0,
          posis: [],
        });
      }

      const gruppe = gruppen.get(supplierName);
      if (!gruppe.to_email && toEmail) gruppe.to_email = toEmail;

      const mengeRaw = p.Menge ?? '';
      const mengeNum = toNum(mengeRaw);
      const stueckpreis = round(p?.bester?.stueckpreis);
      const positionspreis = round(p?.bester?.kosten_variable || (stueckpreis * mengeNum));

      gruppe.lieferkosten = Math.max(gruppe.lieferkosten, round(p?.bester?.lieferkosten));
      gruppe.entladungspauschale = Math.max(gruppe.entladungspauschale, round(p?.bester?.entladungspauschale));
      gruppe.zusatzkosten = Math.max(gruppe.zusatzkosten, round(p?.bester?.zusatzkosten));
      gruppe.positionspreis_summe = round(gruppe.positionspreis_summe + positionspreis);

      gruppe.posis.push({
        pos: p.pos ?? '',
        artikel: prettifyArticle(p.Artikelbezeichnung ?? ''),
        menge: formatQuantity(mengeRaw),
        werkstoff: prettifyMaterial(p.Werkstoff ?? ''),
        norm: String(p.Norm ?? '').trim(),
        stueckpreis,
        preis: positionspreis,
      });
    }

    return Array.from(gruppen.entries()).map(([lieferant, gruppe]) => {
      const lieferkosten = round(gruppe.lieferkosten);
      const entladungspauschale = round(gruppe.entladungspauschale);
      const zusatzkosten = round(gruppe.zusatzkosten);
      const nebenkosten = round(lieferkosten + entladungspauschale + zusatzkosten);
      const positionssumme = round(gruppe.positionspreis_summe);
      const summe = round(positionssumme + nebenkosten);
      const posis = gruppe.posis;

      return {
        lieferant,
        to_email: String(gruppe.to_email ?? '').trim(),
        positionen: posis,
        lieferkosten,
        entladungspauschale,
        zusatzkosten,
        nebenkosten,
        positionssumme,
        summe,
        mail_subject: buildSubject(posis),
        entwurf_text: buildMailText(lieferant, posis, nebenkosten, summe),
        beschaffungskosten: toNum(data.beschaffungskosten),
        kostenvoranschlag: toNum(data.kostenvoranschlag),
        kundenmail_text: String(data.kundenmail_text ?? ''),
        margenfaktor: toNum(data.margenfaktor),
      };
    });
  };

  const inputRows = $input.all().map((item) => item.json ?? {});
  const first = inputRows[0] ?? {};

  let passthrough = { ...first };
  let entwuerfe = [];

  if (inputRows.length === 1 && Array.isArray(first.bestellentwuerfe)) {
    entwuerfe = first.bestellentwuerfe.map((entry) => normalizeExistingDraft(entry));
  } else if (inputRows.some((entry) => entry?.entwurf_text || entry?.mail_subject || entry?.lieferant)) {
    entwuerfe = inputRows.map((entry) => normalizeExistingDraft(entry));
  } else {
    const positionen = Array.isArray(first.positionen) ? first.positionen.map((entry) => ({ ...entry })) : inputRows.map((entry) => ({ ...entry }));
    passthrough = {
      ...first,
      positionen,
    };
    entwuerfe = buildDraftsFromPositionen(passthrough, positionen);
  }

  if (!entwuerfe.length) {
    throw new Error('Keine Bestellentwürfe für KP4 gefunden.');
  }

  entwuerfe = entwuerfe.map((entry) => ({
    ...entry,
    mail_subject: String(entry.mail_subject || buildSubject(entry.positionen)).trim(),
    entwurf_text: naturalizeOrderMailText(entry.entwurf_text, entry.lieferant, entry.positionen, entry.nebenkosten, entry.summe),
  }));

  let html = '';
  html += '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.5">';
  html += '<h2 style="margin:0 0 10px 0">KP4 – Bestellmails prüfen</h2>';
  html += '<p style="margin:0 0 8px 0">Bitte prüfe Betreff und Bestellmail je Lieferant. Bei Freigabe können die Texte direkt im Formular bearbeitet werden. Bei Ablehnung reicht ein kurzer Grund.</p>';
  html += '<div style="display:flex;flex-wrap:wrap;gap:12px;margin:12px 0 16px 0">';
  html += '<div style="min-width:180px;padding:12px;border:1px solid #d0d5dd;border-radius:10px;background:#f8fafc"><div style="font-size:12px;color:#475467;margin-bottom:4px">Lieferanten</div><div style="font-size:20px;font-weight:700;color:#101828">' + esc(String(entwuerfe.length)) + '</div></div>';
  const gesamtSumme = entwuerfe.reduce((acc, entry) => acc + toNum(entry?.summe ?? entry?.gesamt ?? entry?.preis ?? 0), 0);
  html += '<div style="min-width:180px;padding:12px;border:1px solid #d0d5dd;border-radius:10px;background:#f8fafc"><div style="font-size:12px;color:#475467;margin-bottom:4px">Summe Bestellungen</div><div style="font-size:20px;font-weight:700;color:#101828">' + esc(euro(gesamtSumme)) + '</div></div>';
  html += '</div>';

  for (const entry of entwuerfe) {
    const supplierSumme = toNum(entry?.summe ?? entry?.gesamt ?? entry?.preis ?? 0);
    const nebenkosten = toNum(entry?.nebenkosten);

    html += '<div style="margin:12px 0;padding:12px;border:1px solid #d0d5dd;border-radius:10px;background:#ffffff">';
    html += '<h3 style="margin:0 0 6px 0">' + esc(entry.lieferant ?? 'Unbekannter Lieferant') + '</h3>';
    html += '<p style="margin:0 0 6px 0"><b>Empfänger:</b> ' + esc(entry.to_email ?? '—') + '</p>';
    html += '<p style="margin:0 0 6px 0"><b>Betreff:</b> ' + esc(entry.mail_subject ?? '—') + '</p>';
    html += '<p style="margin:0 0 6px 0"><b>Voraussichtlicher Bestellwert:</b> ' + esc(euro(supplierSumme)) + '</p>';
    if (nebenkosten > 0) {
      html += '<p style="margin:0 0 6px 0"><b>Liefer- und Nebenkosten laut Angebot:</b> ' + esc(euro(nebenkosten)) + '</p>';
    }
    html += '<div style="font-size:13px;color:#344054"><b>Materialien:</b>' + renderPositions(entry.positionen) + '</div>';
    html += '</div>';
  }

  html += '<p style="margin:12px 0 0 0;font-size:12px;color:#475467">Bei Ablehnung werden die Bestellmails nicht versendet, sondern mit dem Ablehnungsgrund überarbeitet und erneut vorgelegt.</p>';
  html += '</div>';

  const fields = [
    {
      fieldType: 'html',
      elementName: 'kp4_decision_hint',
      html:
        '<div class="kp4-approve-hint" style="margin:0 0 8px 0;padding:12px;border:1px solid #d0d5dd;border-radius:8px;background:#f8fafc;font-family:Arial,sans-serif;color:#1f2937">' +
        '<p style="margin:0"><b>Freigeben:</b> Prüfe und bearbeite Betreff und Bestellmails direkt im Formular.</p>' +
        '</div>' +
        '<div class="kp4-reject-hint" style="display:none;margin:0 0 8px 0;padding:12px;border:1px solid #f79009;border-radius:8px;background:#fffaeb;font-family:Arial,sans-serif;color:#1f2937">' +
        '<p style="margin:0"><b>Ablehnung:</b> Bitte nur den Ablehnungsgrund eintragen. Die Bestellmails werden dann nicht versendet, sondern überarbeitet.</p>' +
        '</div>',
    },
    {
      fieldName: 'entscheidung',
      fieldLabel: 'Entscheidung',
      fieldType: 'dropdown',
      defaultValue: 'freigeben',
      requiredField: true,
      fieldOptions: {
        values: [{ option: 'freigeben' }, { option: 'ablehnen' }],
      },
    },
    {
      fieldName: 'ablehnungsgrund',
      fieldLabel: 'Ablehnungsgrund',
      fieldType: 'textarea',
      placeholder: 'Nur bei Ablehnung ausfüllen.',
    },
  ];

  entwuerfe.forEach((entry, index) => {
    fields.push({
      fieldType: 'html',
      elementName: 'kp4_meta_' + index,
      html:
        '<div class="kp4-draft-meta" style="margin:16px 0 8px 0;padding:12px;border:1px solid #d0d5dd;border-radius:8px;background:#f8fafc;font-family:Arial,sans-serif;color:#1f2937">' +
        '<h3 style="margin:0 0 6px 0">' + esc(entry.lieferant ?? 'Unbekannter Lieferant') + '</h3>' +
        '<p style="margin:0 0 6px 0"><b>Empfänger:</b> ' + esc(entry.to_email ?? '—') + '</p>' +
        '<p style="margin:0 0 6px 0"><b>Betreff:</b> ' + esc(entry.mail_subject ?? '—') + '</p>' +
        '<p style="margin:0"><b>Materialien:</b></p>' +
        renderPositions(entry.positionen) +
        '</div>',
    });

    fields.push({
      fieldName: 'bestellbetreff_' + index,
      fieldLabel: 'Betreff – ' + String(entry.lieferant ?? ('Lieferant ' + (index + 1))),
      fieldType: 'text',
      defaultValue: String(entry.mail_subject ?? '').trim(),
      requiredField: true,
    });

    fields.push({
      fieldName: 'bestellmail_' + index,
      fieldLabel: 'Bestellmail – ' + String(entry.lieferant ?? ('Lieferant ' + (index + 1))),
      fieldType: 'textarea',
      defaultValue: String(entry.entwurf_text ?? '').trim(),
      requiredField: true,
    });
  });

  fields.push({
    fieldName: 'kp4_payload',
    fieldType: 'hiddenField',
    fieldValue: JSON.stringify(entwuerfe),
  });

  const parseTrace = (value) => {
    if (Array.isArray(value)) return value;
    if (typeof value === 'string' && value.trim()) {
      try {
        const parsed = JSON.parse(value);
        return Array.isArray(parsed) ? parsed : [];
      } catch {}
    }
    return [];
  };

  const appendTrace = (trace, entry) => [
    ...parseTrace(trace),
    {
      timestamp: new Date().toISOString(),
      warnings: [],
      errors: [],
      ...entry,
    },
  ];

  const debugTrace = appendTrace(passthrough.debug_trace, {
    step: 'KP4 – Bestellmails vorbereiten',
    status: 'ok',
    summary: 'Natürliche Bestellmails ohne interne Positionsformulierungen wurden zur Freigabe vorbereitet.',
    input: {
      lieferanten: entwuerfe.length,
    },
    output: {
      bestellmails: entwuerfe.length,
      bestellwert_gesamt: gesamtSumme,
    },
  });

  const debugCarry = {
    debug_run_id: passthrough.debug_run_id,
    debug_started_at: passthrough.debug_started_at,
    debug_cache_file: passthrough.debug_cache_file,
    debug_trace: debugTrace,
    debug_file_write_ok: passthrough.debug_file_write_ok,
    debug_file_write_error: passthrough.debug_file_write_error,
  };

  return [{
    json: {
      ...passthrough,
      ...debugCarry,
      kp4_mail_html: html,
      kp4_form_fields: JSON.stringify(fields),
      bestellentwuerfe: entwuerfe,
    },
  }];

