parameters.jsCode:
const form = $json.data ?? $json ?? {};

const sanitize = (value) => {
  const raw = String(value ?? '').trim();
  if (/^\{\{[\s\S]*\}\}$/.test(raw)) return '';
  return raw;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const getField = (...aliases) => {
  for (const alias of aliases) {
    if (Object.prototype.hasOwnProperty.call(form, alias)) {
      return sanitize(form[alias]);
    }
  }

  const wanted = aliases.map((alias) => normalizeKey(alias));
  for (const [key, raw] of Object.entries(form)) {
    const keyNorm = normalizeKey(key);
    if (wanted.includes(keyNorm) || wanted.some((alias) => keyNorm.includes(alias) || alias.includes(keyNorm))) {
      return sanitize(raw);
    }
  }

  return '';
};

const entscheidung = getField('entscheidung', 'Entscheidung').toLowerCase();
const ablehnungsgrund = getField('ablehnungsgrund', 'Ablehnungsgrund');

if (!['freigeben', 'ablehnen'].includes(entscheidung)) {
  throw new Error("Ungültige Entscheidung. Erlaubt: 'freigeben' oder 'ablehnen'.");
}

if (entscheidung === 'ablehnen' && !ablehnungsgrund) {
  throw new Error('Ablehnung ohne Grund ist nicht zulässig.');
}

const basis = $('KP4 – Übersicht vorbereiten').first().json ?? {};
const debugCarry = {
  debug_run_id: basis.debug_run_id,
  debug_started_at: basis.debug_started_at,
  debug_cache_file: basis.debug_cache_file,
  debug_trace: basis.debug_trace,
  debug_file_write_ok: basis.debug_file_write_ok,
  debug_file_write_error: basis.debug_file_write_error,
};
const hasInternalOrderLabels = (body) => /(?:^|\n)\s*(?:pos\.?|position)\s*\d+\s*(?::|\)|\.|-|–|—)|folgenden\s+Positionen|Positionspreis|Materialposition/i.test(String(body ?? ''));
const entwuerfe = Array.isArray(basis.bestellentwuerfe)
  ? basis.bestellentwuerfe.map((entry) => ({ ...entry }))
  : [];

if (!entwuerfe.length) {
  throw new Error('Keine Bestellentwürfe für KP4 gefunden.');
}

const combinedText = [];

return entwuerfe.map((entry, index) => {
  const supplierName = String(entry.lieferant ?? ('Lieferant ' + (index + 1)));
  const subjectLabel = 'Betreff – ' + supplierName;
  const bodyLabel = 'Bestellmail – ' + supplierName;
  const editedSubject = getField('bestellbetreff_' + index, subjectLabel) || String(entry.mail_subject ?? '').trim();
  let editedText = getField('bestellmail_' + index, bodyLabel) || String(entry.entwurf_text ?? '').trim();
  if (hasInternalOrderLabels(editedText) && String(entry.entwurf_text ?? '').trim()) {
    editedText = String(entry.entwurf_text ?? '').trim();
  }

  if (entscheidung === 'freigeben' && !editedSubject) {
    throw new Error('Betreff für ' + supplierName + ' darf bei Freigabe nicht leer sein.');
  }
  if (entscheidung === 'freigeben' && !editedText) {
    throw new Error('Bestellmail für ' + supplierName + ' darf bei Freigabe nicht leer sein.');
  }

  combinedText.push('Lieferant: ' + String(entry.lieferant ?? ''));
  combinedText.push('Betreff: ' + editedSubject);
  combinedText.push(editedText);

  return {
    json: {
      ...entry,
      ...debugCarry,
      mail_subject: editedSubject,
      entwurf_text: editedText,
      bestellmail_gesamttext: combinedText.join('\n\n-----\n\n'),
      kp4_entscheidung: entscheidung,
      kp4_ablehnungsgrund: ablehnungsgrund,
      kp4_kommentar: entscheidung === 'ablehnen' ? ablehnungsgrund : '',
      kp4_aenderung_hinweis: '',
    },
  };
});

const esc = (value = '') => String(value)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;');

  const toNum = (value) => {
    const raw = String(value ?? '').replace(',', '.');
    const number = Number(raw);
    return Number.isFinite(number) ? number : 0;
  };

  const round = (value) => Number((Math.round(toNum(value) * 100) / 100).toFixed(2));

  const normalizeKey = (value) => String(value ?? '')
    .toLowerCase()
    .replace(/ä/g, 'ae')
    .replace(/ö/g, 'oe')
    .replace(/ü/g, 'ue')
    .replace(/ß/g, 'ss')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();

  const articleMatches = (expected, received) => {
    const left = normalizeKey(expected);
    const right = normalizeKey(received);
    if (!left || !right) return true;
    if (left.includes(right) || right.includes(left)) return true;

    const leftTokens = left.split(' ').filter((token) => token.length >= 4);
    const rightTokens = new Set(right.split(' ').filter((token) => token.length >= 4));
    const overlap = leftTokens.filter((token) => rightTokens.has(token)).length;
    return overlap >= Math.min(2, Math.min(leftTokens.length, rightTokens.size || 0));
  };

  const euro = (value) => toNum(value).toFixed(2) + ' €';

  const moneyVariants = (value) => {
    const number = round(value);
    if (!number) return [];
    const fixed = number.toFixed(2);
    const de = fixed.replace('.', ',');
    const compactDe = de.replace(',00', '');
    const compactFixed = fixed.replace('.00', '');
    return Array.from(new Set([fixed, de, compactDe, compactFixed].filter(Boolean)));
  };

  const containsMoney = (text, value) => {
    const raw = String(text ?? '');
    return moneyVariants(value).some((variant) => raw.includes(variant));
  };

  const renderIssue = (entry) => {
    const posText = Number(entry?.pos) > 0 ? 'Pos ' + entry.pos + ': ' : '';

    if (entry?.typ === 'menge') {
      return posText + 'Mengenabweichung, erwartet ' + entry.erwartet + ', erhalten ' + entry.erhalten + '.';
    }
    if (entry?.typ === 'preis') {
      return posText + 'Preisabweichung, erwartet ' + entry.erwartet + ', erhalten ' + entry.erhalten + '.';
    }
    if (entry?.typ === 'artikel') {
      return posText + 'Artikelabweichung, erwartet "' + String(entry.erwartet ?? '') + '", erkannt "' + String(entry.erhalten ?? '') + '".';
    }
    if (entry?.typ === 'preis_quelle_unbelegt') {
      return posText + 'Preis wurde von der KI bestätigt, ist in der Auftragsbestätigung aber nicht direkt als Geldbetrag auffindbar.';
    }
    if (entry?.typ === 'lieferant_abweichend') {
      return posText + 'Lieferant/Signatur passt nicht eindeutig zur Bestellung: ' + String(entry.info ?? '');
    }

    return posText + String(entry?.info ?? entry?.typ ?? 'Abweichung');
  };

  const renderPositionRows = (rows, type) => {
    const list = Array.isArray(rows) ? rows : [];
    if (!list.length) {
      return '<tr><td colspan="5" style="border:1px solid #d0d5dd;padding:6px 8px">Keine Daten vorhanden.</td></tr>';
    }

    return list.map((entry, index) => {
      const pos = Number.parseInt(String(entry?.pos ?? ''), 10) || index + 1;
      const artikel = String(entry?.artikel ?? '').trim() || '—';
      const menge = type === 'ist'
        ? ((entry?.menge_bestaetigt === true) ? String(entry.menge) : 'nicht bestätigt')
        : String(entry?.menge ?? '—');
      const preis = type === 'ist'
        ? ((entry?.preis_bestaetigt === true) ? euro(entry.preis) : 'nicht bestätigt')
        : euro(entry?.preis ?? 0);
      const kommentar = type === 'ist' ? String(entry?.kommentar ?? '').trim() || '—' : '—';

      return '<tr>'
        + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + esc(pos) + '</td>'
        + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + esc(artikel) + '</td>'
        + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + esc(menge) + '</td>'
        + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + esc(preis) + '</td>'
        + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + esc(kommentar) + '</td>'
        + '</tr>';
    }).join('');
  };

  const firstInput = items[0]?.json ?? {};

  const entries = items.map(({ json }) => {
    const abPos = Array.isArray(json?.ab?.positionen) ? json.ab.positionen : [];
    const bestPos = Array.isArray(json?.bestellung?.positionen) ? json.bestellung.positionen : [];
    const rawAbMail = String(json.auftragsbestaetigung_mail ?? '');
    const aiStatus = String(json.ab_ki_status ?? '').trim().toLowerCase();
    const aiReason = String(json.ab_ki_begruendung ?? '').trim();
    const aiScore = Number.isFinite(Number(json.automatik_score_prozent))
      ? Math.max(0, Math.min(100, Number(json.automatik_score_prozent)))
      : 0;
    const warnings = Array.isArray(json.automatik_warnhinweise)
      ? json.automatik_warnhinweise.map((entry) => String(entry ?? '').trim()).filter(Boolean)
      : [];

    const expectedByPos = new Map();
    for (const entry of bestPos) {
      const pos = Number.parseInt(String(entry.pos ?? ''), 10);
      if (!Number.isInteger(pos) || pos < 1) continue;
      expectedByPos.set(pos, {
        menge: toNum(entry.menge),
        preis: toNum(entry.preis),
        artikel: String(entry.artikel ?? '').trim(),
      });
    }

    const detectedByPos = new Map();
    const issues = [];

    if (!rawAbMail.trim()) {
      issues.push({
        pos: 0,
        typ: 'fehlende_mail',
        kategorie: 'abweichung',
        info: 'Keine Auftragsbestätigung übergeben.',
      });
    }

    const expectedSupplier = normalizeKey(json?.bestellung?.lieferant ?? json?.lieferant ?? '');
    const detectedSupplier = normalizeKey(json?.ab?.lieferant ?? '');
    if (expectedSupplier && detectedSupplier && detectedSupplier !== expectedSupplier && !detectedSupplier.includes(expectedSupplier) && !expectedSupplier.includes(detectedSupplier)) {
      issues.push({
        pos: 0,
        typ: 'lieferant_abweichend',
        kategorie: 'abweichung',
        info: 'erwartet ' + String(json?.bestellung?.lieferant ?? json?.lieferant ?? '') + ', erkannt ' + String(json?.ab?.lieferant ?? ''),
      });
    }

    for (const entry of abPos) {
      const pos = Number.parseInt(String(entry.pos ?? ''), 10);
      if (!Number.isInteger(pos) || pos < 1) {
        issues.push({
          pos: 0,
          typ: 'ungueltige_position',
          kategorie: 'unklar',
          info: 'Eine erkannte AB-Position hat keine gültige Positionsnummer.',
        });
        continue;
      }

      detectedByPos.set(pos, entry);
      const expected = expectedByPos.get(pos);
      if (!expected) {
        issues.push({
          pos,
          typ: 'zusatzposition',
          kategorie: 'abweichung',
          info: 'Position in Auftragsbestätigung, aber nicht in Bestellung.',
        });
        continue;
      }

      if (entry.menge_bestaetigt === true && round(entry.menge) !== round(expected.menge)) {
        issues.push({
          pos,
          typ: 'menge',
          kategorie: 'abweichung',
          erwartet: expected.menge,
          erhalten: toNum(entry.menge),
        });
      }

      if (entry.preis_bestaetigt === true && round(entry.preis) !== round(expected.preis)) {
        issues.push({
          pos,
          typ: 'preis',
          kategorie: 'abweichung',
          erwartet: expected.preis,
          erhalten: toNum(entry.preis),
        });
      }

      if (entry.preis_bestaetigt === true && !entry.preis_aus_stueckpreis && toNum(entry.preis) > 0 && !containsMoney(rawAbMail, entry.preis)) {
        issues.push({
          pos,
          typ: 'preis_quelle_unbelegt',
          kategorie: 'unklar',
          erwartet: expected.preis,
          erhalten: toNum(entry.preis),
          info: 'Der bestätigte Positionspreis ist nicht als Geldbetrag in der Auftragsbestätigung auffindbar. Bitte prüfen, ob die KI Sollwerte übernommen hat.',
        });
      }

      if (entry.artikel_bestaetigt === true && !articleMatches(expected.artikel, entry.artikel)) {
        issues.push({
          pos,
          typ: 'artikel',
          kategorie: 'abweichung',
          erwartet: expected.artikel,
          erhalten: String(entry.artikel ?? '').trim(),
        });
      }

      if (entry.menge_bestaetigt !== true) {
        issues.push({
          pos,
          typ: 'menge_unbestaetigt',
          kategorie: 'unklar',
          info: 'Menge wurde in der Auftragsbestätigung nicht belastbar bestätigt.',
        });
      }

      if (entry.preis_bestaetigt !== true) {
        issues.push({
          pos,
          typ: 'preis_unbestaetigt',
          kategorie: 'unklar',
          info: 'Preis wurde in der Auftragsbestätigung nicht belastbar bestätigt.',
        });
      }
    }

    for (const [pos] of expectedByPos.entries()) {
      if (!detectedByPos.has(pos)) {
        issues.push({
          pos,
          typ: 'fehlend',
          kategorie: 'abweichung',
          info: 'Position in Bestellung, aber nicht in der Auftragsbestätigung erkannt.',
        });
      }
    }

    if (aiStatus === 'abweichend' && aiReason) {
      issues.push({
        pos: 0,
        typ: 'ki_einschaetzung',
        kategorie: 'abweichung',
        info: aiReason,
      });
    }

    if (aiStatus === 'unklar') {
      issues.push({
        pos: 0,
        typ: 'ki_unklar',
        kategorie: 'unklar',
        info: aiReason || 'Die KI konnte die Auftragsbestätigung nicht sicher bewerten.',
      });
    }

    if (aiScore < 80) {
      issues.push({
        pos: 0,
        typ: 'vollstaendigkeit',
        kategorie: 'unklar',
        info: 'KI-Vollständigkeit nur ' + aiScore.toFixed(0) + ' %: ' + (String(json.automatik_score_begruendung ?? '').trim() || 'Begründung fehlt.'),
      });
    }

    for (const warning of warnings) {
      issues.push({
        pos: 0,
        typ: 'warnhinweis',
        kategorie: 'unklar',
        info: warning,
      });
    }

    const hasDeviation = issues.some((entry) => entry.kategorie === 'abweichung');
    const hasUnclear = issues.some((entry) => entry.kategorie === 'unklar');
    const status = hasDeviation ? 'abweichend' : (hasUnclear ? 'unklar' : 'korrekt');

    return {
      lieferant: String(json.lieferant ?? '').trim(),
      to_email: String(json.to_email ?? '').trim(),
      abStatus: status,
      ab_abweichungen: issues,
      automatik_score_prozent: aiScore,
      automatik_score_begruendung: String(json.automatik_score_begruendung ?? '').trim(),
      automatik_warnhinweise: warnings,
      bestellung: json.bestellung ?? {},
      ab: json.ab ?? {},
    };
  });

  const allCorrect = entries.length > 0 && entries.every((entry) => entry.abStatus === 'korrekt');
  const correctCount = entries.filter((entry) => entry.abStatus === 'korrekt').length;
  const deviationCount = entries.filter((entry) => entry.abStatus === 'abweichend').length;
  const unclearCount = entries.filter((entry) => entry.abStatus === 'unklar').length;
  const overallScore = entries.length ? Math.min(...entries.map((entry) => entry.automatik_score_prozent)) : 0;
  const reviewReasonLines = entries.map((entry) => {
    const reason = entry.automatik_score_begruendung || 'Keine explizite KI-Begründung vorhanden.';
    return entry.lieferant + ': ' + reason;
  });
  const reviewWarnings = Array.from(new Set(entries.flatMap((entry) => entry.automatik_warnhinweise.map((warning) => entry.lieferant + ': ' + warning))));
  const scoreColor = overallScore >= 90 ? '#027a48' : (overallScore >= 75 ? '#f79009' : '#b42318');
  const scoreBg = overallScore >= 90 ? '#ecfdf3' : (overallScore >= 75 ? '#fffaeb' : '#fef3f2');
  const statusColor = allCorrect ? '#027a48' : (deviationCount > 0 ? '#b42318' : '#f79009');
  const statusBg = allCorrect ? '#ecfdf3' : (deviationCount > 0 ? '#fef3f2' : '#fffaeb');
  const overallStatusLabel = allCorrect ? 'korrekt' : (deviationCount > 0 ? 'abweichend' : 'unklar');
  const abTone = (status) => status === 'korrekt'
    ? { bg: '#ecfdf3', color: '#027a48', label: 'Korrekt' }
    : status === 'unklar'
      ? { bg: '#fffaeb', color: '#b54708', label: 'Unklar' }
      : { bg: '#fef3f2', color: '#b42318', label: 'Abweichend' };

  let html = '';
  html += '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.45">';
  html += '<h2 style="margin:0 0 10px 0">AF15 – Auftragsbestätigung: Ergebnis</h2>';
  html += '<p style="margin:0 0 12px 0">Die KI hat pro Lieferant geprüft, ob die Auftragsbestätigung zur Bestellung passt und wie vollständig die Bestätigung ist.</p>';

  html += '<div style="display:flex;flex-wrap:wrap;gap:12px;margin:0 0 16px 0">';
  for (const card of [
    ['Lieferanten', String(entries.length)],
    ['Korrekt', String(correctCount)],
    ['Abweichend', String(deviationCount)],
    ['Unklar', String(unclearCount)],
  ]) {
    html += '<div style="min-width:180px;padding:12px;border:1px solid #d0d5dd;border-radius:10px;background:#f8fafc">';
    html += '<div style="font-size:12px;color:#475467;margin-bottom:4px">' + esc(card[0]) + '</div>';
    html += '<div style="font-size:20px;font-weight:700;color:#101828">' + esc(card[1]) + '</div>';
    html += '</div>';
  }
  html += '</div>';

  html += '<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px;margin:12px 0 16px">';
  html += '<div style="padding:12px;border:1px solid ' + scoreColor + ';border-radius:8px;background:' + scoreBg + ';font-size:13px">';
  html += '<p style="margin:0 0 8px 0"><b>Datenvollständigkeit</b> <span style="display:inline-block;margin-left:6px;padding:3px 8px;border-radius:999px;background:' + scoreColor + ';color:#fff">' + esc(overallScore.toFixed(0) + ' %') + '</span></p>';
  html += '<p style="margin:0;color:#344054">Der Wert zeigt, wie vollständig die Auftragsbestätigung gelesen wurde. 100 % bedeutet nicht automatisch, dass Bestellung und Bestätigung fachlich übereinstimmen.</p>';
  html += '</div>';
  html += '<div style="padding:12px;border:1px solid ' + statusColor + ';border-radius:8px;background:' + statusBg + ';font-size:13px">';
  html += '<p style="margin:0 0 8px 0"><b>Fachlicher Status:</b> ' + esc(overallStatusLabel) + '</p>';
  html += '<p style="margin:0">Korrekt: ' + esc(correctCount) + ' · Abweichend: ' + esc(deviationCount) + ' · Unklar: ' + esc(unclearCount) + '</p>';
  html += '</div>';
  html += '</div>';

  html += '<div style="margin:12px 0 16px;padding:12px;border:1px solid #d0d5dd;border-radius:8px;background:#ffffff;font-size:13px">';
  html += '<p style="margin:0 0 8px 0"><b>KI-Begründung je Lieferant:</b><br>' + reviewReasonLines.map((line) => esc(line)).join('<br>') + '</p>';
  html += reviewWarnings.length
    ? '<div style="margin-top:10px;padding:10px;border:1px solid #f79009;border-radius:8px;background:#fffaeb"><p style="margin:0 0 6px 0"><b>Warnhinweise:</b></p><ul style="margin:0 0 0 18px;padding:0">' + reviewWarnings.map((warning) => '<li>' + esc(warning) + '</li>').join('') + '</ul></div>'
    : '<p style="margin:0;color:#027a48"><b>Keine zusätzlichen Warnhinweise.</b></p>';
  html += '</div>';

  html += '<p style="margin:0 0 8px 0"><b>Gesamtstatus:</b> ' + esc(allCorrect ? 'korrekt' : 'Klärung erforderlich') + '</p>';
  html += '<p style="margin:0 0 12px 0;padding:10px;border:1px solid #d0d5dd;border-radius:8px;background:#f8fafc"><b>Bitte dokumentieren:</b> Bestätige im Formular, ob die Auftragsbestätigung korrekt ist, trotz Hinweis akzeptiert wird oder ob eine Klärung nötig ist. Die Entscheidung wird im Protokoll gespeichert.</p>';
  html += '<div style="overflow-x:auto">';
  html += '<table style="border-collapse:collapse;width:100%;font-size:13px">';
  html += '<thead><tr style="background:#f4f4f4">';
  html += '<th style="border:1px solid #ddd;padding:6px;text-align:left">Lieferant</th>';
  html += '<th style="border:1px solid #ddd;padding:6px;text-align:left">Status</th>';
  html += '<th style="border:1px solid #ddd;padding:6px;text-align:left">KI-Score</th>';
  html += '<th style="border:1px solid #ddd;padding:6px;text-align:left">KI-Begründung</th>';
  html += '<th style="border:1px solid #ddd;padding:6px;text-align:left">Details</th>';
  html += '</tr></thead><tbody>';

  for (const entry of entries) {
    const detail = entry.ab_abweichungen.length
      ? entry.ab_abweichungen.map((issue) => renderIssue(issue)).join('<br>')
      : 'Keine Abweichung';

    const tone = abTone(entry.abStatus);
    html += '<tr>'
      + '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(entry.lieferant || 'Unbekannt') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px;vertical-align:top"><span style="display:inline-block;padding:3px 8px;border-radius:999px;background:' + tone.bg + ';color:' + tone.color + ';font-weight:700">' + esc(tone.label) + '</span></td>'
      + '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(entry.automatik_score_prozent.toFixed(0) + ' %') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + esc(entry.automatik_score_begruendung || 'Keine KI-Begründung vorhanden.') + '</td>'
      + '<td style="border:1px solid #ddd;padding:6px;vertical-align:top">' + detail + '</td>'
      + '</tr>';
  }

  html += '</tbody></table>';
  html += '</div>';

  for (const entry of entries) {
    html += '<details style="margin:16px 0;padding:12px;border:1px solid #d0d5dd;border-radius:8px;background:#f8fafc">';
    html += '<summary><b>' + esc(entry.lieferant || 'Unbekannt') + '</b> – Soll/Ist-Vergleich anzeigen</summary>';
    html += '<div style="margin-top:10px">';
    html += '<p style="margin:0 0 8px 0"><b>Bestellung an:</b> ' + esc(entry.to_email || '—') + '</p>';
    html += '<div style="display:grid;grid-template-columns:1fr;gap:12px">';
    html += '<div>';
    html += '<p style="margin:0 0 6px 0"><b>Soll-Bestellung</b></p>';
    html += '<table style="border-collapse:collapse;width:100%;font-size:12px;background:#ffffff">';
    html += '<thead><tr><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Pos</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Artikel</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Menge</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Preis</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Kommentar</th></tr></thead>';
    html += '<tbody>' + renderPositionRows(entry.bestellung.positionen, 'soll') + '</tbody></table>';
    html += '</div>';
    html += '<div>';
    html += '<p style="margin:0 0 6px 0"><b>Erkannte Auftragsbestätigung</b></p>';
    html += '<table style="border-collapse:collapse;width:100%;font-size:12px;background:#ffffff">';
    html += '<thead><tr><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Pos</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Artikel</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Menge</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Preis</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Kommentar</th></tr></thead>';
    html += '<tbody>' + renderPositionRows(entry.ab.positionen, 'ist') + '</tbody></table>';
    html += '</div>';
    html += '</div>';
    html += '</div>';
    html += '</details>';
  }

  html += '</div>';

  const debugRunId = String(firstInput.debug_run_id ?? '').trim();
  const debugCacheFile = String(firstInput.debug_cache_file ?? '').trim();
  const protocolLines = [
    '# AF15 Protokoll – Auftragsbestätigung',
    '',
    'Zeitpunkt: ' + new Date().toISOString(),
    'Gesamtstatus vor User-Entscheidung: ' + (allCorrect ? 'korrekt' : 'Klärung erforderlich'),
    'Fachlicher Status: ' + overallStatusLabel,
    'KI-Prüfung automatische Vollständigkeit: ' + overallScore.toFixed(0) + ' %',
    'Hinweis: Die Vollständigkeit bewertet erkannte Datenfelder. Fachliche Abweichungen werden separat ausgewiesen.',
    'Abweichende Lieferanten: ' + deviationCount + ', unklare Lieferanten: ' + unclearCount,
    debugRunId ? 'Run-ID: ' + debugRunId : '',
    debugCacheFile ? 'Debug-Protokoll: ' + debugCacheFile : '',
    '',
    '## Lieferantenbewertung',
  ].filter(Boolean);
  for (const entry of entries) {
    protocolLines.push('', '### ' + (entry.lieferant || 'Unbekannter Lieferant'));
    protocolLines.push('- Status: ' + entry.abStatus);
    protocolLines.push('- KI-Score: ' + entry.automatik_score_prozent.toFixed(0) + ' %');
    protocolLines.push('- Begründung: ' + (entry.automatik_score_begruendung || 'Keine KI-Begründung vorhanden.'));
    const issues = entry.ab_abweichungen.length ? entry.ab_abweichungen.map(renderIssue) : ['Keine Abweichung'];
    protocolLines.push('- Details: ' + issues.join(' | '));
  }
  if (reviewWarnings.length) {
    protocolLines.push('', '## Warnhinweise', ...reviewWarnings.map((warning) => '- ' + warning));
  }

  const parseTrace = (value) => {
    if (Array.isArray(value)) return value;
    if (typeof value === 'string' && value.trim()) {
      try {
        const parsed = JSON.parse(value);
        return Array.isArray(parsed) ? parsed : [];
      } catch {}
    }
    return [];
  };

  const appendTrace = (trace, entry) => [
    ...parseTrace(trace),
    {
      timestamp: new Date().toISOString(),
      warnings: [],
      errors: [],
      ...entry,
    },
  ];

  const debugTrace = appendTrace(firstInput.debug_trace, {
    step: 'AF15 – Auftragsbestätigung prüfen',
    status: allCorrect ? 'ok' : (deviationCount > 0 ? 'warnung' : 'unklar'),
    summary: 'Auftragsbestätigungen wurden mit den versendeten Bestellungen verglichen. Vollständigkeit und fachliche Abweichungen werden getrennt bewertet.',
    input: {
      lieferanten: entries.length,
    },
    output: {
      fachlicher_status: overallStatusLabel,
      korrekt: correctCount,
      abweichend: deviationCount,
      unklar: unclearCount,
      daten_vollstaendigkeit_prozent: overallScore,
    },
    warnings: reviewWarnings,
  });

  return [{
    json: {
      debug_run_id: firstInput.debug_run_id,
      debug_started_at: firstInput.debug_started_at,
      debug_cache_file: firstInput.debug_cache_file,
      debug_trace: debugTrace,
      debug_file_write_ok: firstInput.debug_file_write_ok,
      debug_file_write_error: firstInput.debug_file_write_error,
      ab_gesamtstatus: allCorrect ? 'korrekt' : 'nicht korrekt',
      ab_lieferanten: entries,
      ab_mail_html: html,
      ab_protokoll_basis_markdown: protocolLines.join('\n'),
      automatik_score_prozent: overallScore,
      automatik_score_begruendung: reviewReasonLines.join(' | '),
      automatik_warnhinweise: reviewWarnings,
    },
  }];

const esc = (v = '') => String(v)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;');

  const looksLikeEmail = (value) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(value ?? '').trim());

  const parseAiJson = (value) => {
    const parseString = (raw) => {
      const cleaned = String(raw ?? '')
        .replace(/^\`\`\`json\s*/i, '')
        .replace(/^\`\`\`/i, '')
        .replace(/\`\`\`$/i, '')
        .trim();
      if (!cleaned) return {};
      try {
        return JSON.parse(cleaned);
      } catch {
        const objectStart = cleaned.indexOf('{');
        const objectEnd = cleaned.lastIndexOf('}');
        if (objectStart >= 0 && objectEnd > objectStart) {
          try {
            return JSON.parse(cleaned.slice(objectStart, objectEnd + 1));
          } catch {}
        }
        return {};
      }
    };

    if (!value) return {};
    if (typeof value === 'string') return parseString(value);
    if (typeof value === 'object') {
      for (const key of ['output', 'text', 'response', 'data']) {
        if (value[key] && typeof value[key] === 'object') return value[key];
        if (typeof value[key] === 'string') return parseString(value[key]);
      }
      return value;
    }
    return {};
  };

  const toNum = (v) => {
    const n = Number(String(v ?? '').replace(',', '.'));
    return Number.isFinite(n) ? n : 0;
  };

  const plural = (count, one, many) => (count === 1 ? one : many);

  const oneMaterialLine = (p) => {
    const menge = String(p?.Menge ?? '').trim();
    const artikel = String(p?.Artikelbezeichnung ?? '').trim();
    const werkstoff = String(p?.Werkstoff ?? '').trim();
    const norm = String(p?.Norm ?? '').trim();
    const pruef = String(p?.Pruefzeugnis ?? '').trim();
    const ober = String(p?.Oberflaecheneigenschaften ?? '').trim();
    const details = [
      menge ? menge + ' Stück' : null,
      artikel || null,
      werkstoff ? 'aus ' + werkstoff : null,
      norm ? '(Norm: ' + norm + ')' : null,
      pruef ? 'Prüfzeugnis: ' + pruef : null,
      ober ? 'Oberfläche: ' + ober : null,
    ].filter(Boolean);
    return details.join(', ');
  };

  const materialSentence = (p) => {
    const menge = String(p?.Menge ?? '').trim();
    const artikel = String(p?.Artikelbezeichnung ?? '').trim();
    const werkstoff = String(p?.Werkstoff ?? '').trim();
    const norm = String(p?.Norm ?? '').trim();
    const pruef = String(p?.Pruefzeugnis ?? '').trim();
    const ober = String(p?.Oberflaecheneigenschaften ?? '').trim();
    const details = [
      menge ? menge + ' Stück' : '',
      artikel,
      werkstoff ? 'aus ' + werkstoff : '',
      norm ? 'nach ' + norm : '',
