const form = ($json.data && typeof $json.data === 'object')
  ? $json.data
  : (($json && typeof $json === 'object') ? $json : {});

const sanitize = (value) => {
  if (value === undefined || value === null) return '';
  const raw = String(value).trim();
  if (/^\{\{[\s\S]*\}\}$/.test(raw)) return '';
  return raw;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const getField = (...aliases) => {
  for (const alias of aliases) {
    if (alias in form) {
      const value = sanitize(form[alias]);
      if (value !== '') return value;
    }
  }

  const normalizedAliases = new Set(aliases.map((a) => normalizeKey(a)));
  for (const [key, valueRaw] of Object.entries(form)) {
    if (normalizedAliases.has(normalizeKey(key))) {
      const value = sanitize(valueRaw);
      if (value !== '') return value;
    }
  }

  return '';
};

const looksLikeEmail = (v) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(String(v ?? '').trim());
const isAbortReason = (value) => /\\b(abbruch|abbrechen|stopp?|stop|cancel|verwerfen|beenden)\\b/i.test(String(value ?? '').trim());

const parsePayload = () => {
  const raw = getField('kp1b_payload');
  if (raw) {
    try {
      const parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) return parsed;
    } catch {
      // fallback below
    }
  }

  if (Array.isArray($json.kp1b_drafts)) return $json.kp1b_drafts;
  return [];
};

const entscheidung = getField('entscheidung', 'Entscheidung').toLowerCase();
const ablehnungsgrund = getField(
  'ablehnungsgrund',
  'Ablehnungsgrund',
  'Ablehnungsgrund / gewünschte Änderung (bei Ablehnung Pflicht)',
);
const kommentar = getField('kommentar_freitext', 'Kommentar', 'Zusätzlicher Kommentar (optional)');
const parseDebugTrace = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try { const parsed = JSON.parse(value); return Array.isArray(parsed) ? parsed : []; } catch {}
  }
  return [];
};
const debugCarry = {
  debug_run_id: getField('debug_run_id') || String($json.debug_run_id ?? ''),
  debug_started_at: getField('debug_started_at') || String($json.debug_started_at ?? ''),
  debug_cache_file: getField('debug_cache_file') || String($json.debug_cache_file ?? ''),
  debug_trace: parseDebugTrace(getField('debug_trace') || $json.debug_trace),
  debug_file_write_ok: String(getField('debug_file_write_ok') || $json.debug_file_write_ok || '').toLowerCase() === 'true',
  debug_file_write_error: getField('debug_file_write_error') || String($json.debug_file_write_error ?? ''),
};

if (!['freigeben', 'ablehnen'].includes(entscheidung)) {
  throw new Error("Ungültige Entscheidung. Erlaubt: 'freigeben' oder 'ablehnen'.");
}

const baseDrafts = parsePayload();
if (!baseDrafts.length) {
  throw new Error('Keine Entwurfsdaten für KP1b gefunden.');
}

const drafts = baseDrafts.map((rawDraft, i) => {
  const draft = rawDraft ?? {};
  const lieferant = String(draft.lieferant ?? '').trim() || `Lieferant ${i + 1}`;

  const sendFlag = getField(
    `senden_${i}`,
    `Anfrage an ${lieferant} senden?`,
  ).toLowerCase() || 'senden';

  const toEmail = getField(
    `to_email_${i}`,
    `Empfänger-Mail (${lieferant})`,
    `Empfaenger-Mail (${lieferant})`,
  ) || String(draft.to_email ?? '').trim();

  const subject = getField(
    `rfq_subject_${i}`,
    `Betreff (${lieferant})`,
  ) || String(draft.rfq_subject ?? '').trim();

  const body = getField(
    `rfq_body_${i}`,
    `Mailtext (${lieferant})`,
  ) || String(draft.rfq_body ?? '').trim();

  const updated = {
    ...draft,
    draft_id: String(draft.draft_id ?? `${i + 1}`),
    lieferant,
    to_email: toEmail,
    rfq_subject: subject,
    rfq_body: body,
    anfrage_positionen: Array.isArray(draft.anfrage_positionen) ? draft.anfrage_positionen : [],
    lieferpauschale_standard: draft.lieferpauschale_standard ?? 0,
    entladungskosten_standard: draft.entladungskosten_standard ?? 0,
    ...debugCarry,
    kp1_request_id: String(draft.kp1_request_id ?? '').trim(),
    kp1b_round: Number(draft.kp1b_round ?? 0) || 0,
    kp1b_send_flag: sendFlag === 'nicht_senden' ? 'nicht_senden' : 'senden',
  };

  if (updated.kp1b_send_flag === 'senden') {
    if (!updated.to_email || !looksLikeEmail(updated.to_email)) {
      throw new Error(`Ungültige Empfänger-Mail bei ${updated.lieferant}.`);
    }
    if (!updated.rfq_subject) {
      throw new Error(`Betreff fehlt bei ${updated.lieferant}.`);
    }
    if (!updated.rfq_body) {
      throw new Error(`Mailtext fehlt bei ${updated.lieferant}.`);
    }
  }

  return updated;
});

const selected = drafts.filter((d) => d.kp1b_send_flag === 'senden');

if (entscheidung === 'freigeben') {
  if (!selected.length) {
    throw new Error('Es ist keine Anfrage zum Senden markiert.');
  }

  return selected.map((d) => ({
    json: {
      ...debugCarry,
      ...d,
      kp1b_entscheidung: 'freigeben',
      kp1b_ablehnungsgrund: '',
      kp1b_kommentar: kommentar,
      kp1b_drafts: drafts,
    },
  }));
}

if (!ablehnungsgrund) {
  throw new Error('Bei Ablehnung bitte einen Ablehnungsgrund eingeben.');
}

const nextRound = drafts.reduce((max, d) => Math.max(max, Number(d.kp1b_round ?? 0) || 0), 0);
const ablehnungsaktion = isAbortReason(ablehnungsgrund) ? 'abbrechen' : 'erneut_bearbeiten';

return [{
  json: {
    kp1_request_id: String(drafts[0]?.kp1_request_id ?? '').trim(),
    kp1b_entscheidung: 'ablehnen',
    kp1b_ablehnungsgrund: ablehnungsgrund,
    kp1b_ablehnungsaktion: ablehnungsaktion,
    kp1b_kommentar: kommentar,
    kp1b_round: nextRound,
    kp1b_drafts: drafts,
  },
}];

const toNum = (v) => {
    const n = Number(String(v ?? '').replace(',', '.'));
    return Number.isFinite(n) ? n : 0;
  };

  const esc = (v = '') => String(v)
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;');

  const readNodeJson = (name) => {
    try {
      return $(name).all().map((i) => i.json ?? {});
    } catch {
      return [];
    }
  };

  const pickFirstText = (...values) => {
    for (const value of values) {
      const text = String(value ?? '').trim();
      if (text) return text;
    }
    return '';
  };

  const mergeRowsByIndex = (primaryRows, fallbackRows) => {
    const primary = Array.isArray(primaryRows) ? primaryRows : [];
    const fallback = Array.isArray(fallbackRows) ? fallbackRows : [];
    const size = Math.max(primary.length, fallback.length);
    if (!size) return [];

    return Array.from({ length: size }, (_, idx) => ({
      ...(fallback[idx] ?? {}),
      ...(primary[idx] ?? {}),
    }));
  };


const _debugShort = (value, limit = 1000) => {
  if (value === undefined || value === null) return value;
  if (typeof value === 'string') {
    const text = value.replace(/\s+/g, ' ').trim();
    return text.length > limit ? text.slice(0, limit) + ` ... (${text.length} Zeichen gesamt)` : text;
  }
  if (Array.isArray(value)) return value.slice(0, 20).map((entry) => _debugShort(entry, Math.max(200, Math.floor(limit / 4))));
  if (typeof value === 'object') {
    const out = {};
    for (const [key, entry] of Object.entries(value).slice(0, 40)) out[key] = _debugShort(entry, Math.max(200, Math.floor(limit / 4)));
    return out;
  }
  return value;
};
const _debugParseTrace = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try { const parsed = JSON.parse(value); return Array.isArray(parsed) ? parsed : []; } catch {}
  }
  return [];
};
const _debugEnv = (name) => {
  try { if (typeof $env !== 'undefined' && $env && $env[name]) return String($env[name]); } catch {}
  try { if (typeof process !== 'undefined' && process?.env?.[name]) return String(process.env[name]); } catch {}
  return '';
};
const _debugEnsure = (source = {}) => {
  const ts = new Date().toISOString().replace(/[:.]/g, '-');
  const random = Math.random().toString(36).slice(2, 8);
  const runId = String(source.debug_run_id ?? '').trim() || `run_${ts}_${random}`;
  const startedAt = String(source.debug_started_at ?? '').trim() || new Date().toISOString();
  const dir = String(source.debug_cache_dir ?? '').trim() || _debugEnv('N8N_DEBUG_DIR') || '/home/cedric/Downloads/n8n-debug-cache';
  const cacheFile = String(source.debug_cache_file ?? '').trim() || `${dir}/SollProzessv2_${runId}.md`;
  return { debug_run_id: runId, debug_started_at: startedAt, debug_cache_file: cacheFile, debug_trace: _debugParseTrace(source.debug_trace), debug_file_write_ok: source.debug_file_write_ok === true || String(source.debug_file_write_ok ?? '').toLowerCase() === 'true', debug_file_write_error: String(source.debug_file_write_error ?? '').trim() };
};
const _debugAdd = (ctx, entry) => {
  ctx.debug_trace = Array.isArray(ctx.debug_trace) ? ctx.debug_trace : [];
  ctx.debug_trace.push({ timestamp: new Date().toISOString(), step: String(entry.step ?? 'Unbenannter Schritt'), status: String(entry.status ?? 'ok'), summary: String(entry.summary ?? ''), decision: _debugShort(entry.decision ?? {}, 1000), input: _debugShort(entry.input ?? {}, 1000), output: _debugShort(entry.output ?? {}, 1000), warnings: Array.isArray(entry.warnings) ? entry.warnings.map(String) : [], errors: Array.isArray(entry.errors) ? entry.errors.map(String) : [] });
  return ctx;
};
const _debugMarkdown = (ctx) => {
  const lines = ['# Debug-Protokoll SollProzessv2', '', `Run ID: ${ctx.debug_run_id}`, `Start: ${ctx.debug_started_at}`, `Datei: ${ctx.debug_cache_file}`, ''];
  const trace = Array.isArray(ctx.debug_trace) ? ctx.debug_trace : [];
  trace.forEach((entry, index) => {
    lines.push(`## ${index + 1}. ${entry.step || 'Schritt'}`, `Status: ${entry.status || 'ok'}`);
    if (entry.timestamp) lines.push(`Zeitpunkt: ${entry.timestamp}`);
    if (entry.summary) lines.push('', entry.summary);
    if (entry.decision && Object.keys(entry.decision).length) lines.push('', 'Entscheidung:', '```json', JSON.stringify(entry.decision, null, 2), '```');
    if (entry.input && Object.keys(entry.input).length) lines.push('', 'Wichtige Eingangsdaten:', '```json', JSON.stringify(entry.input, null, 2), '```');
    if (entry.output && Object.keys(entry.output).length) lines.push('', 'Wichtige Ausgangsdaten:', '```json', JSON.stringify(entry.output, null, 2), '```');
    if (entry.warnings?.length) lines.push('', 'Warnungen:', ...entry.warnings.map((warning) => `- ${warning}`));
    if (entry.errors?.length) lines.push('', 'Fehler:', ...entry.errors.map((error) => `- ${error}`));
    lines.push('');
  });
  if (ctx.debug_file_write_error) lines.push('## Debug-Dateischreibung', '', `Warnung: ${ctx.debug_file_write_error}`, '');
  return lines.join('\n');
};
const _debugWrite = (ctx) => {
  const allowBuiltins = _debugEnv('NODE_FUNCTION_ALLOW_BUILTIN').split(',').map((entry) => entry.trim().toLowerCase());
  const fsExplicitlyAllowed = allowBuiltins.includes('fs') && allowBuiltins.includes('path');
  const debugFsEnabled = /^true$/i.test(_debugEnv('N8N_ALLOW_CODE_FS_DEBUG'));
  if (!fsExplicitlyAllowed && !debugFsEnabled) {
    ctx.debug_file_write_ok = false;
    ctx.debug_file_write_error = 'Debug-Datei wurde nicht geschrieben, weil n8n Code-Nodes fs/path nicht freigegeben haben. debug_trace wird vollständig im Workflow weitergeführt. Für echte Dateien n8n mit NODE_FUNCTION_ALLOW_BUILTIN=fs,path neu starten oder einen Read/Write-Files-Node ergänzen.';
    return ctx;
  }
  try {
    const fs = require('fs');
    const path = require('path');
    fs.mkdirSync(path.dirname(ctx.debug_cache_file), { recursive: true });
    fs.writeFileSync(ctx.debug_cache_file, _debugMarkdown(ctx), 'utf8');
    ctx.debug_file_write_ok = true;
    ctx.debug_file_write_error = '';
  } catch (error) {
    ctx.debug_file_write_ok = false;
    ctx.debug_file_write_error = `Debug-Datei konnte nicht geschrieben werden: ${error?.message || error}`;
  }
  return ctx;
};
const _debugFields = (ctx) => ({ debug_run_id: ctx.debug_run_id, debug_started_at: ctx.debug_started_at, debug_cache_file: ctx.debug_cache_file, debug_trace: ctx.debug_trace, debug_file_write_ok: ctx.debug_file_write_ok, debug_file_write_error: ctx.debug_file_write_error });
const _debugHiddenFields = (ctx) => Object.entries(_debugFields(ctx)).map(([fieldName, fieldValue]) => ({ fieldName, fieldType: 'hiddenField', fieldValue: typeof fieldValue === 'string' ? fieldValue : JSON.stringify(fieldValue) }));

  const currentRows = items.map((item) => item.json ?? {});
  const upstreamRows = readNodeJson('AF7 – Anfrage-Freigabe verarbeiten');
  const overviewRow = readNodeJson('KP1 – Übersicht vorbereiten')[0] ?? {};
  const requestRows = mergeRowsByIndex(currentRows, upstreamRows);
  const _debugContext = _debugEnsure(upstreamRows[0] ?? currentRows[0] ?? overviewRow ?? {});

  const requests = requestRows.map((row, idx) => ({
    lieferant: String(row.lieferant ?? row.lieferantenname ?? row.firma ?? '').trim(),
    to_email: String(row.to_email ?? row.empfaenger_email ?? row.email ?? '').trim(),
    rfq_id: String(row.rfq_id ?? '').trim(),
    rfq_intern_id: String(row.rfq_intern_id ?? row.rfq_id ?? row.draft_id ?? `RFQ-UNKLAR-${idx + 1}`).trim(),
    rfq_subject: String(row.rfq_subject ?? '').trim(),
    rfq_body: String(row.rfq_body ?? '').trim(),
    lieferpauschale_standard: toNum(row.lieferpauschale_standard ?? 0),
    entladungskosten_standard: toNum(row.entladungskosten_standard ?? 0),
    anfrage_positionen: Array.isArray(row.anfrage_positionen) ? row.anfrage_positionen : [],
    kp1_request_id: pickFirstText(row.kp1_request_id, upstreamRows[idx]?.kp1_request_id, overviewRow.kp1_request_id),
    kp1b_round: Number(row.kp1b_round ?? 0) || 0,
  }));

  if (!requests.length) {
    throw new Error('Keine gesendeten Lieferantenanfragen gefunden.');
  }

  let basisPositionen = [];
  try {
    basisPositionen = $('KP1 – Entscheidung verarbeiten').all().map((i) => i.json ?? {});
  } catch {
    basisPositionen = [];
  }

  const posSet = new Set(
    basisPositionen
      .map((p) => Number.parseInt(String(p.pos ?? ''), 10))
      .filter((n) => Number.isInteger(n) && n > 0),
  );

  const template = [];
  for (const req of requests) {
    for (const p of req.anfrage_positionen) {
      const pos = Number.parseInt(String(p.pos ?? ''), 10);
      if (!Number.isInteger(pos) || pos < 1) continue;

      if (!posSet.size || posSet.has(pos)) {
        template.push({
          rfq_intern_id: req.rfq_intern_id,
          rfq_id: req.rfq_id,
          pos,
          lieferant: req.lieferant,
          to_email: req.to_email,
          antwort_status: 'angebot',
          stueckpreis: '',
          lieferkosten: req.lieferpauschale_standard || '',
          entladungspauschale: req.entladungskosten_standard || '',
          zusatzkosten: '',
          lieferzeit_tage: '',
          alternativ_material: '',
          antwort_datum: '',
          kommentar: '',
        });
      }
    }
  }

  template.sort((a, b) => (Number(a.pos) - Number(b.pos)) || String(a.lieferant).localeCompare(String(b.lieferant), 'de'));

  const now = new Date();
  const deadline = new Date(now.getTime() + 6 * 24 * 60 * 60 * 1000);
  const deadlineIso = deadline.toISOString();
  const deadlineShort = deadline.toISOString().slice(0, 10);

  const anfragenRows = requests.map((req, idx) => {
    const posText = req.anfrage_positionen.map((p) => p.pos).join(', ');
    const displayLabel = (() => {
      const supplier = String(req.lieferant ?? '').trim();
      const email = String(req.to_email ?? '').trim();
      const rfq = String(req.rfq_intern_id ?? req.rfq_id ?? '').trim();
      const base = supplier || email || `Anfrage ${idx + 1}`;
      return rfq ? `${base} (${rfq})` : base;
    })();
    return `<tr>
      <td style="border:1px solid #d0d5dd;padding:6px 8px">${esc(displayLabel)}</td>
      <td style="border:1px solid #d0d5dd;padding:6px 8px">${esc(req.lieferant || 'nicht bekannt')}</td>
      <td style="border:1px solid #d0d5dd;padding:6px 8px">${esc(req.to_email || 'ohne E-Mail')}</td>
      <td style="border:1px solid #d0d5dd;padding:6px 8px">${esc(req.rfq_intern_id || req.rfq_id || `RFQ-UNKLAR-${idx + 1}`)}</td>
      <td style="border:1px solid #d0d5dd;padding:6px 8px">${esc(posText || '—')}</td>
    </tr>`;
  }).join('');

  let html = '';
  html += '<div style="font-family:Arial,sans-serif;color:#1f2937">';
  html += '<h2>AF7 – Lieferantenantworten erfassen</h2>';
  html += '<p><b>Weg 1 (Pflicht):</b> Vollständige Antwortmail je Lieferant in das passende Feld einfügen. Parser erkennt Status, Preis, Lieferzeit und Alternativen.</p>';
  html += '<p><b>Weg 2:</b> Direkt strukturiertes <code>angebote_json</code> eintragen.</p>';
  html += '<p><b>KI-Hinweis:</b> Falls Rückfragen auftreten oder du eine besondere Auslegung wünschst, kannst du unten im Feld <code>Anweisung an KI</code> zusätzliche Hinweise geben.</p>';
  html += '<p><b>Empfohlene Frist (4 Werktage):</b> ' + esc(deadlineShort) + '</p>';
  html += '<p><b>Interne RFQ-IDs (nur intern, nicht an Lieferanten gesendet):</b></p>';
  html += '<div style="overflow-x:auto"><table style="border-collapse:collapse;width:100%;font-size:12px">';
  html += '<thead><tr><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Anzeige</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Lieferant</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">E-Mail</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">RFQ intern</th><th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Positionen</th></tr></thead>';
  html += '<tbody>' + anfragenRows + '</tbody></table></div>';
  html += '<p style="font-size:12px;color:#475467">Sobald neue Antworten eingehen, kannst du die vollständigen Mails hier erneut ergänzen.</p>';
  html += '<p style="font-size:12px;color:#475467"><b>Debug-Protokoll:</b> ' + esc(_debugContext.debug_cache_file) + '<br><b>Run-ID:</b> ' + esc(_debugContext.debug_run_id) + '</p>';
  html += '</div>';

  const fields = [];
  fields.push({ fieldType: 'html', elementName: 'kp1c_intro', html });
  fields.push({
    fieldName: 'angebote_json',
    fieldLabel: 'Angebote JSON (optional, strukturiert)',
    fieldType: 'textarea',
    defaultValue: '[]',
    placeholder: 'Optional: Nur ausfüllen, wenn du Angebote bereits strukturiert als JSON erfassen willst.',
  });

  for (let idx = 0; idx < requests.length; idx++) {
    const req = requests[idx];
    const posText = req.anfrage_positionen.map((p) => p.pos).join(', ');
    const displayLabel = (() => {
      const supplier = String(req.lieferant ?? '').trim();
      const email = String(req.to_email ?? '').trim();
      const rfq = String(req.rfq_intern_id ?? req.rfq_id ?? '').trim();
      const base = supplier || email || `Anfrage ${idx + 1}`;
      return rfq ? `${base} (${rfq})` : base;
    })();
    fields.push({
      fieldType: 'html',
      elementName: `mail_header_${idx}`,
      html: `<div style="margin-top:14px;padding:10px;border:1px solid #d0d5dd;border-radius:6px;background:#f8fafc">
        <p style="margin:0 0 4px 0"><b>Anzeige:</b> ${esc(displayLabel)}</p>
        <p style="margin:0 0 4px 0"><b>Lieferant:</b> ${esc(req.lieferant || 'nicht bekannt')}</p>
        <p style="margin:0 0 4px 0"><b>E-Mail:</b> ${esc(req.to_email || 'ohne E-Mail')}</p>
        <p style="margin:0 0 4px 0"><b>Interne RFQ-ID:</b> ${esc(req.rfq_intern_id || req.rfq_id || `RFQ-UNKLAR-${idx + 1}`)}</p>
        <p style="margin:0"><b>Positionen:</b> ${esc(posText || '—')}</p>
      </div>`,
    });
    fields.push({
      fieldName: `lieferantenmail_${idx}`,
      fieldLabel: `Vollständige Antwortmail (Pflicht, ${displayLabel})`,
      fieldType: 'textarea',
      requiredField: true,
      placeholder: 'Hier komplette Lieferanten-Mail einfügen (inkl. Preis/Verfügbarkeit/Lieferzeit).',
    });
  }

  fields.push({
    fieldName: 'lieferantenantworten_rohtext',
    fieldLabel: 'Zusätzlicher Rohtext (optional, mehrere Blöcke mit --- trennen)',
    fieldType: 'textarea',
  });
  fields.push({
    fieldName: 'kommentar_freitext',
    fieldLabel: 'Kommentar / Hinweis',
    fieldType: 'textarea',
  });
  fields.push({
    fieldName: 'ki_anweisung',
    fieldLabel: 'Anweisung an KI (optional)',
    fieldType: 'textarea',
    placeholder: 'Optional: Zusätzliche Hinweise für die KI, z. B. wie unklare Antworten interpretiert oder priorisiert werden sollen.',
  });
  fields.push(..._debugHiddenFields(_debugContext));
  fields.push({ fieldName: 'af7_klaerung_round', fieldType: 'hiddenField', fieldValue: '0' });
  fields.push({ fieldName: 'af7_max_klaerung_rounds', fieldType: 'hiddenField', fieldValue: '2' });
  fields.push({
    fieldName: 'kp1c_requests_payload',
    fieldType: 'hiddenField',
    fieldValue: JSON.stringify(requests),
  });

  fields.push({
    fieldName: 'antworten_deadline',
    fieldType: 'hiddenField',
    fieldValue: deadlineShort,
  });

  fields.push({
    fieldName: 'antworten_deadline_iso',
    fieldType: 'hiddenField',
    fieldValue: deadlineIso,
  });

  fields.push({
    fieldName: 'antworten_mail_html',
    fieldType: 'hiddenField',
    fieldValue: html,
  });

  _debugAdd(_debugContext, { step: 'AF7b – Antwortsammlung vorbereiten', status: 'ok', summary: 'AF7 Antwortformular vorbereitet.', input: { requests: requests.length, basis_positionen: basisPositionen.length }, output: { antworten_deadline: deadlineShort, template_positionen: template.length } });
  _debugWrite(_debugContext);

  return [{
    json: {
      ..._debugFields(_debugContext),
      af7_klaerung_round: 0,
      af7_max_klaerung_rounds: 2,
      kp1_request_id: pickFirstText(requests[0]?.kp1_request_id, overviewRow.kp1_request_id),
      anfragen_gesendet: requests,
      antworten_deadline_iso: deadlineIso,
      antworten_deadline: deadlineShort,
      antworten_json_vorlage: JSON.stringify(template, null, 2),
      antworten_mail_html: html,
      kp1c_form_fields: JSON.stringify(fields),
      kp1c_requests_payload: JSON.stringify(requests),
    },
  }];

