const parseAiJson = (value) => {
    const parseString = (raw) => {
      const cleaned = String(raw ?? '')
        .replace(/^\`\`\`json\s*/i, '')
        .replace(/^\`\`\`/i, '')
        .replace(/\`\`\`$/i, '')
        .trim();
      if (!cleaned) return {};
      try {
        return JSON.parse(cleaned);
      } catch {
        const objectStart = cleaned.indexOf('{');
        const objectEnd = cleaned.lastIndexOf('}');
        if (objectStart >= 0 && objectEnd > objectStart) {
          try {
            return JSON.parse(cleaned.slice(objectStart, objectEnd + 1));
          } catch {}
        }
        return {};
      }
    };

    if (!value) return {};
    if (typeof value === 'string') return parseString(value);
    if (typeof value === 'object') {
      for (const key of ['output', 'text', 'response', 'data']) {
        if (value[key] && typeof value[key] === 'object') return value[key];
        if (typeof value[key] === 'string') return parseString(value[key]);
      }
      return value;
    }
    return {};
  };

  const base = (() => {
    try {
      return $('AF3a – KP1 KI-Input vorbereiten').first().json ?? {};
    } catch {
      return {};
    }
  })();

  const rows = Array.isArray(base.rows) ? base.rows : [];
  if (!rows.length) {
    throw new Error('Keine vorbereiteten KP1-Daten zum Anwenden der KI-Ergebnisse gefunden.');
  }

  const reason = String(base.kp1_ablehnungsgrund ?? '').trim();
  const hint = String(base.kp1_aenderungshinweis ?? '').trim();
  const parsed = parseAiJson($json);
  const changes = Array.isArray(parsed?.aenderungen) ? parsed.aenderungen : [];
  const byPos = new Map();

  for (const change of changes) {
    const pos = Number.parseInt(String(change?.pos ?? ''), 10);
    if (!Number.isInteger(pos) || pos < 1) continue;
    byPos.set(pos, change);
  }

  return rows.map((row) => {
    const pos = Number.parseInt(String(row.pos ?? ''), 10);
    const change = byPos.get(pos);
    const result = {
      ...row,
      kp1_ki_rework: true,
      kp1_ki_rework_reason: reason,
      kp1_ki_rework_hint: hint,
      kp1_ki_rework_model: 'ollama-node',
      kp1_ki_rework_error: '',
      kp1_ki_globaler_hinweis: String(parsed?.globaler_hinweis ?? '').trim(),
      kp1_ki_begruendung: String(change?.begruendung ?? '').trim(),
    };

    if (!change) {
      return { json: result };
    }

    const textUpdate = (targetKey, value) => {
      const normalized = String(value ?? '').trim();
      if (normalized) result[targetKey] = normalized;
    };

    textUpdate('Artikelbezeichnung', change.artikel);
    if (change.menge !== undefined && String(change.menge).trim() !== '') result.Menge = change.menge;
    textUpdate('Werkstoff', change.werkstoff);
    textUpdate('Norm', change.norm);
    textUpdate('Pruefzeugnis', change.pruefzeugnis);
    textUpdate('Oberflaecheneigenschaften', change.oberflaeche);

    const status = String(change.status ?? '').trim();
    if (status === 'ok' || status === 'offen/prüfpflichtig') result.status = status;

    const bevorzugte = Array.isArray(change.bevorzugte_lieferanten)
      ? change.bevorzugte_lieferanten.map((entry) => String(entry ?? '').trim()).filter(Boolean)
      : [];

    if (bevorzugte.length) {
      const oldInfos = Array.isArray(row.lieferantenInfos) ? row.lieferantenInfos : [];
      const infoByName = new Map(oldInfos.map((li) => [String(li?.Lieferant ?? '').trim().toLowerCase(), li]));
      const nextInfos = [];

      for (const name of bevorzugte) {
        const hit = infoByName.get(name.toLowerCase());
        if (hit) {
          nextInfos.push({ ...hit, Lieferant: String(hit.Lieferant ?? name).trim() });
        } else {
          nextInfos.push({
            Lieferant: name,
            Sortimentsbreite: '',
            Lieferpauschale: 0,
            Entladungskosten: 0,
          });
        }
      }

      result.lieferantenInfos = nextInfos;
      result.moeglicheLieferanten = nextInfos.map((li) => String(li.Lieferant ?? '').trim()).filter(Boolean);
      result.zuordnungStatus = result.moeglicheLieferanten.length ? 'zugeordnet' : 'kein passender Lieferant';
      if (!result.moeglicheLieferanten.length) result.status = 'offen/prüfpflichtig';
    }

    return { json: result };
  });

