const toNum = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return 0;
  let normalized = raw.replace(/[^0-9,.-]/g, '');
  if (!normalized || normalized === '-' || normalized === ',' || normalized === '.') return 0;
  if (normalized.includes(',') && normalized.includes('.')) {
    if (normalized.lastIndexOf(',') > normalized.lastIndexOf('.')) {
      normalized = normalized.replace(/\./g, '').replace(',', '.');
    } else {
      normalized = normalized.replace(/,/g, '');
    }
  } else if (normalized.includes(',')) {
    normalized = normalized.replace(',', '.');
  }
  const n = Number(normalized);
  return Number.isFinite(n) ? n : 0;
};

const parseIntSafe = (value) => {
  const n = Number.parseInt(String(value ?? '').replace(',', '.').trim(), 10);
  return Number.isFinite(n) ? n : 0;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const normalizeRfq = (value) => String(value ?? '')
  .toUpperCase()
  .replace(/\s+/g, '')
  .replace(/[^A-Z0-9_-]/g, '');

const pickFirstText = (...values) => {
  for (const value of values) {
    const text = String(value ?? '').trim();
    if (text) return text;
  }
  return '';
};

const sanitize = (value) => {
  const raw = String(value ?? '').trim();
  if (/^\{\{[\s\S]*\}\}$/.test(raw)) return '';
  return raw;
};

const getFieldFactory = (form) => (...aliases) => {
  for (const alias of aliases) {
    if (alias in form) {
      const value = sanitize(form[alias]);
      if (value) return value;
    }
  }

  const wanted = aliases.map((alias) => normalizeKey(alias));
  for (const [key, raw] of Object.entries(form)) {
    const keyNorm = normalizeKey(key);
    if (wanted.includes(keyNorm) || wanted.some((alias) => keyNorm.includes(alias))) {
      const value = sanitize(raw);
      if (value) return value;
    }
  }

  return '';
};

const parseJsonArray = (raw) => {
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    if (Array.isArray(parsed)) return parsed;
    if (parsed && typeof parsed === 'object') return [parsed];
  } catch {}
  return [];
};

const readNodeRows = (name) => {
  try {
    return $(name).all().map((item) => item.json ?? {});
  } catch {
    return [];
  }
};

const readFirstNode = (name) => {
  try {
    return $(name).first().json ?? {};
  } catch {
    return {};
  }
};

const escapeRegex = (value) => String(value ?? '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const extractMoneyCandidates = (text) => {
  const raw = String(text ?? '');
  const matches = [];
  const patterns = [
    /(^|[^0-9])(\d{1,3}(?:\.\d{3})*(?:,\d{2})|\d+(?:,\d{2})|\d+\.\d{2})(?=\s*(?:€|eur|euro)\b)/gi,
    /(^|[^0-9.])(\d{1,3}(?:\.\d{3})*(?:,\d{2})|\d+(?:,\d{2})|\d+\.\d{2})(?!\d)/g,
  ];

  for (const pattern of patterns) {
    for (const match of raw.matchAll(pattern)) {
      const value = toNum(match[2]);
      if (!value) continue;
      const prefixLength = String(match[1] ?? '').length;
      const index = (Number.isInteger(match.index) ? match.index : 0) + prefixLength;
      if (matches.some((entry) => entry.index === index && Math.abs(entry.value - value) < 0.001)) continue;
      matches.push({ value, index, raw: match[2] });
    }
  }

  return matches.sort((left, right) => left.index - right.index);
};

const parsePriceFromText = (text, labels) => {
  const lines = String(text ?? '').split(/\r?\n/);
  const normalizedLabels = labels.map((label) => ({
    escaped: escapeRegex(label),
    normalized: normalizeKey(label),
  }));

  for (const line of lines) {
    const lineNorm = normalizeKey(line);
    for (const label of normalizedLabels) {
      if (!lineNorm.includes(label.normalized)) continue;

      const candidates = extractMoneyCandidates(line);
      if (candidates.length) return candidates[candidates.length - 1].value;

      const inlineMatch = line.match(new RegExp(`${label.escaped}[^\\d\\n]{0,80}(\\d+(?:[.,]\\d{2})?)`, 'i'));
      if (inlineMatch?.[1]) return toNum(inlineMatch[1]);
    }
  }

  for (const label of normalizedLabels) {
    const match = String(text ?? '').match(new RegExp(`${label.escaped}[\\s\\S]{0,120}?(\\d{1,3}(?:\\.\\d{3})*(?:,\\d{2})|\\d+(?:[.,]\\d{2})|\\d+)(?=\\s*(?:€|eur|euro)?\\b)`, 'i'));
    if (match?.[1]) {
      const value = toNum(match[1]);
      if (value) return value;
    }
  }

  return 0;
};

const pickUnitPriceFromLine = (line, quantity) => {
  const candidates = extractMoneyCandidates(line).map((entry) => entry.value).filter((value) => value > 0);
  if (!candidates.length) return 0;

  if (candidates.length >= 2 && quantity > 0) {
    const [first, second] = candidates;
    const delta = Math.abs(first * quantity - second);
    if (delta <= Math.max(0.5, second * 0.03)) return first;
  }

  return candidates[0];
};

const parseLooseOfferRows = (text, request) => {
  const requested = Array.isArray(request.anfrage_positionen) ? request.anfrage_positionen : [];
  if (!requested.length) return [];

  const available = [];
  for (const rawLine of String(text ?? '').split(/\r?\n/)) {
    const line = String(rawLine ?? '').trim();
    if (!line) continue;

    const prices = extractMoneyCandidates(line);
    if (!prices.length) continue;

    const rowPosMatch = line.match(/^\s*(?:pos\.?\s*)?(\d+)\b/i);
    available.push({
      row_pos: rowPosMatch ? parseIntSafe(rowPosMatch[1]) : 0,
      description: line,
      description_normalized: normalizeKey(line),
      price_candidates: prices.map((entry) => entry.value),
    });
  }

  if (!available.length) return [];

  const pool = available.map((row) => ({ ...row }));
  const mapped = [];
  const takeRow = (rowIndex, position) => {
    if (rowIndex < 0) return;
    const [row] = pool.splice(rowIndex, 1);
    if (!row) return;
    mapped.push({
      position,
      row: {
        row_pos: row.row_pos,
        description: row.description,
        stueckpreis: pickUnitPriceFromLine(row.description, toNum(position.Menge ?? position.menge)),
      },
    });
  };

  for (const position of requested) {
    const pos = parseIntSafe(position.pos);
    if (!pos) continue;
    const directIndex = pool.findIndex((row) => row.row_pos === pos);
    if (directIndex >= 0) takeRow(directIndex, position);
  }

  for (const position of requested) {
    const pos = parseIntSafe(position.pos);
    if (!pos || mapped.some((entry) => parseIntSafe(entry.position?.pos) === pos)) continue;

    const tokens = [
      position.Artikelbezeichnung,
      position.artikel,
      position.Werkstoff,
      position.werkstoff,
      position.Norm,
      position.norm,
    ].map((value) => normalizeKey(value)).filter((value) => value.length >= 3);

    let rowIndex = pool.findIndex((row) => tokens.some((token) => row.description_normalized.includes(token)));
    if (rowIndex < 0 && requested.length === 1 && pool.length === 1) rowIndex = 0;
    if (rowIndex < 0) rowIndex = pool.findIndex((row) => row.price_candidates.length >= 2);
    if (rowIndex < 0 && pool.length === 1) rowIndex = 0;
    takeRow(rowIndex, position);
  }

  return mapped.filter((entry) => toNum(entry.row?.stueckpreis) > 0);
};

const parseLieferzeit = (text) => {
  const raw = String(text ?? '').toLowerCase();
  const rangeDays = raw.match(/(\d{1,3})\s*[–-]\s*(\d{1,3})\s*(werk)?tage?/);
  if (rangeDays) return parseIntSafe(rangeDays[2]);
  const weeks = raw.match(/(\d{1,3})\s*wochen?/);
  if (weeks) return parseIntSafe(weeks[1]) * 5;
  const days = raw.match(/(\d{1,3})\s*(werk)?tage?/);
  if (days) return parseIntSafe(days[1]);
  return 0;
};

const detectStatus = (text) => {
  const raw = String(text ?? '').toLowerCase();
  if (/nicht\s+auf\s+lager|nicht\s+verfuegbar|nicht\s+verfügbar|ausverkauft/.test(raw)) return 'nicht_verfuegbar';
  if (/\balternative\b|\balternativ\b|\bersatz\b|abweichendes?\s+material/.test(raw)) return 'alternative';
  if (/teilmenge|teil\s*lieferung/.test(raw)) return 'teilmenge';
  if (/lange\s+lieferzeit|wochen/.test(raw)) return 'lange_wartezeit';
  if (/angebot|preis|stueckpreis|stückpreis|gesamt\s+netto/.test(raw)) return 'angebot';
  return 'unklar';
};

const normalizeStatus = (statusRaw, stueckpreis, fallbackText = '') => {
  const statusNorm = normalizeKey(statusRaw).replace(/\s+/g, '_');
  const map = {
    angebot: 'angebot',
    alternative: 'alternative',
    alternativ: 'alternative',
    nicht_verfuegbar: 'nicht_verfuegbar',
    nicht_verfugbar: 'nicht_verfuegbar',
    teilmenge: 'teilmenge',
    lange_wartezeit: 'lange_wartezeit',
    lange_lieferzeit: 'lange_wartezeit',
    unklar: 'unklar',
  };
  if (map[statusNorm]) return map[statusNorm];
  if (stueckpreis > 0) return 'angebot';
  return detectStatus(fallbackText);
};

const splitTableRow = (line) => String(line ?? '')
  .trim()
  .replace(/^\|/, '')
  .replace(/\|$/, '')
  .split('|')
  .map((cell) => cell.trim());

const parseMarkdownOfferRows = (text) => {
  const lines = String(text ?? '').split(/\r?\n/);
  const tables = [];

  for (let index = 0; index < lines.length - 1; index += 1) {
    const line = lines[index].trim();
    const next = lines[index + 1].trim();
    if (!/^\|.*\|$/.test(line) || !/^\|?[\s:|\-]+\|?$/.test(next)) continue;

    const header = splitTableRow(line);
    const rows = [];
    index += 2;
    while (index < lines.length && /^\|.*\|$/.test(lines[index].trim())) {
      rows.push(splitTableRow(lines[index].trim()));
      index += 1;
    }
    index -= 1;
    tables.push({ header, rows });
  }

  const parsedRows = [];
  for (const table of tables) {
    const headers = table.header.map((cell) => normalizeKey(cell));
    const descIdx = headers.findIndex((cell) => cell.includes('beschreibung') || cell.includes('artikel') || cell.includes('material') || cell.includes('produkt') || cell.includes('bezeichnung'));
    const priceIdx = headers.findIndex((cell) => cell.includes('einzelpreis'));
    const posIdx = headers.findIndex((cell) => cell === 'pos' || cell === 'pos.' || cell.includes('position'));
    if (descIdx < 0 || priceIdx < 0) continue;

    for (const cells of table.rows) {
      parsedRows.push({
        row_pos: posIdx >= 0 ? parseIntSafe(cells[posIdx]) : 0,
        description: String(cells[descIdx] ?? '').trim(),
        stueckpreis: toNum(cells[priceIdx]),
      });
    }
  }

  return parsedRows.filter((row) => row.description || row.stueckpreis > 0);
};

const mapTableRowsToRequestPositions = (tableRows, request) => {
  const requested = Array.isArray(request.anfrage_positionen) ? request.anfrage_positionen : [];
  if (!requested.length || !tableRows.length) return [];

  const available = tableRows.map((row) => ({
    ...row,
    row_pos: parseIntSafe(row.row_pos),
    description_normalized: normalizeKey(row.description),
  }));

  const mapped = [];
  const takeRow = (rowIndex, position) => {
    if (rowIndex < 0) return;
    const [row] = available.splice(rowIndex, 1);
    if (row) mapped.push({ position, row });
  };

  for (const position of requested) {
    const pos = parseIntSafe(position.pos);
    if (!pos) continue;
    const directIndex = available.findIndex((row) => row.row_pos === pos);
    if (directIndex >= 0) takeRow(directIndex, position);
  }

  for (const position of requested) {
    const pos = parseIntSafe(position.pos);
    if (!pos || mapped.some((entry) => parseIntSafe(entry.position?.pos) === pos)) continue;

    const tokens = [
      position.Artikelbezeichnung,
      position.artikel,
      position.Werkstoff,
      position.werkstoff,
      position.Norm,
      position.norm,
    ].map((value) => normalizeKey(value)).filter(Boolean);

    let rowIndex = available.findIndex((row) => tokens.some((token) => row.description_normalized.includes(token)));
    if (rowIndex < 0 && requested.length === tableRows.length && available.length) rowIndex = 0;
    if (rowIndex < 0 && available.length === 1) rowIndex = 0;
    takeRow(rowIndex, position);
  }

  return mapped;
};


const findBestRequestedPosition = (description, requested, usedPositions = new Set()) => {
  const haystack = normalizeKey(description);
  if (!haystack) return null;

  const scored = requested.map((position, index) => {
    const pos = parseIntSafe(position.pos);
    if (!pos || usedPositions.has(pos)) return null;

    const tokens = [
      position.Artikelbezeichnung,
      position.artikel,
      position.Werkstoff,
      position.werkstoff,
      position.Norm,
      position.norm,
      position.Oberflaecheneigenschaften,
      position.oberflaeche,
    ].map((value) => normalizeKey(value)).filter((value) => value.length >= 3);

    const score = tokens.reduce((sum, token) => {
      if (!haystack.includes(token)) return sum;
      return sum + (token.length >= 5 ? 3 : 1);
    }, 0);

    return { position, index, score };
  }).filter(Boolean).sort((left, right) => right.score - left.score || left.index - right.index);

  const best = scored.find((entry) => entry.score > 0);
  return best ? best.position : null;
};

const parseSectionField = (text, labelRegex) => {
  const escapedLabel = labelRegex.source;
  const match = String(text ?? '').match(new RegExp('(?:^|\\n)\\s*(?:\\*\\*)?\\s*' + escapedLabel + '\\s*:?\\s*(?:\\*\\*)?\\s*([^\\n]+)', 'i'));
  if (!match?.[1]) return '';
  return String(match[1]).replace(/\\*\\*/g, '').trim();
};

const parseSectionOfferRows = (text, request) => {
  const requested = Array.isArray(request.anfrage_positionen) ? request.anfrage_positionen : [];
  if (!requested.length) return [];

  const lines = String(text ?? '').split(/\r?\n/);
  const sections = [];
  let current = null;

  const startSection = (line) => {
    const match = String(line ?? '').match(/^\s*(?:#{1,6}\s*)?(?:\*\*)?\s*(?:pos\.?|position)\s*(\d+)\b.*$/i);
    if (!match) return null;
    return { localPos: parseIntSafe(match[1]), lines: [line] };
  };

  for (const rawLine of lines) {
    const line = String(rawLine ?? '');
    const section = startSection(line);
    if (section) {
      if (current) sections.push(current);
      current = section;
      continue;
    }

    if (current && /^\s*(?:#{1,6}\s*)?(?:kosten|kostenuebersicht|kostenübersicht|gesamt|zusatz)/i.test(line)) {
      sections.push(current);
      current = null;
      continue;
    }

    if (current) current.lines.push(line);
  }

  if (current) sections.push(current);
  if (!sections.length) return [];

  const usedPositions = new Set();
  const mapped = [];

  sections.forEach((section, index) => {
    const body = section.lines.join('\n');
    const artikel = parseSectionField(body, /artikel/);
    const menge = parseSectionField(body, /menge/);
    const werkstoff = parseSectionField(body, /werkstoff/);
    const norm = parseSectionField(body, /norm/);
    const oberflaeche = parseSectionField(body, /oberfl(?:ae|ä)che/);
    const description = [artikel, menge, werkstoff, norm, oberflaeche].filter(Boolean).join(' | ') || body.slice(0, 300);
    const stueckpreis = parsePriceFromText(body, ['einzelpreis', 'stückpreis', 'stueckpreis', 'preis']);
    if (!stueckpreis) return;

    let position = findBestRequestedPosition(description + '\n' + body, requested, usedPositions);
    if (!position && sections.length === requested.length) {
      position = requested.find((entry) => !usedPositions.has(parseIntSafe(entry.pos))) || null;
    }

    const pos = parseIntSafe(position?.pos);
    if (!position || !pos) return;
    usedPositions.add(pos);

    mapped.push({
      position,
      row: {
        row_pos: section.localPos || index + 1,
        description,
        stueckpreis,
      },
    });
  });

  return mapped.filter((entry) => toNum(entry.row?.stueckpreis) > 0);
};

