const summarizeMailForKi = (text, limit = 2200) => {
  const raw = String(text ?? '').replace(/\r/g, '').trim();
  if (!raw) return '';

  const lines = raw
    .split('\n')
    .map((line) => line.trim())
    .filter(Boolean);

  const picked = [];
  const seen = new Set();
  const push = (line) => {
    const entry = String(line ?? '').trim();
    if (!entry || seen.has(entry)) return;
    seen.add(entry);
    picked.push(entry);
  };

  for (const line of lines.slice(0, 12)) push(line);
  for (const line of lines) {
    if (/(angebot|preis|einzelpreis|gesamt|lieferzeit|verfueg|verfüg|ab lager|zahlungs|pruefzeugnis|prüfzeugnis|norm|werkstoff|oberflaeche|oberfläche|lieferkosten|handling|verpack|spedition|mwst|brutto|netto|bordsteinkante)/i.test(line)) {
      push(line);
    }
  }

  return picked.join('\n').slice(0, limit);
};

