const parseAiJson = (value) => {
  const parseString = (raw) => {
    const cleaned = String(raw ?? '')
      .replace(/^\`\`\`json\s*/i, '')
      .replace(/^\`\`\`/i, '')
      .replace(/\`\`\`$/i, '')
      .trim();
    if (!cleaned) return null;
    try {
      return JSON.parse(cleaned);
    } catch {
      const objectStart = cleaned.indexOf('{');
      const objectEnd = cleaned.lastIndexOf('}');
      if (objectStart >= 0 && objectEnd > objectStart) {
        try {
          return JSON.parse(cleaned.slice(objectStart, objectEnd + 1));
        } catch {}
      }
      const arrayStart = cleaned.indexOf('[');
      const arrayEnd = cleaned.lastIndexOf(']');
      if (arrayStart >= 0 && arrayEnd > arrayStart) {
        try {
          return JSON.parse(cleaned.slice(arrayStart, arrayEnd + 1));
        } catch {}
      }
      return null;
    }
  };

  const looksUsefulObject = (node) => {
    if (!node || typeof node !== 'object' || Array.isArray(node)) return false;
    return ['globaler_hinweis', 'entwuerfe', 'lieferant', 'entwurf_text'].some((key) => Object.prototype.hasOwnProperty.call(node, key));
  };

  const visit = (node, depth = 0) => {
    if (node == null || depth > 6) return null;

    if (typeof node === 'string') return parseString(node);

    if (Array.isArray(node)) {
      for (const entry of node) {
        const parsed = visit(entry, depth + 1);
        if (parsed) return parsed;
      }
      return null;
    }

    if (typeof node === 'object') {
      if (looksUsefulObject(node)) return node;

      for (const key of ['output', 'text', 'response', 'data', 'content', 'message']) {
        if (!Object.prototype.hasOwnProperty.call(node, key)) continue;
        const parsed = visit(node[key], depth + 1);
        if (parsed) return parsed;
      }

      for (const value of Object.values(node)) {
        const parsed = visit(value, depth + 1);
        if (parsed) return parsed;
      }
    }

    return null;
  };

  return visit(value) ?? {};
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const escHtml = (value = '') => String(value)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;');

const base = (() => {
  try {
    return $('AF14a – KP4 KI-Input vorbereiten').first().json ?? {};
  } catch {
    return {};
  }
})();

const aiObjectRaw = parseAiJson($json);
const aiObject = aiObjectRaw && typeof aiObjectRaw === 'object' && !Array.isArray(aiObjectRaw) ? aiObjectRaw : {};
const globalHint = String(aiObject.globaler_hinweis ?? '').trim();
const aiRows = Array.isArray(aiObject.entwuerfe) ? aiObject.entwuerfe : [];
const aiBySupplier = new Map();

for (const row of aiRows) {
  const key = normalizeKey(row?.lieferant);
  if (!key) continue;
  aiBySupplier.set(key, {
    entwurf_text: String(row?.entwurf_text ?? '').trim(),
    begruendung: String(row?.begruendung ?? '').trim(),
    unsicher: row?.unsicher === true || String(row?.unsicher ?? '').toLowerCase() === 'true',
  });
}

const entries = Array.isArray(base.bestellentwuerfe) ? base.bestellentwuerfe : [];
return entries.map((entry) => {
  const row = { ...entry };
  const key = normalizeKey(row.lieferant);
  const ai = aiBySupplier.get(key);
  if (ai?.entwurf_text) row.entwurf_text = ai.entwurf_text;
  row.kp4_ki_begruendung = ai?.begruendung ?? '';
  row.kp4_ki_unsicher = ai?.unsicher ?? false;
  row.kp4_ki_globaler_hinweis = globalHint;

  let html = '';
  html += '<div style="font-family:Arial,sans-serif;color:#1f2937">';
  html += '<h2>Auftragsbestätigung erfassen</h2>';
  html += '<p><b>Lieferant:</b> ' + escHtml(row.lieferant ?? '') + '</p>';
  if (globalHint || row.kp4_ki_begruendung) {
    html += '<div style="margin:12px 0;padding:12px;border:1px solid #b3b8c4;border-radius:8px;background:#f8fafc">';
    html += '<p style="margin:0 0 8px 0"><b>KI-Hinweis:</b> ' + escHtml(row.kp4_ki_begruendung || globalHint || 'Kein zusätzlicher Hinweis.') + '</p>';
    html += '</div>';
  }
  html += '<p>Bitte die vollständige Auftragsbestätigung / Antwortmail dieses Lieferanten einfügen.</p>';
  html += '<p><b>Gesendeter Bestellentwurf:</b></p>';
  html += '<pre style="background:#f8fafc;border:1px solid #d0d5dd;padding:10px;white-space:pre-wrap">' + escHtml(row.entwurf_text ?? '') + '</pre>';
  html += '</div>';

  row.ab_erfassung_mail_html = html;
  return { json: row };
});

const mailItems = $input.all();

let baseItems = [];
try {
  baseItems = $('KP4 – Entscheidung verarbeiten').all();
} catch {
  baseItems = [];
}

if (!baseItems.length) {
  throw new Error('Keine KP4-Basisdaten zum Wiederanhängen gefunden.');
}

if (baseItems.length !== mailItems.length) {
  throw new Error(`Item-Anzahl passt nicht: Basis=${baseItems.length}, Mail=${mailItems.length}.`);
}

const escHtml = (value = '') => String(value)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;');

const toNum = (value) => {
  const raw = String(value ?? '').replace(',', '.');
  const number = Number(raw);
  return Number.isFinite(number) ? number : 0;
};

const euro = (value) => toNum(value).toFixed(2) + ' €';

const renderPositionsTable = (rows) => {
  const list = Array.isArray(rows) ? rows : [];
  if (!list.length) {
    return '<tr><td colspan="5" style="border:1px solid #d0d5dd;padding:6px 8px">Keine Positionsdaten vorhanden.</td></tr>';
  }

  return list.map((entry, index) => {
    const pos = Number.parseInt(String(entry?.pos ?? ''), 10) || index + 1;
    const artikel = String(entry?.artikel ?? entry?.Artikelbezeichnung ?? '').trim();
    const menge = String(entry?.menge ?? entry?.Menge ?? '').trim();
    const werkstoff = String(entry?.werkstoff ?? entry?.Werkstoff ?? '').trim();
    const norm = String(entry?.norm ?? entry?.Norm ?? '').trim();
    const preis = entry?.preis ?? entry?.gesamt ?? 0;

    return '<tr>'
      + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + escHtml(pos) + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + escHtml(artikel || '—') + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + escHtml(menge || '—') + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:6px 8px">' + escHtml([werkstoff, norm].filter(Boolean).join(' | ') || '—') + '</td>'
      + '<td style="border:1px solid #d0d5dd;padding:6px 8px;text-align:right">' + escHtml(euro(preis)) + '</td>'
      + '</tr>';
  }).join('');
};

const debugSource = baseItems[0]?.json ?? {};
const debugCarry = {
  debug_run_id: debugSource.debug_run_id,
  debug_started_at: debugSource.debug_started_at,
  debug_cache_file: debugSource.debug_cache_file,
  debug_trace: debugSource.debug_trace,
  debug_file_write_ok: debugSource.debug_file_write_ok,
  debug_file_write_error: debugSource.debug_file_write_error,
};

const parseTrace = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch {}
  }
  return [];
};

const appendTrace = (trace, entry) => [
  ...parseTrace(trace),
  {
    timestamp: new Date().toISOString(),
    warnings: [],
    errors: [],
    ...entry,
  },
];

const bestellungen = mailItems.map((item, index) => {
  const mailMeta = item.json ?? {};
  const base = baseItems[index]?.json ?? {};

  return {
    ...base,
    lieferant: String(base.lieferant ?? '').trim() || ('Lieferant ' + (index + 1)),
    to_email: String(base.to_email ?? '').trim(),
    positionen: Array.isArray(base.positionen) ? base.positionen.map((entry) => ({ ...entry })) : [],
    entwurf_text: String(base.entwurf_text ?? '').trim(),
