    bestellung_mail_rejected: Array.isArray(mailMeta.rejected) ? mailMeta.rejected : [],
  };
});

debugCarry.debug_trace = appendTrace(debugCarry.debug_trace, {
  step: 'AF14 – Bestellungen versendet',
  status: bestellungen.some((entry) => Array.isArray(entry.bestellung_mail_rejected) && entry.bestellung_mail_rejected.length) ? 'warnung' : 'ok',
  summary: 'Bestellmails wurden versendet und die Versanddaten für die spätere Auftragsbestätigungsprüfung wieder angehängt.',
  input: {
    bestellmails: mailItems.length,
  },
  output: {
    lieferanten: bestellungen.length,
    abgelehnte_empfaenger: bestellungen.reduce((sum, entry) => sum + (Array.isArray(entry.bestellung_mail_rejected) ? entry.bestellung_mail_rejected.length : 0), 0),
  },
});

const fields = [];
fields.push({
  fieldType: 'html',
  elementName: 'kp4b_intro',
  html: [
    '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.45">',
    '<h2 style="margin:0 0 10px 0">KP4b – Auftragsbestätigungen gesammelt erfassen</h2>',
    '<p style="margin:0 0 8px 0">Für jede versendete Bestellmail bitte die vollständige Auftragsbestätigung oder Antwortmail des jeweiligen Lieferanten einfügen.</p>',
    '<p style="margin:0;font-size:12px;color:#475467">Lieferanten: ' + escHtml(String(bestellungen.length)) + '</p>',
    '</div>',
  ].join(''),
});

bestellungen.forEach((entry, index) => {
  const lieferant = String(entry.lieferant ?? '').trim() || ('Lieferant ' + (index + 1));
  const accepted = Array.isArray(entry.bestellung_mail_accepted) ? entry.bestellung_mail_accepted.filter(Boolean) : [];

  fields.push({
    fieldType: 'html',
    elementName: 'kp4b_meta_' + index,
    html: [
      '<div style="margin:16px 0 8px 0;padding:12px;border:1px solid #d0d5dd;border-radius:8px;background:#f8fafc;font-family:Arial,sans-serif;color:#1f2937">',
      '<h3 style="margin:0 0 6px 0">' + escHtml(lieferant) + '</h3>',
      '<p style="margin:0 0 4px 0"><b>Empfänger:</b> ' + escHtml(entry.to_email || '—') + '</p>',
      '<p style="margin:0 0 4px 0"><b>Versendete Mail-ID:</b> ' + escHtml(entry.bestellung_mail_message_id || '—') + '</p>',
      '<p style="margin:0 0 8px 0"><b>Zugestellt an:</b> ' + escHtml(accepted.join(', ') || '—') + '</p>',
      '<div style="overflow-x:auto;margin:8px 0 0 0">',
      '<table style="border-collapse:collapse;width:100%;font-size:12px;background:#ffffff">',
      '<thead><tr>',
      '<th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Pos</th>',
      '<th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Artikel</th>',
      '<th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Menge</th>',
      '<th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Werkstoff / Norm</th>',
      '<th style="border:1px solid #d0d5dd;padding:6px 8px;text-align:left">Sollpreis</th>',
      '</tr></thead>',
      '<tbody>' + renderPositionsTable(entry.positionen) + '</tbody>',
      '</table>',
      '</div>',
      '<details style="margin-top:10px"><summary><b>Gesendete Bestellmail anzeigen</b></summary>',
      '<pre style="margin-top:8px;background:#ffffff;border:1px solid #d0d5dd;padding:10px;white-space:pre-wrap">' + escHtml(entry.entwurf_text || 'Kein Bestelltext vorhanden.') + '</pre>',
      '</details>',
      '</div>',
    ].join(''),
  });

  fields.push({
    fieldName: 'auftragsbestaetigung_mail_' + index,
    fieldLabel: 'Auftragsbestätigung / Antwortmail (' + lieferant + ')',
    fieldType: 'textarea',
    requiredField: true,
    placeholder: 'Hier die vollständige Auftragsbestätigung oder Antwortmail des Lieferanten einfügen.',
  });
});

fields.push({
  fieldName: 'kp4b_payload',
  fieldType: 'hiddenField',
  fieldValue: JSON.stringify(bestellungen),
});

const mailHtml = [
  '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.45">',
  '<h2 style="margin:0 0 8px 0">KP4b – Auftragsbestätigungen erfassen</h2>',
  '<p style="margin:0 0 8px 0">Bitte die Sammelseite öffnen und für jede versendete Bestellmail die passende Auftragsbestätigung einfügen.</p>',
  '<ul style="margin:0 0 10px 18px;padding:0">',
  bestellungen.map((entry) => '<li>' + escHtml(entry.lieferant) + ' (' + escHtml(entry.to_email || 'ohne E-Mail') + ')</li>').join(''),
  '</ul>',
  '<p style="margin:0;font-size:12px;color:#475467">Die KI prüft danach pro Lieferant, ob Menge, Preis und Positionen zur Bestellung passen.</p>',
  '</div>',
].join('');

return [{
  json: {
    ...debugCarry,
    bestellungen,
    kp4b_supplier_count: bestellungen.length,
