parameters.jsCode:
const parseAiJson = (value) => {
  const parseString = (raw) => {
    const cleaned = String(raw ?? '')
      .replace(/^\`\`\`json\s*/i, '')
      .replace(/^\`\`\`/i, '')
      .replace(/\`\`\`$/i, '')
      .trim();
    if (!cleaned) return {};
    try {
      return JSON.parse(cleaned);
    } catch {
      const objectStart = cleaned.indexOf('{');
      const objectEnd = cleaned.lastIndexOf('}');
      if (objectStart >= 0 && objectEnd > objectStart) {
        try {
          return JSON.parse(cleaned.slice(objectStart, objectEnd + 1));
        } catch {}
      }
      return {};
    }
  };

  if (!value) return {};
  if (typeof value === 'string') return parseString(value);
  if (typeof value === 'object') {
    for (const key of ['output', 'text', 'response', 'data']) {
      if (value[key] && typeof value[key] === 'object') return value[key];
      if (typeof value[key] === 'string') return parseString(value[key]);
    }
    return value;
  }
  return {};
};

const toNum = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return 0;
  let normalized = raw.replace(/[^0-9,.-]/g, '');
  if (!normalized || normalized === '-' || normalized === ',' || normalized === '.') return 0;
  if (normalized.includes(',') && normalized.includes('.')) {
    if (normalized.lastIndexOf(',') > normalized.lastIndexOf('.')) {
      normalized = normalized.replace(/\./g, '').replace(',', '.');
    } else {
      normalized = normalized.replace(/,/g, '');
    }
  } else if (normalized.includes(',')) {
    normalized = normalized.replace(',', '.');
  }
  const number = Number(normalized);
  return Number.isFinite(number) ? number : 0;
};

const parseBoolean = (value) => value === true || String(value ?? '').toLowerCase() === 'true';
const roundMoney = (value) => Number((Math.round(toNum(value) * 100) / 100).toFixed(2));

const clampPercent = (value, fallback = 0) => {
  const number = Number(String(value ?? '').replace(',', '.').trim());
  if (!Number.isFinite(number)) return fallback;
  return Math.max(0, Math.min(100, number));
};

const toStringArray = (value) => {
  if (Array.isArray(value)) {
    return value.map((entry) => String(entry ?? '').trim()).filter(Boolean);
  }
  const raw = String(value ?? '').trim();
  return raw ? [raw] : [];
};

let baseItems = [];
try {
  baseItems = $('AF14d – AB-Eingaben auf Lieferanten aufteilen').all();
} catch {
  baseItems = [];
}

if (!baseItems.length) {
  throw new Error('Keine aufgeteilten AB-Eingaben gefunden.');
}

if (baseItems.length !== items.length) {
  throw new Error(`Item-Anzahl passt nicht: Basis=${baseItems.length}, KI=${items.length}.`);
}

return items.map(({ json }, index) => {
  const base = baseItems[index]?.json ?? {};
  const aiObjectRaw = parseAiJson(json);
  const aiObject = aiObjectRaw && typeof aiObjectRaw === 'object' && !Array.isArray(aiObjectRaw) ? aiObjectRaw : {};

  const bestellungPositionen = Array.isArray(base.positionen)
    ? base.positionen.map((entry, entryIndex) => ({
        pos: Number.parseInt(String(entry.pos ?? ''), 10) || entryIndex + 1,
        menge: toNum(entry.menge ?? entry.Menge ?? 0),
        preis: toNum(entry.preis ?? entry.gesamt ?? entry.positionspreis ?? 0),
        stueckpreis: toNum(entry.stueckpreis ?? 0),
        artikel: String(entry.artikel ?? entry.Artikelbezeichnung ?? '').trim(),
      }))
    : [];

  const expectedByPos = new Map(bestellungPositionen.map((entry) => [entry.pos, entry]));
  const abPositionen = Array.isArray(aiObject.positionen)
    ? aiObject.positionen.map((entry, entryIndex) => {
        const pos = Number.parseInt(String(entry.pos ?? ''), 10) || entryIndex + 1;
        const expected = expectedByPos.get(pos) ?? {};
        const menge = toNum(entry.menge);
        const expectedMenge = toNum(expected.menge);
        const effectiveMenge = menge || expectedMenge || 0;
        const rawPreis = toNum(entry.preis);
        const rawStueckpreis = toNum(entry.stueckpreis ?? entry.einzelpreis ?? entry.unit_price);
        const rawPositionspreis = toNum(entry.positionspreis ?? entry.positionspreis_netto ?? entry.gesamtpreis ?? entry.line_total);
        const expectedUnit = toNum(expected.stueckpreis) || (expectedMenge > 0 ? toNum(expected.preis) / expectedMenge : 0);
        let stueckpreis = rawStueckpreis;
        let positionspreis = rawPositionspreis || rawPreis;
        let preisAusStueckpreis = false;
        const kommentare = [];

        if (!positionspreis && stueckpreis > 0 && effectiveMenge > 0) {
          positionspreis = roundMoney(stueckpreis * effectiveMenge);
          preisAusStueckpreis = true;
          kommentare.push('Positionspreis aus bestätigtem Stückpreis und Menge berechnet.');
        } else if (rawPreis > 0 && !rawPositionspreis && !rawStueckpreis && expectedUnit > 0 && expectedMenge > 1 && Math.abs(rawPreis - expectedUnit) < 0.02 && Math.abs(rawPreis - toNum(expected.preis)) > 0.02) {
          stueckpreis = rawPreis;
          positionspreis = roundMoney(rawPreis * expectedMenge);
          preisAusStueckpreis = true;
          kommentare.push('KI-Feld preis entsprach dem erwarteten Stückpreis; Positionspreis wurde mit der Bestellmenge berechnet.');
        }

        return {
          pos,
          menge,
          menge_bestaetigt: parseBoolean(entry.menge_bestaetigt),
          preis: roundMoney(positionspreis),
          stueckpreis: roundMoney(stueckpreis),
          positionspreis: roundMoney(positionspreis),
          preis_aus_stueckpreis: preisAusStueckpreis,
          preis_bestaetigt: parseBoolean(entry.preis_bestaetigt),
          artikel: String(entry.artikel ?? '').trim(),
          artikel_bestaetigt: parseBoolean(entry.artikel_bestaetigt),
          kommentar: [String(entry.kommentar ?? '').trim(), ...kommentare].filter(Boolean).join(' '),
        };
      })
    : [];

  return {
    json: {
      ...base,
      auftragsbestaetigung_mail: String(base.auftragsbestaetigung_mail ?? '').trim(),
