};

const clamp = (value, min = 0, max = 100) => Math.max(min, Math.min(max, toNum(value)));

const hasOwn = (obj, key) => Object.prototype.hasOwnProperty.call(obj ?? {}, key);

const base = (() => {
  try {
    return $('AF9a – KP2 KI-Prüfinput vorbereiten').first().json ?? {};
  } catch {
    return {};
  }
})();

const positionen = Array.isArray(base.positionen) ? base.positionen.map((entry) => ({ ...entry })) : [];
const aiRaw = parseAiJson($json);
const ai = aiRaw && typeof aiRaw === 'object' && !Array.isArray(aiRaw) ? aiRaw : {};

const avg = (values) => {
  const nums = values.map((value) => clamp(value)).filter((value) => Number.isFinite(value));
  if (!nums.length) return 0;
  return nums.reduce((sum, value) => sum + value, 0) / nums.length;
};

const deterministicFactors = () => {
  const list = positionen.length ? positionen : [];
  const posCoverage = avg(list.map((p) => {
    let score = 0;
    if (p.pos) score += 20;
    if (String(p.Artikelbezeichnung ?? '').trim()) score += 25;
    if (String(p.Menge ?? '').trim()) score += 20;
    if (String(p.Werkstoff ?? '').trim()) score += 20;
    if (String(p.Norm ?? '').trim()) score += 15;
    return score;
  }));
  const priceCoverage = avg(list.map((p) => {
    const best = p.bester ?? {};
    let score = 0;
    if (toNum(best.stueckpreis) > 0) score += 45;
    if (toNum(best.gesamt) > 0) score += 45;
    if (String(best.lieferant ?? '').trim()) score += 10;
    return score;
  }));
  const costCoverage = avg(list.map((p) => {
    const best = p.bester ?? {};
    let score = 0;
    if (hasOwn(best, 'lieferkosten')) score += 45;
    if (hasOwn(best, 'entladungspauschale')) score += 25;
    if (hasOwn(best, 'zusatzkosten')) score += 30;
    return score;
  }));
  const deliveryCoverage = avg(list.map((p) => {
    const best = p.bester ?? {};
    let score = 0;
    if (toNum(best.lieferzeit_tage) > 0) score += 55;
    if (String(best.verfuegbarkeit ?? '').trim()) score += 45;
    return score;
  }));
  const alternatives = avg(list.map((p) => {
    const offers = Array.isArray(p.angebote) ? p.angebote : [];
    if (offers.length >= 2) return 100;
    if (offers.length === 1) return 75;
    return 25;
  }));
  const warningCount = list.reduce((sum, p) => sum + (Array.isArray(p.af7_validierungswarnungen) ? p.af7_validierungswarnungen.length : 0) + (p.kp2_ki_unsicher ? 1 : 0), 0);
  const sourceCoverage = avg(list.map((p) => String(p?.bester?.preisquelle ?? '').trim() ? 100 : 55));
  const warningScore = Math.max(0, sourceCoverage - warningCount * 8);

  return [
    { faktor: 'Stücklistenabdeckung / Positionsdaten', gewicht_prozent: 20, bewertung_prozent: posCoverage, begruendung: 'Position, Artikel, Menge, Werkstoff und Norm wurden je Position geprüft.' },
    { faktor: 'Preise je Position', gewicht_prozent: 25, bewertung_prozent: priceCoverage, begruendung: 'Ausgewählte Angebote wurden auf Stückpreis, Gesamtpreis und Lieferant geprüft.' },
    { faktor: 'Liefer- und Nebenkosten', gewicht_prozent: 20, bewertung_prozent: costCoverage, begruendung: 'Lieferkosten, Entladung und Zusatzkosten wurden als bekannte Kostenbestandteile bewertet.' },
    { faktor: 'Lieferzeit und Verfügbarkeit', gewicht_prozent: 15, bewertung_prozent: deliveryCoverage, begruendung: 'Lieferzeit und Verfügbarkeit wurden je ausgewähltem Angebot geprüft.' },
    { faktor: 'Alternativen und Auswahlplausibilität', gewicht_prozent: 10, bewertung_prozent: alternatives, begruendung: 'Vorhandene Alternativangebote erhöhen die Nachvollziehbarkeit der Auswahl.' },
    { faktor: 'Datenquelle / Warnhinweise', gewicht_prozent: 10, bewertung_prozent: warningScore, begruendung: 'Preisquellen und vorhandene Warnhinweise wurden berücksichtigt.' },
  ];
};

const normalizeFactors = (rawFactors) => {
  const source = Array.isArray(rawFactors) && rawFactors.length ? rawFactors : deterministicFactors();
  const cleaned = source.map((entry) => ({
    faktor: String(entry.faktor ?? entry.name ?? '').trim() || 'Unbenannter Faktor',
    gewicht_prozent: Math.max(0, toNum(entry.gewicht_prozent ?? entry.gewicht ?? 0)),
    bewertung_prozent: clamp(entry.bewertung_prozent ?? entry.bewertung ?? entry.score ?? 0),
    begruendung: String(entry.begruendung ?? entry.grund ?? '').trim(),
  })).filter((entry) => entry.gewicht_prozent > 0);

  const factors = cleaned.length ? cleaned : deterministicFactors();
  const weightSum = factors.reduce((sum, entry) => sum + entry.gewicht_prozent, 0) || 100;
  return factors.map((entry) => {
    const normalizedWeight = entry.gewicht_prozent * 100 / weightSum;
    const contribution = normalizedWeight * entry.bewertung_prozent / 100;
    return {
      faktor: entry.faktor,
      gewicht_prozent: Number(normalizedWeight.toFixed(1)),
      bewertung_prozent: Number(entry.bewertung_prozent.toFixed(0)),
      beitrag_prozentpunkte: Number(contribution.toFixed(1)),
      begruendung: entry.begruendung || 'Keine Detailbegründung der KI vorhanden.',
    };
  });
};

const factorScore = (factorList) => Number((Array.isArray(factorList) ? factorList : [])
  .reduce((sum, entry) => sum + toNum(entry.beitrag_prozentpunkte), 0)
  .toFixed(0));

const deterministic = normalizeFactors(deterministicFactors());
const deterministicScore = factorScore(deterministic);
const aiFactorSource = Array.isArray(ai.automatik_score_faktoren) ? ai.automatik_score_faktoren : [];
const aiFactors = aiFactorSource.length ? normalizeFactors(aiFactorSource) : [];
const aiScore = aiFactors.length ? factorScore(aiFactors) : 0;
const aiHasEnoughFactors = aiFactorSource.length >= 4;
const aiContradictsData = Math.abs(aiScore - deterministicScore) > 25 || (deterministicScore >= 70 && aiScore < 45);
const useAiFactors = aiHasEnoughFactors && !aiContradictsData;
const factors = useAiFactors ? aiFactors : deterministic;
const score = factorScore(factors);

const positionHasMaterial = (p) => Boolean(
  String(p?.Werkstoff ?? p?.werkstoff ?? '').trim()
  || String(p?.Norm ?? p?.norm ?? '').trim()
  || String(p?.Artikelbezeichnung ?? p?.artikel ?? '').trim()
  || String(p?.material ?? p?.alternativ_material ?? '').trim()
);
const allPositionsHaveMaterial = positionen.length > 0 && positionen.every(positionHasMaterial);
const rawWarnings = Array.isArray(ai.automatik_warnhinweise)
  ? ai.automatik_warnhinweise.map((entry) => String(entry ?? '').trim()).filter(Boolean)
  : [];
const warnings = rawWarnings.filter((warning) => {
  if (allPositionsHaveMaterial && /(material|alternativmaterial).*(fehlt|unvollst|nicht vorhanden)/i.test(warning)) return false;
  return true;
});
if (!useAiFactors) {
  warnings.push(aiFactorSource.length
    ? 'KI-Faktoren waren unvollständig oder widersprachen den geprüften Angebotsdaten; Score und Faktoren wurden deterministisch aus der KP2-Tabelle berechnet.'
    : 'KI-Prüfung hat keine verwertbaren Faktoren geliefert; Faktoren wurden deterministisch aus den Angebotsdaten ergänzt.');
}

const aiReason = String(ai.automatik_score_begruendung ?? '').trim();
const contradictoryReason = /(alle|sämtliche|saemtliche).*(fehlen|nicht vorhanden)|keine.*daten|nicht vollständig|nicht vollstaendig/i.test(aiReason);
const deterministicReason = 'Die Einschätzung wurde aus geprüften Positionsdaten, Preisen, Liefer- und Nebenkosten, Lieferzeit, Verfügbarkeit, Alternativen und Datenquellen berechnet.';
const reason = (!useAiFactors || (score >= 70 && contradictoryReason)) ? deterministicReason : (aiReason || deterministicReason);
const readiness = score >= 90 ? 'freigabereif' : (score >= 70 ? 'manuell_pruefen' : 'nicht_freigabereif');

return positionen.map((entry) => ({
  json: {
    ...entry,
    automatik_score_prozent: score,
    automatik_score_begruendung: reason,
    automatik_score_faktoren: factors,
    automatik_warnhinweise: [...new Set(warnings)],
    automatik_entscheidungsreife: readiness,
    ki_job_modus: 'ki_kp2_bestellpruefung',
    kp2_ki_review_rohantwort: ai,
    kp2_ki_faktoren_verwendet: useAiFactors ? 'ki' : 'deterministisch',
    kp2_ki_faktoren_verworfen: !useAiFactors,
    kp2_deterministischer_score: deterministicScore,
    kp2_roher_ki_score: aiFactors.length ? aiScore : null,
  },
}));

