const toNum = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return 0;
  let normalized = raw.replace(/[^0-9,.-]/g, '');
  if (normalized.includes(',') && normalized.includes('.')) {
    normalized = normalized.lastIndexOf(',') > normalized.lastIndexOf('.')
      ? normalized.replace(/\./g, '').replace(',', '.')
      : normalized.replace(/,/g, '');
  } else if (normalized.includes(',')) {
    normalized = normalized.replace(',', '.');
  }
  const n = Number(normalized);
  return Number.isFinite(n) ? n : 0;
};

const normalizeKey = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const form = $json.data ?? $json ?? {};
const basis = (() => {
  try {
    return $('IF – Preisverhandlung?').first().json ?? {};
  } catch {
    return {};
  }
})();

const getField = (...aliases) => {
  for (const alias of aliases) {
    if (Object.prototype.hasOwnProperty.call(form, alias)) return String(form[alias] ?? '').trim();
  }
  const wanted = aliases.map(normalizeKey);
  for (const [key, raw] of Object.entries(form)) {
    const keyNorm = normalizeKey(key);
    if (wanted.includes(keyNorm) || wanted.some((alias) => keyNorm.includes(alias))) return String(raw ?? '').trim();
  }
  return '';
};

const entscheidungRaw = getField('Entscheidung nach Preisverhandlung', 'entscheidung_nach_preisverhandlung');
const vereinbarterPreis = toNum(getField('Neu vereinbarter Preis optional', 'neu_vereinbarter_preis_optional'));
const notiz = getField('Notiz / Vereinbarung', 'notiz_vereinbarung');

let kundenentscheidung = 'Große Änderung';
if (entscheidungRaw === 'Kunde stimmt zu') kundenentscheidung = 'stimmt zu';
if (entscheidungRaw === 'Kunde lehnt ab') kundenentscheidung = 'abgelehnt';
if (entscheidungRaw === 'Neu kalkulieren') kundenentscheidung = 'Große Änderung';

const out = {
  ...basis,
  data: form,
  preisverhandlung_noetig: false,
  preisverhandlung_abgeschlossen: true,
  preisverhandlung_entscheidung: entscheidungRaw,
  preisverhandlung_notiz: notiz,
  kundenentscheidung,
  kundenentscheidung_begruendung: notiz || 'Preisverhandlung wurde manuell geklärt.',
  kundenentscheidung_aenderungswunsch: kundenentscheidung === 'Große Änderung' ? (notiz || 'Preis neu kalkulieren.') : '',
  kundenentscheidung_quelle: 'manuell_preisverhandlung',
  kundenentscheidung_unsicher: false,
  kp3_kommentar: notiz,
};

if (vereinbarterPreis > 0 && kundenentscheidung === 'stimmt zu') {
  out.kostenvoranschlag = Number(vereinbarterPreis.toFixed(2));
  out.kostenvoranschlag_manuell_vereinbart = Number(vereinbarterPreis.toFixed(2));
}

return [{ json: out }];

const esc = (value = '') => String(value)
  .replaceAll('&', '&amp;')
  .replaceAll('<', '&lt;')
  .replaceAll('>', '&gt;')
  .replaceAll('"', '&quot;');

const normalize = (value) => String(value ?? '')
  .toLowerCase()
  .replace(/ä/g, 'ae')
  .replace(/ö/g, 'oe')
  .replace(/ü/g, 'ue')
  .replace(/ß/g, 'ss')
  .replace(/[^a-z0-9]+/g, ' ')
  .trim();

const shortText = (value, limit = 900) => {
  if (value === undefined || value === null || value === '') return '';
  const text = typeof value === 'string' ? value : JSON.stringify(value, null, 2);
  const compact = text.replace(/[ \t]+/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
  return compact.length > limit ? compact.slice(0, limit) + ' ... (' + compact.length + ' Zeichen gesamt)' : compact;
};

const parseTrace = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string' && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch {}
  }
  return [];
};

const issueText = (issue) => {
  if (!issue || typeof issue !== 'object') return shortText(issue, 300) || 'Hinweis';
  const pos = Number(issue.pos) > 0 ? 'Pos. ' + issue.pos + ': ' : '';
  const type = String(issue.typ ?? '').trim();
  const label = ({
    preis: 'Preisabweichung',
    menge: 'Mengenabweichung',
    artikel: 'Artikelabweichung',
    fehlend: 'Fehlende Position',
    zusatzposition: 'Zusätzliche Position',
    menge_unbestaetigt: 'Menge nicht belastbar bestätigt',
    preis_unbestaetigt: 'Preis nicht belastbar bestätigt',
    vollstaendigkeit: 'Unvollständige KI-Erkennung',
    warnhinweis: 'Warnhinweis',
    ki_einschaetzung: 'KI-Einschätzung',
    ki_unklar: 'KI unklar',
  })[type] || type || 'Hinweis';
  const parts = [pos + label];
  if (issue.erwartet !== undefined || issue.erhalten !== undefined) {
    parts.push('erwartet: ' + String(issue.erwartet ?? '—') + ', erhalten: ' + String(issue.erhalten ?? '—'));
  }
  if (issue.info) parts.push(String(issue.info));
  return shortText(parts.join(' – '), 450);
};

const renderTraceMarkdown = (trace) => {
  const rows = parseTrace(trace);
  const lines = ['## Kurzfassung des Prozesslaufs'];
  const warningsCount = rows.reduce((sum, entry) => sum + (Array.isArray(entry.warnings) ? entry.warnings.length : 0), 0);
  const errorsCount = rows.reduce((sum, entry) => sum + (Array.isArray(entry.errors) ? entry.errors.length : 0), 0);
  const notable = rows.filter((entry) => {
    const status = String(entry.status ?? '').toLowerCase();
    return status && status !== 'ok' && status !== 'übersprungen' && status !== 'uebersprungen';
  });

  lines.push('', '- Protokollierte Schritte: ' + rows.length);
  lines.push('- Warnungen im Ablauf: ' + warningsCount);
  lines.push('- Fehler im Ablauf: ' + errorsCount);
  if (notable.length) {
    lines.push('- Schritte mit Prüfbedarf: ' + notable.map((entry) => String(entry.step || 'Schritt') + ' (' + String(entry.status || 'unbekannt') + ')').join(' | '));
  } else {
    lines.push('- Schritte mit Prüfbedarf: keine im Debug-Trace markiert');
  }

  lines.push('', '## Ablaufprotokoll ab Start');
  if (!rows.length) {
    lines.push('', 'Es wurde kein vollständiger `debug_trace` bis AF15 mitgeführt. Das Protokoll enthält deshalb die zusammengefassten AF15-Daten und die User-Entscheidung. Für neue Läufe wird der Trace an den Hauptstationen fortgeschrieben.');
    return lines;
  }

  rows.forEach((entry, index) => {
    lines.push('', '### ' + (index + 1) + '. ' + (entry.step || 'Schritt'));
    lines.push('- Status: ' + (entry.status || 'ok'));
    if (entry.timestamp) lines.push('- Zeitpunkt: ' + entry.timestamp);
    if (entry.summary) lines.push('- Kurzfassung: ' + shortText(entry.summary, 700));
    if (entry.decision && Object.keys(entry.decision).length) lines.push('- Entscheidung: ' + shortText(entry.decision, 800));
    if (entry.input && Object.keys(entry.input).length) lines.push('- Eingangsdaten: ' + shortText(entry.input, 900));
    if (entry.output && Object.keys(entry.output).length) lines.push('- Ergebnis: ' + shortText(entry.output, 900));
    if (Array.isArray(entry.warnings) && entry.warnings.length) lines.push('- Warnungen: ' + entry.warnings.map((warning) => shortText(warning, 220)).join(' | '));
    if (Array.isArray(entry.errors) && entry.errors.length) lines.push('- Fehler: ' + entry.errors.map((error) => shortText(error, 220)).join(' | '));
  });
  return lines;
};

const renderSupplierSummary = (suppliers) => {
  const list = Array.isArray(suppliers) ? suppliers : [];
  const lines = ['## AF15 Ergebnis'];
  if (!list.length) {
    lines.push('', 'Keine Lieferantenbewertung vorhanden.');
    return lines;
  }
  for (const entry of list) {
    const status = String(entry.abStatus || 'unbekannt');
    const score = Number.isFinite(Number(entry.automatik_score_prozent)) ? Number(entry.automatik_score_prozent).toFixed(0) + ' %' : 'nicht angegeben';
    const issues = Array.isArray(entry.ab_abweichungen) ? entry.ab_abweichungen : [];
    lines.push('', '### ' + (entry.lieferant || 'Unbekannter Lieferant'));
    lines.push('- Fachlicher Status: ' + status);
    lines.push('- Datenvollständigkeit: ' + score);
    if (Number(entry.automatik_score_prozent) >= 90 && status !== 'korrekt') {
      lines.push('- Interpretation: Die Auftragsbestätigung wurde vollständig gelesen, enthält aber fachliche Abweichungen oder unklare Angaben.');
    }
    if (entry.automatik_score_begruendung) lines.push('- KI-Begründung: ' + shortText(entry.automatik_score_begruendung, 800));
    if (issues.length) lines.push('- Hinweise/Abweichungen: ' + issues.map(issueText).join(' | '));
    else lines.push('- Hinweise/Abweichungen: Keine Abweichung erkannt.');
  }
  return lines;
};

const base = (() => {
  try { return $('AF15 – AB-Abgleich').first().json ?? {}; } catch { return {}; }
})();
const current = $json ?? {};
const response = current.data ?? current.formData ?? current.form ?? current.response ?? current;
const entries = Object.entries(response && typeof response === 'object' ? response : {});
const pick = (patterns) => {
  for (const [key, value] of entries) {
    const normKey = normalize(key);
    if (patterns.some((pattern) => pattern.test(normKey))) return String(value ?? '').trim();
  }
  return '';
};

const decision = pick([/entscheidung/]);
const comment = pick([/kommentar/, /korrektur/, /anpassung/]);
const decisionNorm = normalize(decision);
const needsClarification = /nicht korrekt|klaerung|klarung|ablehnen|abweich/.test(decisionNorm);
const documentedAdjustment = /anpassung/.test(decisionNorm);
const acceptedWithHint = /trotz hinweis|abweichung akzeptieren/.test(decisionNorm);
if ((needsClarification || documentedAdjustment) && !comment) {
  throw new Error('Bitte Kommentar / Korrektur für Klärung oder dokumentierte Anpassung ergänzen.');
}

const finalStatus = needsClarification ? 'nicht korrekt' : 'korrekt';
const userDecisionType = needsClarification
  ? 'klaerung_erforderlich'
  : (documentedAdjustment ? 'anpassung_dokumentiert' : (acceptedWithHint ? 'korrekt_trotz_hinweis' : 'korrekt'));

const started = new Date().toISOString();
const runId = String(base.debug_run_id ?? '').trim();
const protocolName = 'SollProzessv2_Protokoll_' + (runId || started.replace(/[:.]/g, '-')) + '.md';
const trace = parseTrace(base.debug_trace);
const basis = String(base.ab_protokoll_basis_markdown ?? '').trim();

const lines = [];
lines.push('# Durchlaufprotokoll SollProzessv2');
lines.push('');
lines.push('Erstellt: ' + started);
if (runId) lines.push('Run-ID: ' + runId);
if (base.debug_started_at) lines.push('Start: ' + base.debug_started_at);
if (base.debug_cache_file) lines.push('Debug-Datei: ' + base.debug_cache_file);
if (base.debug_file_write_error) lines.push('Debug-Dateihinweis: ' + base.debug_file_write_error);
lines.push('Finaler AF15-Status: ' + finalStatus);
if (base.ab_gesamtstatus) lines.push('AF15-Status vor User-Entscheidung: ' + base.ab_gesamtstatus);
lines.push('Protokollierte Debug-Schritte: ' + trace.length);
lines.push('');
lines.push(...renderTraceMarkdown(trace));
lines.push('', ...renderSupplierSummary(base.ab_lieferanten));
if (basis) {
  lines.push('', '## Technischer AF15-Soll/Ist-Auszug', '', basis);
}
lines.push('', '## User-Entscheidung');
lines.push('- Zeitpunkt: ' + started);
lines.push('- Entscheidung: ' + (decision || 'nicht angegeben'));
lines.push('- Interner Entscheidungstyp: ' + userDecisionType);
lines.push('- Finaler Workflow-Status: ' + finalStatus);
if (comment) lines.push('- Kommentar / Korrektur: ' + comment);

const markdown = lines.join('\n') + '\n';
const html = '<div style="font-family:Arial,sans-serif;color:#1f2937;line-height:1.45">'
  + '<h2>AF15 – Durchlaufprotokoll gespeichert</h2>'
  + '<p>Die Entscheidung zur Auftragsbestätigung wurde protokolliert. Das Markdown-Protokoll ist dieser Mail angehängt und enthält eine Kurzfassung, den Ablauf-Trace, AF15-Soll/Ist-Hinweise und die finale User-Entscheidung.</p>'
  + '<p><b>Entscheidung:</b> ' + esc(decision || 'nicht angegeben') + '<br>'
  + '<b>Finaler Status:</b> ' + esc(finalStatus) + '</p>'
  + (comment ? '<p><b>Kommentar / Korrektur:</b><br>' + esc(comment).replace(/\n/g, '<br>') + '</p>' : '')
  + (base.debug_cache_file ? '<p style="font-size:12px;color:#475467"><b>Debug-Protokoll:</b> ' + esc(base.debug_cache_file) + '<br><b>Run-ID:</b> ' + esc(runId) + '</p>' : '')
  + '</div>';

return [{
  json: {
    ...base,
    ...current,
    ab_gesamtstatus_vor_user: base.ab_gesamtstatus,
    ab_gesamtstatus: finalStatus,
    ab_user_entscheidung: decision,
    ab_user_entscheidung_typ: userDecisionType,
    ab_user_kommentar: comment,
    ab_user_entschieden_am: started,
    ab_protokoll_markdown: markdown,
    ab_protokoll_dateiname: protocolName,
